INSERT INTO `actualites` (`id`, `description`, `titre`, `soutTitre`, `img_url`, `pdf`, `is_active`, `publish_at`, `expire_at`, `created_at`, `updated_at`) VALUES
	(2, '<p><strong>Ésaïe 62:1&nbsp;</strong></p><p>"Pour l\'amour de Sion je ne me tairai point, Pour l\'amour de Jérusalem je ne prendrai point de repos, Jusqu\'à ce que son salut paraisse, Comme l\'aurore,Et sa délivrance comme un flambeau qui s\'allume."</p>', 'Pour l\'amour de mon pays, je ne me tairai point ! ', 'Sujets de prière', NULL, 'actualites/01JJWFJHEF9C9C3X8RGE1ZW5KE.pdf', 0, '2025-07-15 00:00:00', '2025-08-26 00:00:00', '2025-01-30 11:40:58', '2025-07-14 21:46:24'),
	(3, '<p>Betsaleel, fils d’Uri, fils de Hur, de la tribu de Juda, fit tout ce que l’Éternel avait ordonné à Moïse; il eut pour aide Oholiab, fils d’Ahisamac, de la tribu de Dan, habile à graver, à inventer, et à broder sur les étoffes teintes en bleu, en pourpre, en cramoisi, et sur le fin lin.<br>‭‭<strong>Exode‬ ‭38‬:‭22‬-‭23‬ ‭LSG‬‬</strong><br><br><strong><em>#eglisecmp<br>#cenacle</em></strong></p>', 'Lecture du jour', 'Mardi 28 Janvier 2025', 'actualites/01JJVSNGREYG6M89RTS6W5W38R.jpg', NULL, 0, '2025-01-30 15:30:00', '2025-01-30 16:00:00', '2025-01-30 13:26:00', '2025-01-30 13:59:39'),
	(4, '<p>Et si on passait à une AUTRE DIMENSION ?&nbsp;<br><br>Celle-ci n’est pas une simple retraite&nbsp; mais un rendez-vous du divin et de l’humain.&nbsp;<br><br>Dieu nous donne rendez-vous&nbsp;<br>Du 10 au 16 Août 2025 pour la grande retraite de la jeunesse&nbsp;<br><br>📍Lycée Mgr SHAUMBA&nbsp;<br>🏷Frais de participation: 30$<br><br>Contact:&nbsp; ‪+243983793375‬/&nbsp; ‪+243812322082‬/ +243896555935‬<br><br>Que Dieu nous&nbsp; bénisse.<br><br></p>', '𝗚𝗥𝗔𝗡𝗗𝗘 𝗥𝗘𝗧𝗥𝗔𝗜𝗧𝗘 𝟮𝟬𝟮𝟱', NULL, 'actualites/01K05NDK01Z51XQJCN59W5D1XG.jpg', NULL, 0, '2025-09-17 00:00:00', '2025-09-30 00:00:00', '2025-07-14 21:48:14', '2025-09-16 12:40:33'),
	(5, '<p>&nbsp;Et si on passait à une AUTRE DIMENSION ?&nbsp;<br><br>Celle-ci n’est pas une simple retraite&nbsp; mais un rendez-vous du divin et de l’humain.&nbsp;<br><br>Dieu nous donne rendez-vous&nbsp;<br>Du 10 au 16 Août 2025 pour la grande retraite de la jeunesse&nbsp;<br><br>📍Lycée Mgr SHAUMBA&nbsp;<br>🏷Frais de participation: 30$<br><br>Contact:&nbsp; ‪+243983793375‬/&nbsp; ‪+243812322082‬/&nbsp;<br>‪+243896555935‬<br><br>Que Dieu nous&nbsp; bénisse.<br><br>#granderetraite #departementdelajeunesse #eglisecmp #kenluamba #jonathanassani&nbsp;</p>', 'Semaine des prières', 'Vous verrez de nouveau la différence ', 'actualites/01K59FEM13E4G3PKRVJWSFH2HP.jpeg', NULL, 0, '2025-11-24 00:00:00', '2025-11-26 00:00:00', '2025-09-16 12:39:23', '2025-10-22 22:10:32'),
	(6, '<p>&nbsp;🔥 <strong>BUNDA 21 – “Le zèle de ta maison me dévore” (Jean 2:17)</strong></p><p><br> Du <strong>3 au 23 novembre 2025</strong>, 21 jours pour rechercher la face de Dieu, vivre le surnaturel et raviver la flamme.<br> 🕕 Trois sessions chaque jour : <strong>06h–08h | 12h–14h | 17h30–20h</strong><br> 📍 <strong>Temple de l’Église, croisement Forces Armées &amp; Shaumba</strong><br> 🔥 Des orateurs inspirés, une atmosphère de gloire — ne viens pas assister, viens être transformé !</p><p><br>&nbsp;#BUNDA21 #eglisecmp #ZeleDeSaMaison&nbsp;</p>', 'Bunda 21', 'Programme Annuel de jeune et prière', NULL, 'actualites/01K877EF00FDKY3DQS27Q2CFF1.pdf', 1, '2025-11-03 00:00:00', '2025-11-23 00:00:00', '2025-10-22 22:13:14', '2025-10-22 23:34:30');
