	(2, 'Amos Makanda', 'ministre/01JCHH4BFKDTW25ABDA8SE5ZT2.png', NULL, 0, 1, '+243818772740', 'Pasteur', '2023-10-19 17:50:12', '2024-11-13 00:10:14', NULL, NULL, NULL, NULL),
	(4, 'Medi VEDOSO', 'ministre/01JCHHNHHE85CTR6PHEZDDW8K0.png', NULL, 0, 1, '+243897000227', 'Pasteur', '2023-10-23 08:18:06', '2024-11-13 00:19:37', NULL, NULL, NULL, NULL),
	(5, 'Christian MUTOMBO', 'ministre/01JCHH7KVSNST5CSGJMMH3CY3C.png', NULL, 0, 1, '+243897000227', 'Pasteur', '2023-10-23 08:18:43', '2024-11-13 00:12:01', NULL, NULL, NULL, NULL),
	(6, 'Héros MBUMBA', 'ministre/01JCHHEYRZ2XYNA89B3XZV9MPC.png', NULL, 0, 1, '+243897000227', 'Pasteur', '2023-10-23 08:19:12', '2024-11-13 00:16:01', NULL, NULL, NULL, NULL),
	(7, 'Françis NDOKAYI', 'ministre/1698056454.Pasteur Francis Ndokay-min.JPG', NULL, 0, 0, '+243897000227', 'Pasteur', '2023-10-23 08:20:54', '2024-11-02 02:02:27', NULL, NULL, NULL, NULL),
	(8, 'Anthony NKINZO', 'ministre/01JCHH9TGY686QZ1RXVNH5V6QD.png', NULL, 0, 1, '+243897000227', 'Pasteur', '2023-10-23 09:18:08', '2024-11-13 00:13:13', NULL, NULL, NULL, NULL),
	(9, 'Lord LOMBO', 'ministre/1698061208.395092332_18389460193027216_6206816548039522175_n.jpg', NULL, 0, 0, '+243897000227', 'Pasteur stagiaire', '2023-10-23 09:40:08', '2024-11-02 00:58:01', NULL, NULL, NULL, NULL),
	(10, 'Dulde Tsumbu Khenge ', 'ministre/01JCHH0REH1F1N1RWV8A9APVVD.png', '<p>La servante de Dieu, Dulde Khenge Tsumbu, est née le 5 septembre à Kinshasa. Elle a&nbsp; une&nbsp; formation&nbsp; en&nbsp; médecine&nbsp; et&nbsp; poursuit&nbsp; actuellement&nbsp; un&nbsp; cursus&nbsp; biblique&nbsp; pour approfondir sa connaissance des Écritures. Elle est mariée à Monsieur Jean-Loup Atambutu depuis 13 ans, et leur union a été bénie par la naissance de cinq enfants.<br>Dulde a donné sa vie au Seigneur en 1994 à Matadi, et a été baptisée le 27 avril 2019. Elle a servi fidèlement dans plusieurs départements de son église, notamment dans les cultes matinaux et en tant qu\'interprète. Son église locale est le Centre Missionnaire Philadelphie&nbsp; (CMP)&nbsp; à&nbsp; Gombe,&nbsp; qu\'elle&nbsp; a&nbsp; rejoint&nbsp; en&nbsp; septembre&nbsp; 2018&nbsp; après&nbsp; avoir découvert l\'œuvre de CMP à travers les médias.<br>Elle a pris conscience de son appel à servir le Seigneur lors d\'une retraite spirituelle en 2012. Aujourd\'hui, son plus grand désir est d\'aimer et de paître les brebis du Seigneur, suivant Sa volonté.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:08:16', '2025-05-20 03:50:47', NULL, NULL, NULL, NULL),
	(11, 'Dally Lukute Nyandu', 'ministre/01JCHJ14ADEXQN920THWNEF2W8.png', '<p>La servante de Dieu Dally Lukute Nyandu est née le 23 septembre à Goma. Elle détient une formation en droit économique et social. Elle est mariée à Monsieur Nyandu Kahindo Patrick-Benjamin depuis 9 ans, et leur union a été bénie par la naissance de cinq enfants.<br>Dally a donné sa vie au Seigneur en 2004 à Goma et a été baptisée à Kinshasa en 2007. Au sein de l\'Église, elle a servi dans plusieurs départements, notamment celui de la jeunesse et dans la commission de baptême et d\'affermissement.<br>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'elle a rejoint en 2013 après avoir été introduite à l\'œuvre par des frères et sœurs du Groupe Évangélique du Centenaire (GEC).<br>Elle a découvert son appel à travers une conviction personnelle, par révélation, ainsi que&nbsp; par&nbsp; l\'intermédiaire&nbsp; de&nbsp; ministres&nbsp; de&nbsp; Dieu.&nbsp; Son&nbsp; aspiration&nbsp; est&nbsp; de&nbsp; contribuer&nbsp; à l\'expansion de la Bonne Nouvelle à travers le monde en s\'investissant pleinement dans la mission. Elle souhaite apporter sa pierre à l\'édifice dans l\'Église, le Corps du Christ, et militer pour des messages christocentriques qui mettent l\'accent sur la centralité de Jésus-Christ.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:25:57', '2024-11-13 00:25:57', NULL, NULL, NULL, NULL),
	(12, 'Papy-Bo Bwango Mambula Bongonza', 'ministre/01JCHJR0AF7WPGN35XDS7KXNW2.png', '<p>Le serviteur de Dieu Papy-Bo Bwango Mambula Bongonza est né à Kinshasa le 4 juin. Après&nbsp; avoir&nbsp; obtenu&nbsp; une&nbsp; formation&nbsp; solide&nbsp; en&nbsp; sciences&nbsp; économiques,&nbsp; il&nbsp; s\'est engagé&nbsp; dans&nbsp; un&nbsp; parcours&nbsp; plus&nbsp; profond&nbsp; en&nbsp; poursuivant&nbsp; des&nbsp; études&nbsp; théologiques rigoureuses, ce qui lui a permis de renforcer ses connaissances spirituelles et de se préparer au ministère.<br>Il est marié à Madame Nancy Lukusa depuis 9 ans, et leur union a été bénie par la naissance de quatre enfants. Papy-Bo s\'est converti en 1991 à Kinshasa, à l\'église La Borne, où il a été baptisé en 1993.<br>Dans son cheminement, il a servi avec dévouement dans divers départements tels que la chorale, le ministère des grands jeunes, les fiancés et jeunes mariés, et a assuré la coordination des cellules. Sa riche formation théologique lui a permis de servir avec discernement et profondeur dans tous ces rôles.<br>Il est membre du Centre Missionnaire Philadelphie (CMP) à Gombe depuis le 24 février 2008, ayant suivi l\'évolution de cette œuvre depuis ses débuts. Papy-Bo a reçu son appel au ministère à travers des songes, des visions, ainsi que des messages prophétiques reçus par des serviteurs de Dieu.</p><p>Animé par une vision claire, il aspire à ramener les cœurs des fils vers le Père par la puissance de l\'Évangile et à impacter les âmes par l\'adoration, mettant à profit à la fois sa formation théologique et ses expériences spirituelles.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:27:11', '2024-11-13 00:38:26', NULL, NULL, NULL, NULL),
	(13, 'Anthony-Joel Sungu Muanda Tandi', 'ministre/01JCHJ8HWRWJ7SMTYC2F19TWXY.png', '<p>Le serviteur de Dieu Anthony-Joel Sungu Muanda Tandi est né à Kinshasa le 3 mai. Il est titulaire d\'une formation en informatique et est marié à Madame Sukari Verco Bella, avec qui il partage une union bénie depuis 4 mois.<br>Anthony-Joel s’est converti très jeune, dès son enfance, et a été baptisé le 22 octobre 2012. Il sert activement au département de l’intercession au sein de son église locale, le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint en 2017 après avoir été introduit par des frères qui fréquentaient déjà l\'église.<br>Dès l’âge de 10 ans, Anthony-Joel a reçu une vision claire de son appel lorsque le Seigneur lui est apparu pour lui parler de son ministère. Cet appel a été confirmé au fil des années, renforçant son engagement dans l’œuvre de Dieu.<br>Il aspire à apporter un message prophétique aux Nations et à gagner le monde par la parole et la démonstration de la puissance de Dieu, avec une passion pour l\'expansion de l\'Évangile et la transformation des vies</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:30:00', '2024-11-13 00:30:00', NULL, NULL, NULL, NULL),
	(14, 'René Molandi Zinano', 'ministre/01JCHJXJK0SDYNS1BSB701B5QS.png', '<p>Le serviteur de Dieu René Molandi Zinano est né à Kinshasa le 20 avril. Il détient une formation en gestion financière et poursuit actuellement des études en théologie pour approfondir sa compréhension des Écritures. Il est marié à Madame Léa Ngalula Kasongo, avec qui il partage 12 ans de mariage, une union bénie par la naissance d’un enfant.<br>René a donné sa vie au Seigneur en décembre 1997 à Bumba, où il a également été baptisé. Il a servi fidèlement au département de la chorale de son église locale, le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint en 2008 grâce à un frère de son église précédente.<br>Son appel au ministère lui a été révélé en 1997 à travers une vision dans laquelle son oncle, qui était pasteur, lui annonçait qu\'il serait appelé à servir Dieu en tant que pasteur. Cet appel n’a fait que se renforcer au fil des années.</p><p>René aspire à une intimité profonde avec Dieu, à semer la Parole pour transformer les cœurs, et à œuvrer dans le domaine de la délivrance des ténèbres, contribuant ainsi à la libération spirituelle de nombreux croyants.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:31:49', '2024-11-13 00:41:29', NULL, NULL, NULL, NULL),
	(15, 'Jonathan Mukongo Assani', 'ministre/01JCHK04XK246ZH1R5MSMFVGZE.png', '<p>Le serviteur de Dieu Jonathan Mukongo Assani est né le 30 juin à Kinshasa. Il est titulaire d\'une formation en droit, et a également suivi une formation en mission pratique à Pretoria, en Afrique du Sud. Marié à Madame Dulcinée Boyiko depuis 5 ans, leur union a été bénie par la naissance de trois enfants.<br>Jonathan a donné sa vie à Jésus-Christ le 19 septembre 2008, alors qu\'il était élève à l\'école Mont-Amba, et a été baptisé en décembre de la même année. Il a servi activement au département de la jeunesse.<br>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint en octobre 2013, suite à une invitation de son père. Jonathan a découvert son appel au ministère par une révélation du Seigneur lors d\'un temps de prière.<br>Il aspire à annoncer l\'Évangile et à impacter les communautés à travers des projets de développement visant à améliorer les conditions de vie.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:34:06', '2024-11-13 00:42:53', NULL, NULL, NULL, NULL),
	(16, 'Nathalie Muehe Domai', 'ministre/01JCHK12HTKK2NK1V6G0ZJE447.png', '<p>Le serviteur de Dieu Jonathan Mukongo Assani est né le 30 juin à Kinshasa. Il est titulaire d\'une formation en droit, et a également suivi une formation en mission pratique à Pretoria, en Afrique du Sud. Marié à Madame Dulcinée Boyiko depuis 5 ans, leur union a été bénie par la naissance de trois enfants.<br>Jonathan a donné sa vie à Jésus-Christ le 19 septembre 2008, alors qu\'il était élève à l\'école Mont-Amba, et a été baptisé en décembre de la même année. Il a servi activement au département de la jeunesse.<br>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint en octobre 2013, suite à une invitation de son père. Jonathan a découvert son appel au ministère par une révélation du Seigneur lors d\'un temps de prière.<br>Il aspire à annoncer l\'Évangile et à impacter les communautés à travers des projets de développement visant à améliorer les conditions de vie.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:35:33', '2024-11-13 00:43:23', NULL, NULL, NULL, NULL),
	(17, 'Eric Mbaya Sunga', 'ministre/01JCHK8JTM1FXXA48DCBAVFMHK.png', '<p>Le serviteur de Dieu Eric Mbaya Sunga est né le 8 novembre à Kinshasa. Il est titulaire&nbsp; d\'une&nbsp; formation&nbsp; en&nbsp; math-informatique&nbsp; ainsi&nbsp; qu\'en&nbsp; théologie.&nbsp; Marié&nbsp; à Madame Cathy Ekeke Mondanga depuis 7 ans, leur union a été bénie par la naissance de trois enfants.<br>Eric a donné sa vie au Seigneur en 2004, au Centre Évangélique Francophone La Borne à Kinshasa, et il a été baptisé le 21 février 2009. Il a servi avec dévouement dans plusieurs départements, notamment l\'évangélisation, le diaconat, ainsi que la coordination des cellules.<br>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint le 24 février 2008, après avoir découvert cette œuvre grâce à des camarades étudiants du Groupe Biblique Universitaire (GBU) à l\'UPN. Son appel au ministère lui a été révélé lors d\'une visitation divine où le Seigneur Jésus-Christ lui a parlé de son mandat spirituel.<br>Eric aspire à annoncer la Bonne Nouvelle et à faire des disciples, poursuivant avec passion son engagement dans l\'œuvre de Dieu.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:47:30', '2024-11-13 00:47:30', NULL, NULL, NULL, NULL),
	(18, 'Roane Mwabi Dalo', 'ministre/01JCHKBHRCWMZ74QSS2WQJK1ZD.png', '<p>La servante de Dieu Roane Mwabi Dalo est née à Kinshasa le 30 décembre. Elle détient une formation en musique et en relations publiques. Mariée à Monsieur Medi Wayikwa Vedoso depuis 4 ans, leur union a été bénie par la naissance de deux enfants.<br>Roane s\'est convertie en 2003 à l\'église La Borne UPN à Kinshasa, et elle a été baptisée le 26 juin 2011. Elle a servi dans plusieurs départements, notamment en tant que Hard Singer, dans la jeunesse, au Créa ainsi qu\'à la chorale.<br>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'elle a rejoint le 24 février 2008, après l\'avoir découvert grâce à ses parents. Le Seigneur lui a révélé son appel à l\'âge de 14 ans, et celui-ci a été confirmé au fil des années.<br>Pour Roane, le ministère est bien plus qu\'un titre : c\'est un style de vie, une manière de servir et de vivre en totale obéissance à Dieu.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:49:07', '2024-11-13 00:49:07', NULL, NULL, NULL, NULL),
	(19, 'Mulumba Katchy Serge', 'ministre/01JCHKF120ACYEHVBN3YAEJ52G.png', '<p>Le serviteur de Dieu Mulumba Katchy Serge est né le 4 mai à Kinshasa. Il détient une formation en fiscalité. Marié à Madame Mbala Muswamba Jolie depuis 21 ans, leur union a été bénie par la naissance de deux enfants.</p><p>Katchy s\'est converti à Kinshasa, à l\'église CEF La Trinité à Righini, et a été baptisé en août 2001. Tout au long de son parcours, il a servi dans plusieurs départements, notamment ceux de la jeunesse, de l\'intercession, du protocole, de la prédication, ainsi qu\'auprès des conseillers et partenaires.<br>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint en 2008, après avoir découvert cette œuvre grâce à l\'apôtre Roland Dalo. Il a reconnu&nbsp; son&nbsp; appel&nbsp; au&nbsp; ministère&nbsp; en&nbsp; servant&nbsp; au&nbsp; sein&nbsp; de&nbsp; l\'Église&nbsp; à&nbsp; Gembloux,&nbsp; en Belgique.<br>Son aspiration est de ne pas briser le roseau cassé ni éteindre la mèche qui fume encore, mais d\'accompagner les âmes dans une restauration intégrale par l\'amour et la compassion.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:51:01', '2024-11-13 00:51:01', NULL, NULL, NULL, NULL),
	(20, 'Godric Effata Mwindu', 'ministre/01JCHKJQXX3R50B4NYEDSH7QDA.png', '<p>Le serviteur de Dieu Godric Effata Mwindu est né le 31 mars à Kinshasa. Il détient une formation en économie. Marié à Madame Orhycia Musuamba Lukusa Mwindu depuis 4 ans, leur union a été bénie par la naissance de deux enfants.<br>Godric s\'est converti en 2000 à l\'église Communauté Baptiste du Fleuve Congo, où il a&nbsp; été&nbsp; baptisé&nbsp; le&nbsp; 5&nbsp; août&nbsp; de&nbsp; la&nbsp; même&nbsp; année.&nbsp; Il&nbsp; a&nbsp; servi&nbsp; fidèlement&nbsp; dans&nbsp; plusieurs départements, notamment celui du baptême et affermissement, de la formation et du suivi des âmes.<br>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint en juin 2016, après avoir découvert l\'œuvre au travers des enseignements en ligne. Son appel au ministère a été confirmé par des orientations prophétiques.</p><p>Godric aspire à œuvrer pour l\'avancement du Royaume de Dieu, à dépeupler les ténèbres, et à conduire les croyants vers une ressemblance à Christ.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:53:02', '2024-11-13 00:53:02', NULL, NULL, NULL, NULL),
	(21, 'Dieudonné Tshibuyi Tshiakambila', 'ministre/01JCHKQ82WTKYQWAJ8ECKBGVY2.png', '<p>Le serviteur de Dieu Dieudonné Tshibuyi Tshiakambila est né le 14 mars à Kinshasa. Il détient une formation en génie civil construction. Marié à Madame Micheline Tshabu Tambwe depuis 14 ans, leur union a été bénie par la naissance de quatre enfants.<br>Dieudonné a donné sa vie au Seigneur en 1991, à la maison familiale, et a été baptisé en 1998. Il a servi activement dans le département de baptême et d\'affermissement.</p><p>Son église locale est le Centre Missionnaire Philadelphie (CMP) à Gombe, qu\'il a rejoint le 10 juillet 2010, après avoir été introduit à l\'œuvre par son épouse. En 2006, il a reçu la confirmation de son appel au ministère à travers le pasteur Kupa.<br>Dieudonné voit le ministère comme une opportunité divine de servir non seulement l\'église,&nbsp; mais&nbsp; aussi&nbsp; d\'accompagner&nbsp; les&nbsp; autres&nbsp; ministères.&nbsp; Il&nbsp; est&nbsp; convaincu&nbsp; de l\'importance de la bivocation, croyant que sa mission est de combiner le séculier et le ministère pour un impact plus large.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:55:30', '2024-11-13 00:55:30', NULL, NULL, NULL, NULL),
	(22, 'Magali Simba Kaï', 'ministre/01JCHKSXCDVX1B4SWBVBTPYWJS.png', '<p>La servante de Dieu Magali Simba Kaï est née à Bruxelles le 11 mars. Elle est diplômée&nbsp; en&nbsp; sciences&nbsp; commerciales&nbsp; et&nbsp; consulaires.&nbsp; Mariée&nbsp; à&nbsp; Monsieur&nbsp; Stéphane Godfroid depuis 17 ans, leur union a été bénie par la naissance de deux enfants.<br>Magali a donné sa vie à Christ en 1989 à Kinshasa, à l\'église La Borne UPN, et a été baptisée&nbsp; le&nbsp; 27&nbsp; avril&nbsp; 1997.&nbsp; Au&nbsp; cours&nbsp; de&nbsp; son&nbsp; parcours,&nbsp; elle&nbsp; a&nbsp; servi&nbsp; dans&nbsp; divers départements tels que la louange, l\'Ecodim, les jeunes et adolescents, les couples, l\'éducation, ainsi qu\'au sein de la pastorale.<br>Son église locale actuelle est le Ministère Le Phare au Luxembourg, qu\'elle a rejoint après avoir découvert le Centre Missionnaire Philadelphie (CMP) lors de la visite de l\'apôtre Roland Dalo en 2013, et du passage du pasteur Ken en 2026 au CCI El Shaddai Luxembourg. Elle a découvert et confirmé son appel à servir Dieu pendant 14 années aux côtés du pasteur Adama Ouedraogo.<br>Magali aspire à être un Phare dans les ténèbres, guidant les âmes perdues et battues par&nbsp; la&nbsp; tempête&nbsp; vers&nbsp; le&nbsp; Père,&nbsp; en&nbsp; veillant&nbsp; à&nbsp; leur&nbsp; transformation&nbsp; à&nbsp; travers&nbsp; des enseignements solides et bibliques.</p>', 0, 1, '+243897000227', 'Pasteur', '2024-11-13 00:56:57', '2024-11-13 00:59:19', NULL, NULL, NULL, NULL);
