	(6, 'Alidor bope', '1997-03-31', NULL, '13 kinsenso. masina', '0811071863', 'alybm69@gmail.com', NULL, 'informaticien', '2020', 'phila cité d\'exaucement', '2021-02-13', 'phila cité d\'exaucement', NULL, NULL, '0', NULL, '1', NULL, 'Quotidienne', 'luc', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', 'Anglais', NULL, 'j\'ai suivi des formations en communications et lu des livres en leadership', '1', 'je sens que Dieu m\'appelle àça. et aussi j\'aimerai vraiment devenir un missionnaire en temps plein aū service de Dieu', 'devenir missionnairë', '1', '0', NULL, '2025-01-16 23:53:38', '2025-01-16 23:53:38'),
	(7, 'Mbala toko Valérian', '1991-07-25', NULL, '196 avenue tshibambi \r\nKintambo babylone', '0895553666', 'Valerianmbala@gmail.com', NULL, 'Artiste cinéaste', '2018', 'Église Christ est ma vie', '2018-06-02', 'Maison de miséricorde', NULL, NULL, '0', NULL, '0', NULL, 'Quotidienne', 'Psaumes', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', NULL, 'Lingala', 'J’ai eu à participer aux masters classes avec le docteur athom’s sur le leadership et parler en public', '1', 'Je me réfère toujours à ce que Jésus nous a dit aller et faites de ce monde mes disciples.\r\nJ’ai toujours voulu gagner les âmes pour la gloire de Jésus', 'Approfondir ma foi, devenir missionnaire et former les autres', '1', '0', NULL, '2025-02-12 08:02:00', '2025-02-12 08:02:00'),
	(8, 'MAKITA MOMBUSE RUTH', '2003-05-05', NULL, 'Av: Kamina n22\r\nC: kalamu \r\nQ:yolo nord', '0978443142', 'ruthmakiga9@gmail.com', NULL, 'Étudiante ( terminale) , entrepreneur', '2014', 'Église Dunamis explo', '2015-06-12', 'Centre missionnaire Philadelphie', '2 ans', 'Aucun ( en affermissement pour rejoindre un département)', '0', NULL, '0', NULL, 'Occasionnelle', 'Ruth', 'Non, je suis novice', 'Pas du tout familier', 'Francais', NULL, 'Lingala', 'En communication oui , car j’ai une formation en communication et la prise de parole en public', '1', 'Cela est un fardeau et un appel du seigneur', 'Approfondir ma foi , devenir missionnaire', '1', '0', NULL, '2025-02-12 08:02:04', '2025-02-12 08:02:04'),
	(9, 'David Wanzambi', '2001-05-05', NULL, 'n°01bis, bangala, kintambo/kinshasa', '0827706065', 'dvdwanzambi@gmail.com', NULL, 'Étudiant en terminal', '2016', 'Centre évangélique parole de vérité', '2016-12-31', 'Centre missionnaire Philadelphie Gombe', '2020', 'Intercession', '0', NULL, '0', NULL, 'Quotidienne', 'J\'étudie tout les livres bible de la même manière', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', 'Anglais', NULL, 'Oui, parce que je gère la communication d\'une structure et j\'ai des gens sous ma responsabilité dans la dite structure depuis plus d\'un an.', '1', 'Premièrement parce que c\'est un appel pour tout chrétien, deuxièmement parce que cela bouillonne dans mon cœur (le fardeau pour le salut des âmes), troisièmement parce que c\'est une passion pour moi. Enfin, parce que j\'aimerais avoir toutes les compétences physique ainsi que spirituelles afin d\'accomplir cette œuvre de mission.', 'Acquérir toutes les aptitudes possible, devenir missionnaire et former ceux qui ont cette même vocation.', '1', '0', NULL, '2025-02-12 08:03:56', '2025-02-12 08:03:56'),
	(10, 'TSHUMA-MUTOMBO-DJANNY', '1998-12-23', NULL, 'Av. De la science num 18. Q/haut commandement C /gombe', '+243817543784', 'djannytshuma2020@gmail.com', NULL, 'Libérale', '2020', 'Église centenaire /UPC / centre missionnaire Philadelphie', '2021-03-07', 'Centre missionnaire Philadelphie', '2018', 'Aucun', '0', NULL, '0', NULL, 'Quotidienne', 'Exode', 'Non, je suis novice', 'Moyennement familier', 'Francais', NULL, 'Lingala , tshiluba', 'Oui en communication , j’ai obtenue mon diplôme de licence en communication sociale .', '1', 'C’est un appel du seigneur , cela me permettrait d’avoir de la maîtrise dans la mission', 'Approfondir ma foi , péché les âmes négligées ainsi que ramener les cœurs à christ', '1', '0', NULL, '2025-02-12 08:15:15', '2025-02-12 08:15:15'),
	(11, 'Mwanza Tshibeybey Antoinette', '1969-05-30', NULL, '140A, Kabalo, commune de Kinshasa', '243 812347274', 'antomwanza05@gmail.com', NULL, 'Assistant administrative', '1990', 'Binez Ozone, Sola, rivière Mangungu', '2006-09-23', 'CMP', '2016', 'Evangelisation', '1', NULL, '0', 'Lors des implantations des extensions du CMP', 'Quotidienne', 'Aucun', 'Oui, je peux expliquer les fondement de la mission', 'Pas du tout familier', 'Francais', NULL, NULL, 'Non', '1', 'Pour être efficace dans la mission.', 'Pour devenir missionnaire', '1', '0', NULL, '2025-02-12 08:15:23', '2025-02-12 08:15:23'),
	(12, 'Hénoc ndola ngwi', '1998-05-20', NULL, 'Camp kokolo, pm bloc 5A', '0828186636', 'henocndola4@gmail.com', NULL, 'Étudiant', '', 'Fepaco nzambe malamu', '2012-12-29', 'Cmp', '2023', 'Nul part, mais nous voulons adhéré le chorale', '0', NULL, '0', NULL, 'Occasionnelle', 'Rien', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', NULL, NULL, NULL, 'Oui, d\'allier j\'ai déjà travaillé comme moniteur de l\'ecodim', '1', 'Parce je veux servir Dieu dans ma vie à tous prix, je veux gagner des âme accomplir Mathieu 28:18-20', 'Devenir missionnaire', '1', '0', NULL, '2025-02-12 08:17:19', '2025-02-12 08:17:19'),
	(13, 'Osongo Lokasha Christian', '1990-12-24', NULL, '8 Kabuiku, Q Abattoir Vallée , C/Masina', '0828814984', 'osongochristian3@gmail.com', NULL, 'informaticien', '2020', 'ECB 18 em rue', '2020-12-20', 'Phila C.E', 'Depuis Septembre 2024', 'Évangélisation', '0', NULL, '0', NULL, 'Occasionnelle', 'Pas de Lecture approfondie Jusqu\'à présent', 'Oui, je peux expliquer les fondement de la mission', 'Pas du tout familier', 'Francais', NULL, 'anglais légèrement niveau débutant', 'Pédagogue de formation,  et des capacités à intégrer des nouvelles compétences et le transmettre,  Pédagogiquement parlant je pense que je suis assez aguerris', '1', 'Accroître ma connaissance sur la théologie et pour ensuite gagner des âmes pour christ faire des toutes les nations ses disciplines', 'Approfondir ma foi et devenir un Missionnaire', '1', '0', NULL, '2025-02-12 08:20:05', '2025-02-12 08:20:05'),
	(14, 'Bijou Mukenga Wa Mukenga', '1986-03-04', NULL, '16 bis, Av. Barumbi, Yolo-Sud, Kalamu', '+243821753083', 'bijou04muk@gmail.com', NULL, 'HR and Operations Manager', '2007', 'Sang Précieux', '2007-01-27', 'Centre Missionnaire Philadelphie', 'Octobre 2019', 'AUMÔNERIE', '1', 'Étant membre active de l\'aumônerie, nous organisons de descentes dans les hôpitaux, les orphelinats, home des vieillards, prisons etc une à deux fois l\'an... pour parler de la bonne nouvelle de Jésus Christ.', '1', 'Les descentes de l\'aumônerie', 'Quotidienne', 'Luc et Apocalypse', 'Non, mais j\'ai quelques notions', 'Moyennement familier', 'Francais', 'Anglais', 'Mandarin, kreyol Haitien, Lingala', 'Oui car occupant des postes de responsabilités, j\'ai développé mes capacités transférer méthodiquement les informations, gérer les équipes et former la relève.', '1', 'J\'ai fait plusieurs rêves où je me voyais entrain de dire aux autres de tenir ferme pendant le chaos en fort et avec conviction que JÉSUS CHRIST EST LE ROI DE CE MONDE....rêves très repetitifs\r\nAlors, j\'ai opté pour une formation\r\n concrète pour mieux le faire.\r\nDonc, mon objectif est de mieux m\'outiller afin de réaliser cette mission noble avec sans faillir.', '1.Approndir ma foi et connaissances théologiques \r\n2. Devenir Missionnaire \r\n3. Propager la bonne nouvelle de Jésus Christ \r\n4. Être capable de transférer les connaissances acquises après formation', '1', '0', NULL, '2025-02-12 08:20:35', '2025-02-12 08:20:35'),
	(15, 'Nkongolo kayamba Josué', '2003-12-02', NULL, 'Ah/Bononge,N°23,Q/Des officiers\r\nC/Gombe,réf :camp kokolo', '0850938791', 'nkongolojosue8@gmail.com', NULL, 'Étudiant et entrepreneur', '2023', 'Centre missionnaire Philadelphie', '2023-04-01', 'Centre missionnaire Philadelphie', '2019', 'Au sein du département de la jeunesse plus précisément à la chorale', '1', NULL, '0', 'Si le mois évangélique compte,oui j\'ai participé à une mission déjà', 'Quotidienne', 'Jean', 'Non, mais j\'ai quelques notions', 'Moyennement familier', 'Francais', NULL, NULL, 'Oui,je suis apte à m\'adapter à un nouveau milieu et je sais m\'exprimer devant les gens.', '1', 'Accomplir la mission de Mathieu 28:19...\r\nAllez,faites de toutes les nations des disciples,les baptisants au nom du père,du fils et du Saint-esprit', 'Approndir mes connaissances,grandir dans ma foi,développer une relation encore plus forte avec DIEU et former d\'autres personnes', '1', '0', NULL, '2025-02-12 08:21:01', '2025-02-12 08:21:01'),
	(16, 'IBWA MBUNZIMU MERVEDI', '1998-01-10', NULL, '12, Nsanga, Lubudi, Bandalungwa', '+243819303557', 'mervedijustine@gmail.com', NULL, 'Médecin', '12 ans', 'Kinshasa', '2013-08-17', 'CMP GOMBE', 'Depuis 2017', 'Je sers au département de la jeunesse, dans l\'équipe d\'intercession.', '0', 'Atelier Paul, à CMP GOMBE, 6 mois. \r\nJe n\'ai pas connu une expérience missionnaire, si ce n\'est que d\'aller en province pour prêcher dans un séminaire au sein d\'une église protestante.', '1', NULL, 'Quotidienne', 'Les épîtres de Paul, les 4 évangiles, l\'apocalypse, et certains livres de l\'ancien testament.', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Lingala', 'En communication je dirais oui, en ce qui concerne la pédagogie je dirais aussi oui d\'autant plusque j\'encadre à la faculté de médecine où j\'ai finis certaines matières liées à la maison, mais aussi dans le cadre de l\'aumônerie dans laquelle j\'étais lors de mon passage à l\'université où j\'enseignais aux autres quelques sujets de la bible. Quand au leadership, je dirais que je peux gérer les gens d\'autant plus que j\'ai eu à assumer certaines fonctions lors de mon passage à l\'université, comme étant Aumônier de ma promotion, responsable principal de l\'administration du groupe évangélique du centenaire et actuellement à l\'église je suis responsable chargé de la discipline au sein de l\'équipe d\'intercession à la jeunesse CMP GOMBE.', '1', '- Premièrement c\'est un fardeau que Dieu a déposé dans mon cœur depuis plusieurs années, depuis ma conversion et même lors de mon passage à l\'université protestante au Congo où j\'étais aumônier de ma promotion que d\'apprendre davantage sur la mission et l\'œuvre de Dieu afin de gagner par la grâce de Dieu un grand nombre à Jésus-Christ.\r\n- Deuxième c\'est pour répandre l\'évangile dans les extrémités de la terre afin que les âmes soient sauvées par la bonne nouvelle de l\'évangile aussi avoir des stratégies me permettant de mieux m\'y prendre sans commettre trop d\'erreurs. \r\n- Enfin c\'est par amour pour le seigneur et dans le but de grandir dans les choses de Dieu.\r\n- Les objectifs : c\'est d\'abord pour la connaissance et l\' aiguisement spirituel de ma personne. En outre c\'est pour aider mon église dans cette mission grande qu\'elle a , celle de faire de toute les nations les disciples de Jésus.', '- d\'abord c\'est d\'approfondir ma connaissance sur Dieu et sur la mission ; \r\n- ensuite de devenir missionnaire.', '1', '0', NULL, '2025-02-12 08:28:00', '2025-02-12 08:28:00'),
	(17, 'MANSIANGI MBALA Gracia', '1998-09-20', NULL, '18,av/Zeka; Q/Musey; C/Ngaliema -Binza Ozone', '+243819299605', 'graciellamansiangimbala@gmail.com', NULL, 'Entrepreneuse', '2021', 'C.E Parole Vivante / La Borne Sola', '2022-12-24', 'Maison de Miséricorde', NULL, NULL, '0', NULL, '0', NULL, 'Quotidienne', 'Apocalypse', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Lingala', 'J’ai des notions de pédagogie parce que j’ai suivi une formation en pédagogie et j’ai déjà était encadreuse d’un mouvement des jeunes et j’ai également donné des formations à domicile et pour le leadership j’ai dirigé un mouvement des jeunes en tant que coordonnatrice du mouvement,  je suis également DG de mon entreprise et gérante dans une entreprise de la place', '1', 'Comme soldat enrôlé dans l’œuvre de Dieu, j’aimerai accomplir ma mission de disciple de Christ selon qu’il nous le demande dans Mathieu 28, d’aller faire de toutes les nations des disciples cette formation est une opportunité qui s’offre à moi pour arriver à cette fin et accomplir correctement ma mission sur terre', 'En effet, cette formation aura pour objectif de m’enraciner d’avantage dans ma foi chrétienne afin de produire des fruits en devenant missionnaire pour former d’autres personnes aussi dans la mission c’est à dire d’autres disciples', '1', '0', NULL, '2025-02-12 08:32:01', '2025-02-12 08:32:01'),
	(18, 'Guillaume MBUBU BOKOTE', '1995-02-12', NULL, 'Camp kokolo', '0813333118', 'bokote465gui@gmail.com', NULL, 'Libéral', '2011', 'Kinshasa Camp kokolo a l\'église protestante', '2012-12-25', 'Philadelphie', '2016', 'Chorale', '0', NULL, '0', NULL, 'Quotidienne', 'Genèse, Exode Josué, Esther,job,esaïe, Mathieu,jean, Luc, galates, corinthiens', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Lingala, swahili', 'Je suis diplômé en pédagogie général \r\nPour je pense que je suis capable de communiquer avec les autres.', '1', 'Je souhaite suivre cette formation pour s\'enrichir personnellement de la parole de Dieu et de connaître les différentes stratégies pour accomplir les désirs et la mission qui m\'à été faite par Jésus pour l\'intérêt de son royaume', 'J\'ai plusieurs objectifs dans cette formation \r\n1.approfondir ma foi \r\n2.devenir missionnaire pour transmettre aussi la bonne nouvelle aux autres ...', '1', '0', NULL, '2025-02-12 08:32:59', '2025-02-12 08:32:59'),
	(19, 'Etey luanda gabriel', '2003-08-03', NULL, 'C/ kinshasa \r\nAvenue / Lowa N•127', '+ 243 849787068', 'gabrielgatsby28@gmail.com', NULL, 'Étudiant', '2018', 'kimwenza', '2018-06-30', 'CMP', '2022', NULL, '0', NULL, '0', NULL, 'Occasionnelle', 'Hébreux 12:14', 'Non, je suis novice', 'Pas du tout familier', 'Francais', NULL, NULL, 'Non', '0', 'c’est mon souhait depuis longtemps de devenir missionnaire je disais ça même dans me prière et quand pasteur ken à fait cette appele pour la mission durant bunda 21 je directement compris que mon temps de commencé l’œuvre de Dieu', 'devenir missionnaire et former aussi d’autre personnes', '1', '0', NULL, '2025-02-12 08:36:21', '2025-02-12 08:36:21'),
	(20, 'Mitanda Mpia Providence', '1999-03-04', NULL, 'Av. Mukoso num 50, C/Bumbu', '0812888087', 'provimitanda@gmail.com', NULL, 'Ingénieur Informaticien', '2012', 'Bandundu-ville', '2012-07-13', 'CMP Gombe', '2022', 'Cénacle', '0', NULL, '0', NULL, 'Quotidienne', 'Génèse,  Exode, Romains, Luc, Actes, Marc, Galates, etc.', 'Non, mais j\'ai quelques notions', 'Pas du tout familier', 'Francais', NULL, 'Lingala, kikongo', 'Je suis pédagogue de formation, et durant mon parcours académique j\'ai assumé plusieurs fois les responsabilités liées au leadership (Chef de promotion ), y compris au sein de mon département.', '1', 'Premièrement c\'est pour répondre à l\'instruction divine. Je pense avoir reçu un appel pour la mission et cette formation s\'avère être une bonne occasion pour moi d\'être équipé, formé, aiguisé et bien taillé pour bien exercer cet appel.\r\nDeuxièmement c\'est pour acquérir des connaissances et techniques pratique pour bien méner une mission. Troisièmement c\'est pour apprendre les stratégies d\'évangélisation afin de bien répandre l\'évangile selon la demande de Jésus-Christ (Marc 16:15)', 'Devenir missionnaire, être bien formé dans l\'évangélisation', '1', '0', NULL, '2025-02-12 08:38:59', '2025-02-12 08:38:59'),
	(21, 'Mpiana kaboza Jonathan', '2002-01-05', NULL, 'Av, Mbomu n°127 Q/ Ngwaka, C/ Kinshasa', '+243 818426774', 'jonathanmpiana466@gmail.com', NULL, 'Étudiant', '2019', 'CMP', '2019-04-27', 'CMP', 'Depuis 2018', 'Évangélisation', '0', NULL, '0', NULL, 'Quotidienne', 'Jean', 'Non, mais j\'ai quelques notions', 'Moyennement familier', 'Francais', 'Anglais', NULL, 'Non.', '1', 'Parce que je vais devenir missionnaire.', 'Devenir missionnaire, formet d\'autre aussi approfondir ma foi.', '1', '0', NULL, '2025-02-12 08:41:44', '2025-02-12 08:41:44'),
	(22, 'KALEMA KINEMO MONIQUE', '2002-04-19', NULL, 'Av/ Bongandanga N°43 \r\nC/ Kasa Vubu \r\nQ/ Anciens Combattants', '+243812528073', 'moniquekalema1@gmail.com', NULL, 'Étudiante', '2017', 'CMP Gombe', '2022-11-26', 'CMP Gombe', 'Depuis le 31 Octobre 2022', 'Je compte intégrer le département de la jeunesse où je viens de finir la formation de l\'atelier Paul.', '0', 'Je n\'ai pas suivi une quelconque formation biblique ou théologique.', '0', NULL, 'Quotidienne', 'Le livre d\'Esther, de Néhémie, le 1er livre de Samuel et une partie du livre de Juges', 'Non, je suis novice', 'Pas du tout familier', 'Francais', NULL, 'Lingala, swahili, kikongo', 'Parlant des compétences je dirais car je n\'ai pas eu à les acquérir de façons formelles mais je dirais également avoir quelques aptitudes dans la communication sur lesquelles je travaille.', '0', 'Parce que j\'en suis convaincue et j\'en avais reçu la directive sans savoir clairement ce que cela signifiait à l\'époque mais c\'est avec le temps que les choses deviennent de plus en plus claires.\r\nD\'où, commencer par une formation me semble être avantageux pour rattraper les bases manquées.', 'Approfondir mes connaissances liées à la foi, m\'armer de la bonne connaissance et devenir missionnaire.', '0', '0', NULL, '2025-02-12 08:42:30', '2025-02-12 08:42:30'),
	(23, 'Yannick Nkuta MUTOMBO', '2003-06-01', NULL, 'De la science 16 , c/Gombe', '+243856190831', 'Yannkuta10@gmail.com', NULL, 'Étudiant', '2018', 'Cmp/gombe', '2021-11-23', 'Cmp/gombe', '2018', 'INTERCESSION', '0', NULL, '0', NULL, 'Quotidienne', 'Exode', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Lingala , Tshiluba', 'Je crois , un peu en leadership', '1', 'Je veux faire ce pourquoi le seigneur nous a dit de faire, obéir à l’ordre divin', 'Approfondir ma connaissance dans la mission', '1', '0', NULL, '2025-02-12 08:46:48', '2025-02-12 08:46:48'),
	(24, 'KAZETA, KAKIER ET JONAS', '1994-02-12', NULL, '21, avenue : Haute-tension Q/ Joli-parc C/ Ngaliema.', '082 21 11 395', 'kazeta.jonas@gmail.com', NULL, 'Libérale', '2009', 'Église: Cité Béthel.', '2009-07-30', 'Centre missionnaire Philadelphie.', 'Depuis 2014', 'La chorale', '0', 'Je ne suis pas encore allée en mission.', '1', NULL, 'Quotidienne', 'Luc 16: 19-31 et Marc 7:24-31.', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, NULL, 'En communication un peu et en leadership aussi un peu.', '0', 'Pour être équipé afin de bien faire mon travail étant ambassadeur de Jésus.', 'Approfondir ma connaissance pour bien travailler pour les intérêts du royaume ( gagner les âmes). \r\n\r\nEt aussi pour former les autres afin qu\'eux aussi gagnent les âmes pour Dieu.', '1', '0', NULL, '2025-02-12 08:46:58', '2025-02-12 08:46:58'),
	(25, 'KALALA KALOMBO JONATHAN', '1995-06-22', NULL, '43, avenue Mpika\r\nQuartier LUBUDI \r\nCommune BANDALUNGWA', '+243816606680', 'jonathahkalala2018@gmail.com', NULL, 'Libérale', '2013', 'Église Évangélique Le Puissant Rédempteur', '2015-02-14', 'CMP', '2020', 'Aucun', '0', 'Des missions concrètes n’ont pas eu lieu faute des moyens et la non achèvement de la formation', '1', NULL, 'Hebdomadaire', 'Mathieu', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Tshiluba', 'Oui, par la grâce de Dieu nous avons mené à bien certaines responsabilités de l’église qui exigeaient une bonne communication, c’est à dire cette capacité d’échanger avec les autres (membres de l’église, nouveaux venus et personnes à gagner dans le Seigneur). Toujours dans cette optique nous leurs avons enseigné les valeurs, bénéfices et la conduite du royaume en vue de leurs perfectionnements et enfin par le leadership du Saint Esprit en nous utilisant nous avons conduit ces fils du royaume à devenir semblable au maître ( Christ). \r\nGrâce à cela nous avons développé la capacité de faire passer le message convenablement, d’enseigner et de conduire des personnes à destination voulue.', '1', 'M’aiguiser en vue d’aiguiser les autres pour la croissance du royaume et sa maturité !', 'Accroître ma foi comme dit ci haut et ma connaissance de la personne de Christ dans le but de faire des autres disciples comme nous le sommes', '1', '0', NULL, '2025-02-12 08:50:10', '2025-02-12 08:50:10'),
	(26, 'Patrick disanka', '1989-11-30', NULL, '254 Rue De Luisa, Kinshasa, Democratic Republic of the Congo', '+243 899490300', 'patrickdisanka1@gmail.com', NULL, 'Libéral', 'Né dans une famille chrétienne', 'CACVH ex ACK', '2015-08-26', 'Centre missionnaire Philadelphie', 'Avril-mai 2022', 'Cenacle', '0', NULL, '0', NULL, 'Quotidienne', 'Évangile selon Jean, exode', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Lingala, tshilubaet le swahili', 'Je sais transmettre mon message vue que j\'ai fait les études pédagogique à l\'humanité', '1', 'Pour accomplire la seule mission que Christ nous a laissé celle de faire de toutes les Nations des disciples, les baptisent au nom du père, du fils, et du saint Esprit ( Mathieu 28:19)', 'Approfondir ma foi, croître spirituellement enfin d\'aider les autres à suivre Jésus-Christ', '1', '0', NULL, '2025-02-12 08:52:07', '2025-02-12 08:52:07'),
	(27, 'Tshambamba ndaye Jacques', '1997-07-20', NULL, 'Av pongo numéro 6 quartier des officiels/ camp kokolo', '+243990838009', 'Tshambambandaye@gma', NULL, 'Étudiant', '2013', 'Tshikapa', '2013-10-13', 'CMP', '2020', 'Au qu\'un', '0', NULL, '0', NULL, 'Quotidienne', 'Rien', 'Non, mais j\'ai quelques notions', 'Très familier', 'Francais', NULL, NULL, 'Un peu oui , mais pas vraiment vus que je ne jamais évangélise', '1', 'Premièrement c\'est un ordre divin ,  d\'aller partout dans le monde de faire toutes le nations des diciple , est comme moi j\'étais sauvé je devais sauvé aussi des autres voilà pourquoi je vais faire la formation en fin des sauvé des Âme', 'Mes objectifs sont  ,  premièrement d\' approfondir ma fois  comme vous venez de le dire est de devenir aussi missionnaire', '1', '0', NULL, '2025-02-12 08:54:55', '2025-02-12 08:54:55'),
	(28, 'Kaj Muanda Sophie', '1998-05-02', NULL, 'Av Kiluinzi n•191 ,commune de bandalungwa ,quartier de lingwala', '0821271312', 'kajsophie4@gmail.com', NULL, 'Étudiante', '2016', 'Centenaire de l’UPC', '2019-12-07', 'Centre missionnaire Philadelphie', '2016', 'Je n’ai pas de département', '0', NULL, '0', NULL, 'Occasionnelle', 'L’évangile de jean', 'Non, mais j\'ai quelques notions', 'Pas du tout familier', 'Francais', NULL, 'Lingala', 'Je suis capable de transmettre des idées de manière claire et adaptée aux besoins du public. J’utilise des outils variés ,oral, écrit pour rendre le message accessible et engageant.', '0', 'Je souhaiterais suivre cette formation missionnaire pour approfondir ma compréhension de la mission chrétienne, renforcer ma foi et acquérir les outils nécessaires pour aider et soutenir ceux qui en ont besoin.', 'j’espère approfondir ma relation personnelle avec Dieu et me préparer à relever les défis spirituels et pratiques de la mission.', '1', '0', NULL, '2025-02-12 08:55:28', '2025-02-12 08:55:28'),
	(29, 'Mpwa Zola Juvel', '2001-08-25', NULL, 'Avenue Baboro 18bis, commune de Kalamu, Quartier/Yolo-Sud.', '+243 828094860', 'longidan9@gmail.Com', NULL, 'Étudiant', '2010', 'Masina sainte-Thérèse', '2015-09-05', 'Église cité de Justice/Extension de Lemba', NULL, NULL, '1', NULL, '0', 'À l’une des extensions de ma communauté', 'Quotidienne', 'Les 4 Évangiles, Les Actes des apôtres, Les Épîtres de Paul, Les Épîtres Generales, Les livres Pentateuque et autres…', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', NULL, 'Lingala', 'Communication et leadership \r\nDes compétences naturelles et non scientifiques', '1', 'Déjà en parlant de la mission dans le cadre ecclésiastique, ce terme fait plus allusion à l’évangélisation,  et l’importance et l’urgence de l’évangélisation n’est plus à démontrer. Dans la vie du chrétien et de l’église l’évangélisation occupe une place très fondamentale.\r\n\r\nEt l’annonce de la bonne nouvelle du royaume de Dieu était le message central de Jésus, c’était même l’objet de son tout premier message (Matthieu 4:17)\r\n\r\nAlors ma motivation et mes objectifs à suivre cette formation missionnaire est d’aider l’église mais aussi l’enseigner à cultiver cette vie d’évangéliste quotidiennement et remettre l’évangélisation au centre des nos attentes et objectifs au sein de l’oeuvre de Dieu', 'Approfondir ma foi', '0', '0', NULL, '2025-02-12 09:03:38', '2025-02-12 09:03:38'),
	(30, 'KASEREKA KASOMEKO Méthode', '1994-05-02', NULL, 'Numéro 34, Avenue de la Gombe, Commune de la Gombe', '+243 990 314 494', 'methodekasereka@gmail.com', NULL, 'Évangéliste - Prédicateur de l\'Évangile', '2017', 'Centre Missionnaire Philadelphie', '2018-10-13', 'Centre Missionnaire Philadelphie', 'Depuis 2018', 'Département de l\'Aumônerie', '1', 'C\'était en Linge, à l\'Ecole de Ministère Morris CERULLO INTERNATIONAL (Californie USA) de l\'Évangeliste MORRIS CERULLO, pendant 1 an pour recevoir des certificats de réussite après chaque cours.', '1', 'Personnellement, j\'organise des Croisades d\'Evangélisation à masse, ici à Kinshasa et une fois en province (Kongo Centrale)', 'Quotidienne', 'Je peux dire toute la Bible ! Par la grâce de Dieu, j\'ai lu et relu toute la Bible des nombreuses fois, avec Méditation.', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', 'Anglais', 'Swahili, Lingala et Kinande (ma langue maternelle)', 'A vrai dire, je suis licencié en Sciences informatiques (Administration des bases de données) à ISIPA Kinshasa ; je suis Ir. Informaticien Administrateur des bases de données avec 5 ans d\'expériences, jusqu\'à ce que le Seigneur m\'a demandé de me consacrer à son oeuvre à temps plein !\r\n\r\nAujourd\'hui, par la grâce de Dieu, je suis Président Fondateur d\'un Ministre d\'évangélisation appelé CBJEN (The Cross and the Blood of Jesus Christ for the Nations) en œuvre jusqu\'à présent.', '1', 'L\'évangélisation c\'est mon appel. Mon cœur brûle pour le Salut des âmes; et le salut des âmes c\'est ma priorité ; m\'empêcher d\'annoncer l\'Évangile, c\'est comme boucher mes narines, afin de m\'empêcher à respirer.\r\n\r\nJe suis un Soldat du Christ, je suis un Évangéliste !', 'Avoir encore plus connaissances et expériences sur la mission ! \r\n\r\nEt pourquoi pas former les autres ! Car la mission consiste non seulement à gagner les âmes, mais aussi à en faire des disciples ! (Matthieu 28:19-20a)', '1', '0', NULL, '2025-02-12 09:06:29', '2025-02-12 09:06:29'),
	(31, 'KIAWUTUA FULAMA BLESS', '1999-09-08', NULL, 'Av:MBAMA 3 \r\nC/ NGALIEMA \r\nQ/CONGO', '0827170928', 'kiawutuabless@gmail.com', NULL, 'Libéral', '2014', 'CBFC/ LISALA', '2011-12-24', 'CBFC LISALA', 'Depuis La naissance ( 3mois a la dédicace)', 'Monitariat/ intercession', '0', 'Oui, j\'ai fait une formation des ouvriers pendant une année \r\nEn terme d\'expérience je suis a l\'encadrement des enfants vu mon titre de monitrice et la gérance des différents cas vu je fais des cures d\'âme là c\'est au niveau de l\'intercession', '1', NULL, 'Quotidienne', 'Livre de Ruth ,Samuel, la croissance de Jésus,ses miracles (les évangiles),,,', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, NULL, 'En communication Oui,( vu  je parle avec les enfants concernant leurs vies ( problème, difficulté, orientation)\r\nEn pédagogie oui( je suis monitrice)', '1', 'Je souhaite suivre cette formation en fin de propulser l\'évangile de Jésus Christ car nous sommes sauvé pour sauvé les autres', 'Devenir missionnaire', '1', '0', NULL, '2025-02-12 09:08:08', '2025-02-12 09:08:08'),
