	(112, 'Ntumba Mwanza Esther', '2004-09-13', NULL, 'Av. Lomande \r\nNuméro.1\r\nCommune. Ngaliema', '0812826021', 'ntumbamwanza198@gmail.com', 'Célibataire', 'Étudiante', '2022-08-12', 'Cité Béthel', '2021-05-09', 'Centre missionnaire Philadelphie', '2022', 'Intercession de la jeunesse', '0', NULL, '0', NULL, 'Quotidienne', 'Esther', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', NULL, NULL, 'Non', '0', 'Pour accomplir la grande mission que Christ nous a confié \r\nMatthieu 28:19 \r\nAllez,faites de toutes les nations des disciples,les baptisant au nom du père, du fils et du Saint Esprit', 'Approfondir ma foi, devenir missionnaire', '1', '0', NULL, '2025-02-19 17:05:16', '2025-02-19 17:05:16'),
	(113, 'Mpayi Nsumi Bertille', '1997-12-14', NULL, 'Avenue Logec villa 201. Q. mama Mobutu C. Mont Ngafula', '+243826210607', 'mpayibertille@gmail.com', 'Célibataire', 'Entrepreneure, fonctionnaire( formatrice)', '2014-07-01', 'Eglise choisis la vie', '2015-07-25', 'CMP', '2021', NULL, '0', NULL, '0', NULL, 'Quotidienne', 'Aucun', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Lingala', 'Quelques compétences en communication mais beaucoup plus sur les réseaux, un peu en leadership mais pas assez en pédagogie', '1', 'Je veux suivre cette formation parce que c\'est ce que je suis appelée à faire. Annoncer la bonne nouvelle de Christ dans toutes les nations', 'Approfondir ma connaissance en Dieu, devenir missionnaire, former d\'autres personnes', '1', '0', NULL, '2025-02-19 17:17:28', '2025-02-19 17:17:28'),
	(114, 'Jonathan BEKWA INGANA', '1995-09-05', NULL, '8, Av. Milambo Q/ Makelele C/ Bandalungwa', '828933580', 'josamuel.bekwa@gmail.com', 'Célibataire', 'Libéral', '2014-11-07', 'CENTRE MISSIONNAIRE FOI EN ŒUVRE', '2020-02-20', 'CE La Parole Éternelle Bandal', NULL, NULL, '0', NULL, '0', NULL, 'Occasionnelle', 'Aggée', 'Oui, je peux expliquer les fondement de la mission', 'Pas du tout familier', 'Francais', NULL, NULL, 'Oui, j’ai des compétences en communication, pédagogie et leadership. J’anime un groupe de prière, ce qui m’a appris à bien m’exprimer, à enseigner la Parole de Dieu et à encourager les autres dans leur foi.', '1', 'Je souhaite suivre cette formation missionnaire afin d’approfondir ma foi, de mieux comprendre ma mission en tant que serviteur de Dieu et d’être équipé pour partager efficacement l’Évangile. Mon désir est d’édifier les autres, de les encourager dans leur marche spirituelle et de contribuer à l’expansion du Royaume de Dieu avec sagesse et engagement.', 'Mon objectif dans le cadre de cette formation est d’approfondir ma foi, de mieux servir dans le ministère et d’édifier les autres en partageant les enseignements reçus. Je souhaite également développer mon appel et mettre en pratique ces connaissances pour impacter mon entourage spirituellement.', '1', '0', NULL, '2025-02-20 00:11:07', '2025-02-20 00:11:07'),
	(115, 'DIPOVA MBIZI BACHIR', '2001-10-23', NULL, 'Av: présidence n:24 Q: kimbwala C: MONT-NGAFULA', '0851723917', 'bachirmbizi3@gmail.com', 'Célibataire', 'Entrepreneur', '2018-02-20', 'Lukunga', '2018-03-23', 'TABEÉRA', NULL, NULL, '1', 'J\'ai déjà fais la mission evangelique dans le quartier de l\'église plusieurs fois;porte par porte ,et dans le marché j\'ai pu prêcher.\r\nPompage kimbwala, maman Mobutu et autre.', '1', 'À mama Mobutu et pompage', 'Hebdomadaire', 'Romain', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', NULL, 'Lingala ,un peu kikongo mais j\'entends bien kikongo', 'J\'ai des compétences pédagogie et leadership', '1', 'Approfondir ma foi ,devenir missionnaire et former d\'autres.', 'Devenir missionnaire et former d\'autres', '1', '0', NULL, '2025-02-20 03:32:05', '2025-02-20 03:32:05'),
	(116, 'Kulude awuma kem\'s', '1986-01-15', NULL, 'Avenue de la science numéro 3, Quartier Haut-commandement, commune de la Gombé', '±243825558652', 'Kem\'skulude1@gmail.com', 'Célibataire', 'Droit', '2015-11-13', 'Eglise la borne/ UPN', '2015-11-13', 'Centre missionnaire philadelphie', NULL, 'Département de l\'évanglisation', '1', NULL, '0', 'Durant le mois évangelique à lingwala', 'Quotidienne', 'Psaumes, proverbes', 'Non, mais j\'ai quelques notions', 'Moyennement familier', 'Francais', 'Anglais', NULL, 'Oui en somme je puis dire que j\'ai la compétence  communicationnelle et pédagique par le fait que j\'ai appris à l\'évanglisation comment aborder les gens et les parler de Christ.', '1', 'Ma motivation est celle de propager la Parole de Dieu partout. Quant aux objectifs c\'est d\'apporter la Parole de Dieu au-près de no-croyants de Jésus Christ et les ignorants dans but de sauver leurs âmes et de les amener en Jésus -Christ.', 'Pour moi les objectifs  sont: premièrement c\'est de complèter une connaissance très signicative à celle que j\'ai, deuxièment c\'est de me performer et troisièment et afin c\'est pour devenir missionnaire.', '1', '0', NULL, '2025-02-20 12:55:27', '2025-02-20 12:55:27'),
