	(152, 'Daniel Luzolo Kuzungulu', '2005-04-20', NULL, 'Av/Place  Mangue 20 \r\nQ/ Yolo Sud \r\nC/Kalamu', '+243971839018', 'luzolodaniel@icloud.com', 'Célibataire', 'Étudiant', '2024-11-13', 'Centenaire protestant', '2025-03-22', 'Centre Missionnaire Philadelphie', '03 décembre 2023', 'Je suis encore aux affermissement', '0', NULL, '0', NULL, 'Quotidienne', 'Psaume 27', 'Oui, je peux expliquer les fondement de la mission', 'Moyennement familier', 'Francais', NULL, 'Lingala', 'En communication oui \r\nJe sais communiquer avec les gens', '1', 'Pour avoir des connaissances approfondies sur la bible et pour répandre l’œuvre du Seigneur', 'Approfondir ma foi pour gagner des âmes pour continuer l’œuvre du Christ', '1', '0', NULL, '2025-03-23 15:07:57', '2025-03-23 15:07:57'),
	(153, 'Jonathan Mwambila Mwambila', '1995-01-09', NULL, 'Saio opala, kasa vubu 106', '0820786474', 'jonathanmwambila5@gmail.com', 'Célibataire', 'Libérale', '2014-09-10', 'Kinshasa, CMP Gombe', '2014-12-06', 'CMP Gombe', '06/12/2014', 'Suivi des âmes', '0', NULL, '1', NULL, 'Quotidienne', 'Actes des apôtres et autres', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', NULL, NULL, 'Non', '1', 'Je trouve dans cette formation un cadre idéal pour apporter la bonne nouvelle aux non atteint. Ce programme va me permettre d\'accomplir cette grande commission : faire des disciples.', 'Deux objectifs: devenir millionnaire et être en mesure de former les autres.', '1', '0', NULL, '2025-03-31 19:02:04', '2025-03-31 19:02:04'),
	(154, 'Elia Baraka', '1999-09-11', NULL, 'kasarani-Nairobi-Kenya', '+254 701 410931', 'eliabarakagedeon@gmail.com', 'Marié', 'Pasteur, Videgraph', '2011-04-05', 'Bukavu', '2012-08-13', '37è CADC CEF LE ROCHER/BUKAVU', NULL, NULL, '1', '- Nyangezi/ Territoire de Walungu/ Sud-Kivu : participé à la mission d\'Implantation d\'une église CEPAC (5semaines)\r\n- Burhinyi/ Territoire de Mwenga/ Sud-Kivu : Formation d\'une équipe d\'implication d\'église (1mois)\r\n- Bugarula/ Territoire d\'Idjwi Formation des pasteurs (3mois)', '1', NULL, 'Quotidienne', 'l\'Evangile selon Jean', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', 'Anglais', 'Swahili', 'Oui, j’ai des compétences en communication, en pédagogie et en leadership, qui me seront précieuses dans le cadre missionnaire. En tant que pasteur, j’ai l’habitude d’enseigner la Parole de Dieu, de guider spirituellement les fidèles et de communiquer avec clarté et impact. Mon expérience en formation et en développement personnel m’a permis d’acquérir des compétences pédagogiques solides, facilitant la transmission des enseignements bibliques de manière compréhensible et inspirante. De plus, en tant que leader, j’ai appris à motiver et à encadrer des groupes, à gérer des défis et à travailler en équipe pour accomplir une vision commune. Ces compétences me permettront de servir efficacement dans le cadre missionnaire, en apportant un message d’espérance et en encadrant les personnes spirituellement et socialement', '1', 'Je souhaite suivre cette formation missionnaire parce que j’ai à cœur d’accomplir l’appel de Dieu en partageant l’Évangile et en servant les autres. En tant que pasteur, je ressens le besoin d’approfondir mes connaissances bibliques, d’affermir ma foi et d’acquérir des compétences pratiques pour mieux répondre aux besoins spirituels et sociaux des communautés. Cette formation me permettra d’être plus efficace dans l’évangélisation, le discipulat et l’implantation d’églises. Je suis convaincu que cette formation renforcera ma capacité à impacter des vies et à manifester l’amour de Christ à travers mon engagement missionnaire.', 'Mon objectif principal dans cette formation est d’approfondir ma foi et de me préparer efficacement pour le travail missionnaire. Je veux acquérir des connaissances et des outils pratiques pour mieux partager l’Évangile, accompagner spirituellement les personnes et répondre aux besoins des communautés. Cette formation me permettra également de développer mes compétences en leadership et en enseignement afin de former d’autres personnes et de les équiper pour le ministère. Mon désir est d’être un instrument entre les mains de Dieu pour impacter des vies, implanter des églises et contribuer à l’édification du corps de Christ, notamment dans le contexte où je suis appelé à servir.', '1', '0', NULL, '2025-04-02 22:39:15', '2025-04-02 22:39:15'),
	(155, 'Danga Akode Deborah', '1993-06-26', NULL, 'Av: eben-ezer  numéro 2, quartier nganda commune de kintambo', '+243850858619', 'deborahdanga4@gmail.com', 'Célibataire', 'Libéral', '2004-05-14', 'Cepa mont ngafula', '2009-12-24', 'Cmp', '2021', 'Aucun', '1', 'Gangner des âmes. De porte à portes, comment faire les suivis des âmes vers le seigneur, les apprendre à croître et à garder la foi après les enseignements…\r\nCepa mont ngafula, arche lubumbashi, ministère de combat spirituel, fepaco nzambe Malamu', '1', 'Boma, matadi', 'Quotidienne', 'Juge 6', 'Non, mais j\'ai quelques notions', 'Moyennement familier', 'Francais', NULL, 'Lingala', 'Pas tellement mais naturellement oui', '1', 'Pour servir Dieu, et faire part à mes frères qui ne connaissent pas Dieu partout dans le monde', 'Devenir missionnaire est formée les autres.', '1', '0', NULL, '2025-04-13 20:36:09', '2025-04-13 20:36:09'),
	(156, 'KYUNGu mwepu Olivier', '2000-09-22', NULL, 'Minsk (Belarus)', '+375257176398', 'Oliviermwepu7@gmail.com', 'Célibataire', 'Étudiant', '2016-02-14', 'Cmp', '2016-03-20', 'Cmp', '2012', 'Évangélisation', '1', 'Maison de la bible ; EMMAUS( cours par correspondance)', '1', 'Les descentes sur terrain', 'Quotidienne', 'Actes', 'Oui, je peux expliquer les fondement de la mission', 'Très familier', 'Francais', 'Anglais', 'Russe ,', 'En leadership', '1', 'C\'est un impératif du Seigneur\r\nMt 28:19-20', 'Toutes les assertions sont bonnes et adéquates.', '1', '0', NULL, '2025-06-09 17:41:12', '2025-06-09 17:41:12'),
	(157, 'Gloria Dina Luvambu', '1995-10-30', NULL, 'Matuba 3 Selembao', '+247988053341', 'glorialuvambu@gmail.com', 'Célibataire', 'Maquilleuse professionnelle', '2025-07-09', 'Cape Town', '2017-08-17', 'Gospel Rama Cape Town', NULL, 'Dans la Technique', '0', NULL, '0', NULL, 'Occasionnelle', 'Job', 'Non, je suis novice', 'Pas du tout familier', 'Francais', NULL, NULL, 'Pas vraiment mais j’ai eu à travailler comme agent au centre d’appels ( call centre)', '1', 'En ce moment j’ai comme l’impression de perdre ma foi. \r\n\r\nCependant, je sais que sans Dieu dans ma vie, rien y ira donc je tiens à approfondir ma ma relation avec Dieu dans cette phase très compliquée de ma vie.', 'Beaucoup plus pour a approfondir ma vie, j’ai comme l’impression de sombrer dans le noir.   Je suis que la mission m’aidera.', '1', '0', NULL, '2025-07-09 03:53:09', '2025-07-09 03:53:09'),
	(158, 'Sanduku LUBWIMI Michelange', '2003-05-16', NULL, '55 av.botamba Q.Ngina C.Nsele MPASA 1 ville de Kinshasa', '+243 998 512 637', 'angelofreezer19@gmail.com', 'Célibataire', 'Coopérant', '2018-08-18', 'Kinshasa - rivière ndjili', '2018-08-18', 'Mission d’intercession pour les nations', NULL, NULL, '1', NULL, '0', 'Affermissement', 'Hebdomadaire', 'Genèse Matthieu Luc actes des apôtres juges 1 Samuel', 'Non, je suis novice', 'Très familier', 'Francais', NULL, NULL, 'Pas vraiment', '1', 'Parce que j’ai un appel à être missionnaire et j’aimerais aussi me former avec les bases', 'Devenir missionnaire', '1', '0', NULL, '2025-07-23 16:34:46', '2025-07-23 16:34:46');
