false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 6\\"\\/>\\r\\n <\\/w:LatentStyles>\\r\\n<\\/xml><![endif]--><!--[if gte mso 10]>\\r\\n<style>\\r\\n \\/* Style Definitions *\\/\\r\\n table.MsoNormalTable\\r\\n\\t{mso-style-name:\\"Tableau Normal\\";\\r\\n\\tmso-tstyle-rowband-size:0;\\r\\n\\tmso-tstyle-colband-size:0;\\r\\n\\tmso-style-noshow:yes;\\r\\n\\tmso-style-priority:99;\\r\\n\\tmso-style-parent:\\"\\";\\r\\n\\tmso-padding-alt:0cm 5.4pt 0cm 5.4pt;\\r\\n\\tmso-para-margin:0cm;\\r\\n\\tmso-para-margin-bottom:.0001pt;\\r\\n\\tline-height:115%;\\r\\n\\tmso-pagination:widow-orphan;\\r\\n\\tfont-size:11.0pt;\\r\\n\\tfont-family:\\"Arial\\",sans-serif;\\r\\n\\tmso-ansi-language:#000C;}\\r\\n<\\/style>\\r\\n<![endif]-->\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Sous- th\\u00e8me : Votre Attention s\\u2019il vous pla\\u00eet<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Orateur : Pasteur MeDi Vedoso<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">R\\u00e9f\\u00e9rence Biblique : Luc 10 : 38 - 42<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Votre attention veut indiquer que l\\u2019on veut\\r\\ndonner un message important qui doit retenir l\\u2019attention.<br style=\\"mso-special-character:line-break\\">\\r\\n<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Dans le passage de base, Marthe \\u00e9tait\\r\\ndistraite, quelque chose se passait quelque part mais elle \\u00e9tait occup\\u00e9e \\u00e0\\r\\nautre chose. Quelque chose se passait dans la maison. Marie, elle \\u00e9tait dans la\\r\\npr\\u00e9sence de Dieu, assise aux c\\u00f4t\\u00e9s de J\\u00e9sus-Christ mais Marthe \\u00e9tait ailleurs,\\r\\nelle n\\u2019avait pas orient\\u00e9e son attention au bon endroit.<\\/span><\\/p><p class=\\"MsoNormal\\"><u><span lang=\\"fr\\">Qu\\u2019est ce l\\u2019attention?<\\/span><\\/u><span lang=\\"fr\\"> : <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"margin-left:36.0pt;text-indent:-18.0pt;mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\"><span style=\\"mso-list:Ignore\\">\\u25cf<span style=\\"font:7.0pt &quot;Times New Roman&quot;\\">&nbsp;&nbsp;&nbsp;&nbsp;\\r\\n<\\/span><\\/span><\\/span><span lang=\\"fr\\">C\'est parler de la concentration\\r\\nde l\\u2019activit\\u00e9 mentale sur un objet;<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"margin-left:36.0pt;text-indent:-18.0pt;mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\"><span style=\\"mso-list:Ignore\\">\\u25cf<span style=\\"font:7.0pt &quot;Times New Roman&quot;\\">&nbsp;&nbsp;&nbsp;&nbsp;\\r\\n<\\/span><\\/span><\\/span><span lang=\\"fr\\">C\'est le fait de remarquer quelque\\r\\nchose;<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"margin-left:36.0pt;text-indent:-18.0pt;mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\"><span style=\\"mso-list:Ignore\\">\\u25cf<span style=\\"font:7.0pt &quot;Times New Roman&quot;\\">&nbsp;&nbsp;&nbsp;&nbsp;\\r\\n<\\/span><\\/span><\\/span><span lang=\\"fr\\">C\'est le fait de consid\\u00e9rer une\\r\\nchose ou une personne;<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"margin-left:36.0pt;text-indent:-18.0pt;mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\"><span style=\\"mso-list:Ignore\\">\\u25cf<span style=\\"font:7.0pt &quot;Times New Roman&quot;\\">&nbsp;&nbsp;&nbsp;&nbsp;\\r\\n<\\/span><\\/span><\\/span><span lang=\\"fr\\">C\'est la conscience de r\\u00e9pondre \\u00e0\\r\\nune ou plusieurs choses.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Dans la vie en g\\u00e9n\\u00e9rale et dans la vie\\r\\nspirituelle, l\'attention est d\\u2019une grande importance.<br>\\r\\nEn venant \\u00e0 la pri\\u00e8re ce matin,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>vous\\r\\navez d\\u00fb faire attention l\\u00e0 o\\u00f9 vous avez mis vos pieds quand vous traversez. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">L\\u2019homme de <i style=\\"mso-bidi-font-style:normal\\">Marc\\r\\n10 : 46<\\/i>, Barthim\\u00e9e \\u00e0 acc\\u00e9der \\u00e0 son miracle, il \\u00e9tait aveugle et en \\u00e9tant\\r\\naveugle il a perdu la vue,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>mais il avait\\r\\nencore l\'ou\\u00efe pour \\u00eatre attentif, il a demand\\u00e9 ce qu\\u2019il se passe, on lui dit\\r\\nque c\\u2019est J\\u00e9sus. Alors il se met \\u00e0 crier J\\u00e9sus Fils de David aie piti\\u00e9 de moi. <br>\\r\\nIl continue de placer son attention sur le fils de David, malgr\\u00e9 les obstacles\\r\\nqui lui demandent de se taire. <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">M\\u00eame lorsque l\'on\\r\\nperd des choses, il nous reste des choses qui nous permettent d\'\\u00e9voluer.<\\/span><\\/i><\\/b><\\/p><p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">Barthim\\u00e9e avait\\r\\nperdu la vue, il lui restait l\'ou\\u00efe qui lui permit d\'\\u00eatre sauv\\u00e9.<\\/span><\\/i><\\/b><span lang=\\"fr\\"><br>\\r\\n<b style=\\"mso-bidi-font-weight:normal\\"><i style=\\"mso-bidi-font-style:normal\\">Ne\\r\\nregarde pas les obstacles, place ton attention au bon endroit, sur J\\u00e9sus.<\\/i><\\/b><\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">C\\u2019est par l\'attention d\\u2019abord, avant la foi,\\r\\nqui lui a permis de savoir que quelque chose se passait.<br>\\r\\nDieu quand il veut parler \\u00e0 Mo\\u00efse avant de lui montrer<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>sa puissance, Dieu commence \\u00e0 attirer son\\r\\nattention, il fait le buisson ardent. Il part de son attention pour lui parler\\r\\ndu reste. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Exode 31 : 2- 3<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Jacob remarque le visage de Laban et se rend\\r\\ncompte que son visage a chang\\u00e9.<br>\\r\\nL\\u2019attention est un capital important pour les humains, on ach\\u00e8te les choses, on\\r\\npeut acheter des choses, on peut atteindre une s\\u00e9curit\\u00e9. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">La bible dit que l\'homme prudent voit le mal\\r\\nde loin, l\\u2019homme qui fait attention en voyant le mal et s\'en cache. <br>\\r\\nL\'attention est un \\u00e9l\\u00e9ment important. Dans la vie nous arrivons \\u00e0 des endroits\\r\\nparce que nous les avons consid\\u00e9r\\u00e9s. Matthieu 7 ( parabole des deux maisons),\\r\\nune maison a subsist\\u00e9 et l\\u2019autre s\\u2019est \\u00e9croul\\u00e9e. L\\u2019un des propri\\u00e9taires a\\r\\nprivil\\u00e9gi\\u00e9 les fondations et la structure de l\'\\u00e9difice et l\\u2019autre a choisi de\\r\\nne mettre l\'accent que sur l\'aspect esth\\u00e9tique.<br>\\r\\n<b style=\\"mso-bidi-font-weight:normal\\"><i style=\\"mso-bidi-font-style:normal\\">Par\\r\\nrapport \\u00e0 ce que Dieu a pr\\u00e9vu, il faudra faire attention et \\u00eatre attentif.<\\/i><\\/b><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Gen\\u00e8se 3<i style=\\"mso-bidi-font-style:normal\\">\\r\\n<\\/i><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">\\u00c0 quel moment la femme a pris conscience de\\r\\nl\\u2019arbre interdit? Quand l\\u2019ennemi, le serpent a attir\\u00e9 son attention. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Elle vit ce jour-l\\u00e0 que le fruit est bon \\u00e0\\r\\nmanger. Pendant tout le temps son attention \\u00e9tait sur ce que Dieu leur avait\\r\\ndit, vers certaines caract\\u00e9ristiques de l\\u2019attention il y a eu un shift tel\\r\\nqu\\u2019elle a vu quelque chose qu\\u2019elle n\'avait pas vu avant.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Pendant ce temps de pri\\u00e8re, sur quoi portera\\r\\nton attention ?<br>\\r\\nPendant le programme Bunda 21 le diable ne part pas en vacances, il vous\\r\\nmontrera des choses; alors est ce que vous resterez attentionn\\u00e9s sur ce que\\r\\nDieu a dit et dira ou sur ce que le diable vous montre ou montrera ? <br>\\r\\n<br>\\r\\nAllez-vous vous concentrer sur la face de Dieu ou allez- vous c\\u00e9der aux\\r\\ntentations ?<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Il y aura des occasions d\\u2019\\u00eatre distraits, <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Bunda 21 n\\u2019est pas une ambassade o\\u00f9 l\\u2019on pense\\r\\n\\u00eatre automatiquement hors p\\u00e9rim\\u00e8tre de tentations, cela d\\u00e9pendra de l\\u00e0 o\\u00f9 sera\\r\\nplac\\u00e9e votre attention. Il n y a pas de grand ou petit p\\u00e9ch\\u00e9, la diff\\u00e9rence\\r\\nr\\u00e9side dans les cons\\u00e9quences; quelque chose que tu n\\u2019as jamais fait en plein\\r\\nBunda 21 peut arriver. Tu peux voler, falsifier une signature, accepter de\\r\\ncourtiser une autre femme que ton \\u00e9pouse, accepter les avances d\'un homme\\r\\nmari\\u00e9, \\u2026<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">En plein jardin d\'Eden Adam et \\u00c8ve ont d\\u00e9tourn\\u00e9 leur regard de tout ce que Dieu\\r\\navait dit pour regarder ce que le diable a montr\\u00e9. <br>\\r\\nLorsque l\\u2019on vous dit <b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\">votre Attention s\\u2019il vous plait<\\/i><\\/b>,\\r\\ncela signifie qu\\u2019il faut porter son attention sur l\\u2019essentiel.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Pendant Bunda 21, choisissez de vous connecter\\r\\n\\u00e0 Dieu, d\\u00e9cidez de chercher sa face malgr\\u00e9 tout ce qui vous entoure. <\\/span><br style=\\"mso-special-character:line-break\\"><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">\\r\\n<\\/span><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">C\'est\\r\\npossible d\'\\u00eatre \\u00e0 Bunda 21 o\\u00f9 J\\u00e9sus est pr\\u00e9sent mais ne pas \\u00eatre \\u00e0 l\'endroit de\\r\\nsa manifestation<\\/span><\\/i><span lang=\\"fr\\"> ! <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Marthe a commis une faute, on est dans la m\\u00eame\\r\\nmaison les choses sont importantes mais c\\u2019est l\\u00e0 o\\u00f9 J\\u00e9sus est pas l\\u00e0 o\\u00f9 elle\\r\\nest, Dieu veut qu\\u2019elle soit \\u00e0 ses pieds.<br>\\r\\nDans la m\\u00eame maison, une est dans la pr\\u00e9sence du Seigneur, l\\u2019autre est\\r\\ndistraite et regarde ailleurs.<br>\\r\\nPendant Bunda 21 o\\u00f9 sera ton attention ? <br>\\r\\nQu\\u2019est ce que tu peux rechercher, que peux tu chercher dans la pr\\u00e9sence du\\r\\nSeigneur?<br>\\r\\nIl a besoin de notre attention, de notre concentration mentale.<br>\\r\\nNous venons chercher la face de l\\u2019\\u00c9ternel. Il ne suffira pas que je sois dans\\r\\nla maison o\\u00f9 J\\u00e9sus est je dois \\u00eatre dans sa pr\\u00e9sence, je dois bannir la\\r\\ndistraction. <br>\\r\\n<br>\\r\\nAlors, <b style=\\"mso-bidi-font-weight:normal\\">Votre attention s\\u2019il vous\\r\\npla\\u00eet!!!<\\/b><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">&nbsp;<\\/span><\\/p>","en":null}', NULL, NULL, 1, 'cherchez-continuellement-sa-face-1', 1, '2023-11-04 23:56:12', '2024-11-14 19:04:29', NULL, '2023-10-30 07:00:00', NULL, 4),
	(10, '{"fr":"Cherchez continuellement sa face (2)","en":null}', 3, 'https://www.youtube.com/watch?v=NmJ_5TSMTFo', '{"fr":"posts\\/1699146486.B21-Vign-J2-Matin.jpg","en":""}', '{"fr":"<!--[if gte mso 9]><xml>\\r\\n <w:WordDocument>\\r\\n  <w:View>Normal<\\/w:View>\\r\\n  <w:Zoom>0<\\/w:Zoom>\\r\\n  <w:TrackMoves\\/>\\r\\n  <w:TrackFormatting\\/>\\r\\n  <w:PunctuationKerning\\/>\\r\\n  <w:ValidateAgainstSchemas\\/>\\r\\n  <w:SaveIfXMLInvalid>false<\\/w:SaveIfXMLInvalid>\\r\\n  <w:IgnoreMixedContent>false<\\/w:IgnoreMixedContent>\\r\\n  <w:AlwaysShowPlaceholderText>false<\\/w:AlwaysShowPlaceholderText>\\r\\n  <w:DoNotPromoteQF\\/>\\r\\n  <w:LidThemeOther>EN-US<\\/w:LidThemeOther>\\r\\n  <w:LidThemeAsian>X-NONE<\\/w:LidThemeAsian>\\r\\n  <w:LidThemeComplexScript>X-NONE<\\/w:LidThemeComplexScript>\\r\\n  <w:Compatibility>\\r\\n   <w:BreakWrappedTables\\/>\\r\\n   <w:SnapToGridInCell\\/>\\r\\n   <w:WrapTextWithPunct\\/>\\r\\n   <w:UseAsianBreakRules\\/>\\r\\n   <w:DontGrowAutofit\\/>\\r\\n   <w:SplitPgBreakAndParaMark\\/>\\r\\n   <w:EnableOpenTypeKerning\\/>\\r\\n   <w:DontFlipMirrorIndents\\/>\\r\\n   <w:OverrideTableStyleHps\\/>\\r\\n  <\\/w:Compatibility>\\r\\n  <w:DoNotOptimizeForBrowser\\/>\\r\\n  <m:mathPr>\\r\\n   <m:mathFont m:val=\\"Cambria Math\\"\\/>\\r\\n   <m:brkBin m:val=\\"before\\"\\/>\\r\\n   <m:brkBinSub m:val=\\"&#45;-\\"\\/>\\r\\n   <m:smallFrac m:val=\\"off\\"\\/>\\r\\n   <m:dispDef\\/>\\r\\n   <m:lMargin m:val=\\"0\\"\\/>\\r\\n   <m:rMargin m:val=\\"0\\"\\/>\\r\\n   <m:defJc m:val=\\"centerGroup\\"\\/>\\r\\n   <m:wrapIndent m:val=\\"1440\\"\\/>\\r\\n   <m:intLim m:val=\\"subSup\\"\\/>\\r\\n   <m:naryLim m:val=\\"undOvr\\"\\/>\\r\\n  <\\/m:mathPr><\\/w:WordDocument>\\r\\n<\\/xml><![endif]--><!--[if gte mso 9]><xml>\\r\\n <w:LatentStyles DefLockedState=\\"false\\" DefUnhideWhenUsed=\\"false\\"\\r\\n  DefSemiHidden=\\"false\\" DefQFormat=\\"false\\" DefPriority=\\"99\\"\\r\\n  LatentStyleCount=\\"371\\">\\r\\n  <w:LsdException Locked=\\"false\\" Priori