n   Name=\\"List Table 7 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 6\\"\\/>\\r\\n <\\/w:LatentStyles>\\r\\n<\\/xml><![endif]--><!--[if gte mso 10]>\\r\\n<style>\\r\\n \\/* Style Definitions *\\/\\r\\n table.MsoNormalTable\\r\\n\\t{mso-style-name:\\"Tableau Normal\\";\\r\\n\\tmso-tstyle-rowband-size:0;\\r\\n\\tmso-tstyle-colband-size:0;\\r\\n\\tmso-style-noshow:yes;\\r\\n\\tmso-style-priority:99;\\r\\n\\tmso-style-parent:\\"\\";\\r\\n\\tmso-padding-alt:0cm 5.4pt 0cm 5.4pt;\\r\\n\\tmso-para-margin:0cm;\\r\\n\\tmso-para-margin-bottom:.0001pt;\\r\\n\\tline-height:115%;\\r\\n\\tmso-pagination:widow-orphan;\\r\\n\\tfont-size:11.0pt;\\r\\n\\tfont-family:\\"Arial\\",sans-serif;\\r\\n\\tmso-ansi-language:#000C;\\r\\n\\tmso-fareast-language:FR;}\\r\\n<\\/style>\\r\\n<![endif]-->\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Orateur : Pasteur H\\u00e9ros Mbumba<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">S\\/Th\\u00e8me :<b style=\\"mso-bidi-font-weight:normal\\"><i style=\\"mso-bidi-font-style:normal\\"><span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>Le\\r\\nRepos de Dieu.<\\/i><\\/b><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">R\\u00e9f\\u00e9rences Bibliques : Gen\\u00e8se 32. 24-30 ; 2\\r\\nchroniques 15. 12-15 <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">Gen\\u00e8se 32\\r\\n:28 Il dit encore : ton nom ne sera plus Jacob, mais tu seras appel\\u00e9 Isra\\u00ebl ;\\r\\ncar tu as lutt\\u00e9 avec Dieu et avec des hommes, et tu as \\u00e9t\\u00e9 vainqueur.<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">Gen\\u00e8se 32\\r\\n:30 Jacob appela ce lieu du nom de Peniel : car, dit-il, j\'ai vu Dieu face \\u00e0\\r\\nface, et mon \\u00e2me a \\u00e9t\\u00e9 sauv\\u00e9e.<\\/span><\\/i><span lang=\\"fr\\"><br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Quand on rencontre Dieu face \\u00e0 face, il change\\r\\nnotre identit\\u00e9, si tu es entr\\u00e9 dans ce Bunda comme Jacob, tu en ressortiras\\r\\ncomme Isra\\u00ebl. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Vous ne pouvez pas rencontrer le Seigneur face\\r\\n\\u00e0 face et avoir la m\\u00eame vie. Il accorde la d\\u00e9livrance&nbsp;; l\\u2019\\u00e2me est sauv\\u00e9e ! <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Nous ne\\r\\nsommes pas ici en tourisme. Nous y sommes pour un but, la d\\u00e9livrance, ayant vu\\r\\nsa face.<\\/span><\\/b><span lang=\\"fr\\"><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Et ce midi, d\\u00e9clare ceci : \\u00ab&nbsp;<b style=\\"mso-bidi-font-weight:normal\\"><i style=\\"mso-bidi-font-style:normal\\">parce\\r\\nque je t\'ai vu Seigneur, accorde d\\u00e9livrance \\u00e0 ma maison, \\u2026&nbsp;\\u00bb<\\/i><\\/b> <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">2 chroniques 15. 12-15<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">2\\r\\nChroniques 15 :15. Tout Juda se r\\u00e9jouit de ce serment, car ils avaient jur\\u00e9 de\\r\\ntout leur c\\u0153ur, ils avaient cherch\\u00e9 l\'\\u00c9ternel de plein gr\\u00e9, et ils l\'avaient\\r\\ntrouv\\u00e9, et l\'\\u00c9ternel leur donna du repos de tous c\\u00f4t\\u00e9s.<\\/span><\\/i><span lang=\\"fr\\"><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">Le repos de Dieu est plus que celui que les hommes pr\\u00e9tendent\\r\\naccorder. <br><\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Retenons que parce que nous avons vu Dieu face\\r\\n\\u00e0 face, cette rencontre engendre trois cons\\u00e9quences : <br><\\/span><\\/p>\\r\\n\\r\\n<ol style=\\"margin-top:0cm\\" start=\\"1\\" type=\\"1\\"><li class=\\"MsoNormal\\" style=\\"mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\">Le\\r\\n     changement d\\u2019identit\\u00e9 ;<\\/span><\\/li><li class=\\"MsoNormal\\" style=\\"mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\">La\\r\\n     d\\u00e9livrance de mon \\u00e2me ;<\\/span><\\/li><li class=\\"MsoNormal\\" style=\\"mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\">Le repos de\\r\\n     Dieu.<\\/span><span lang=\\"fr\\"> <br><\\/span><\\/li><\\/ol>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Amen !!!<\\/span><\\/p>","en":null}', NULL, NULL, 1, 'cherchez-continuellement-sa-face-2', 1, '2023-11-05 00:20:39', '2024-11-14 19:04:29', NULL, '2023-10-31 14:00:00', NULL, 6),
