"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 6\\"\\/>\\r\\n <\\/w:LatentStyles>\\r\\n<\\/xml><![endif]--><!--[if gte mso 10]>\\r\\n<style>\\r\\n \\/* Style Definitions *\\/\\r\\n table.MsoNormalTable\\r\\n\\t{mso-style-name:\\"Tableau Normal\\";\\r\\n\\tmso-tstyle-rowband-size:0;\\r\\n\\tmso-tstyle-colband-size:0;\\r\\n\\tmso-style-noshow:yes;\\r\\n\\tmso-style-priority:99;\\r\\n\\tmso-style-parent:\\"\\";\\r\\n\\tmso-padding-alt:0cm 5.4pt 0cm 5.4pt;\\r\\n\\tmso-para-margin:0cm;\\r\\n\\tmso-para-margin-bottom:.0001pt;\\r\\n\\tline-height:115%;\\r\\n\\tmso-pagination:widow-orphan;\\r\\n\\tfont-size:11.0pt;\\r\\n\\tfont-family:\\"Arial\\",sans-serif;\\r\\n\\tmso-ansi-language:#000C;}\\r\\n<\\/style>\\r\\n<![endif]-->\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">R\\u00e9f\\u00e9rence Biblique: 1 Chroniques 7:11; Psaumes\\r\\n42:2<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Pour les h\\u00e9breux parler de la pr\\u00e9sence de\\r\\nDieu, en profondeur c\\u2019\\u00e9tait parler de la face de Dieu.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">C\\u2019est-\\u00e0-dire, qu\\u2019on parle toujours de la\\r\\npr\\u00e9sence de Dieu mais une pr\\u00e9sence qui n\\u2019est pas id\\u00e9ologique seulement mais\\r\\nc\\u2019est physique.<br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">La face de Dieu ne se rencontre pas toujours\\r\\nen public et m\\u00eame quand on est avec les gens il est possible qu\\u2019on ne rencontre\\r\\npas la face de Dieu.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">La face de Dieu on ne la rencontre pas en\\r\\npublic parce que la qu\\u00eate de Dieu est une affaire d\\u2019intimit\\u00e9 o\\u00f9 on sort avec\\r\\ndes secrets que seul soi-m\\u00eame on sait, des secrets qui transforment notre\\r\\nmani\\u00e8re de concevoir les choses.<br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Ceux qui acc\\u00e9daient au saint des saints\\r\\nc\\u2019\\u00e9taient ceux-l\\u00e0 qui rencontraient la face de Dieu. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">La\\r\\nqu\\u00eate de Dieu peut commencer avec beaucoup de gens et plus on avance plus on\\r\\nreste seul plus l\'intimit\\u00e9 grandit; car c\\u2019est une affaire personnelle.<\\/span><\\/b><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Lorsqu\'on est \\u00e0 la recherche de sa face Dieu\\r\\nfinit par devenir un Dieu personnel, un Dieu que l\\u2019on conna\\u00eet personnellement. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Psaumes 91:1-2<\\/span><\\/p><ol><li><span lang=\\"fr\\"><\\/span><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">Celui\\r\\nqui demeure sous l\'abri du Tr\\u00e8s Haut Repose \\u00e0 l\'ombre du Tout Puissant.<\\/span><\\/i><\\/li><li><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">Je\\r\\ndis \\u00e0 l\'\\u00c9ternel: Mon refuge et ma forteresse, Mon Dieu en qui je me confie!<\\/span><\\/i><\\/li><\\/ol>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Celui\\r\\nqui recherche la face de Dieu atteint une dimension o\\u00f9 il a une relation\\r\\npersonnelle avec Dieu.<\\/span><\\/b><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Actes 9:3-6 ; Actes 5:15; Apocalypse 1:10<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Bien aim\\u00e9s, notre Dieu a des causes qui\\r\\ncherchent les effets.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Quand tu viens \\u00e0 Bunda 21 tu sais ce que tu\\r\\nviens chercher, mais chercher Dieu est une affaire d\\u2019intimit\\u00e9. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Les\\r\\ncouvertures spirituelles n\\u2019annulent pas la place de l\\u2019intimit\\u00e9.<br><\\/span><\\/b><span lang=\\"fr\\">L\\u2019intimit\\u00e9 n\\u2019est pas remplac\\u00e9e par la\\r\\ncouverture spirituelle.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Fr\\u00e8res et s\\u0153urs, vous ne pouvez pas faire\\r\\nvotre parcours avec Dieu sans \\u00ab l\\u2019ainsi dit l\\u2019Eternel \\u00bb.<br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Luc 22:31-32, Actes 10<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Toi aussi tu as une mission, tu dois chercher\\r\\nDieu parce que Dieu veut passer par toi, il y a de ces genres de probl\\u00e8mes qui\\r\\nn\\u2019ont que toi comme solution.<br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Vous\\r\\n\\u00eates pauvres si vous n\\u2019avez pas de secrets<span style=\\"mso-spacerun:yes\\">&nbsp;\\r\\n<\\/span>avec Dieu peu importe votre statut.<\\/span><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Si vous n\\u2019avez pas de secret avec Dieu, vous\\r\\n\\u00eates par terre. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Les choses que nous recevons en r\\u00e9alit\\u00e9 sont\\r\\ndes choses que nous rencontrons dans notre qu\\u00eate de l\'\\u00c9ternel.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Quand vous recherchez la face de Dieu il est\\r\\ntellement grand qu\'\\u00e0 chaque fois que vous pensez \\u00eatre arriv\\u00e9 il y a une autre\\r\\ndimension de Lui et dans votre qu\\u00eate il se peut que vous passiez \\u00e0 c\\u00f4t\\u00e9 de\\r\\nbeaucoup de choses; les dons de proph\\u00e9ties, etc.<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Les\\r\\ndons de proph\\u00e9tie et autres sont des choses que nous ne devons pas chercher,\\r\\nnous les rencontrons en route puisque c\\u2019est Dieu qui est notre qu\\u00eate.<\\/span><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Fr\\u00e8res et s\\u0153urs n\\u2019allez pas vers de choses qui\\r\\nsont cens\\u00e9es venir vers vous.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Exode 34:5-9; 1 Corinthiens 7:5 ; 2\\r\\ncorinthiens 12:1-4; Actes 21:10-13<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Nous sommes dans une g\\u00e9n\\u00e9ration o\\u00f9 nous aimons\\r\\nles manifestations de Dieu et nous n\\u2019aimons pas la pr\\u00e9sence de Dieu.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">Quelque chose se passe lorsqu\\u2019on rencontre\\r\\nDieu et notre c\\u0153ur est marqu\\u00e9 \\u00e0 jamais, on arrive plus \\u00e0 s\\u2019en d\\u00e9barrasser. <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><span lang=\\"fr\\">Fr\\u00e8res et s\\u0153urs, les plus forts sont ceux-l\\u00e0 qui restent\\r\\nlongtemps dans la pr\\u00e9sence de Dieu parce que c\\u2019est dans la pr\\u00e9sence de Dieu que\\r\\nnous rayonnons.<\\/span><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">En parlant de la pr\\u00e9sence de Dieu, j\\u2019aimerai\\r\\nparler des quatre \\u00eatres vivants. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Ces quatre \\u00eatres vivants, ce qui les rend\\r\\nsp\\u00e9ciaux, c\'est le fait qu\\u2019ils restent longtemps dans la pr\\u00e9sence de Dieu. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Bien aim\\u00e9, Si tu restes longtemps dans la\\r\\npr\\u00e9sence de Dieu, on en verra les traces. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Quand vous \\u00eates quelqu\\u2019un qui reste longtemps\\r\\ndans la pr\\u00e9sence de Dieu, l\\u2019ob\\u00e9issance n\\u2019est pas un probl\\u00e8me pour toi. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Lorsqu\\u2019on reste longtemps dans la pr\\u00e9sence de\\r\\nDieu, M\\u00eame la simple voix de l\\u2019Esprit nous pousse et nous rend capable de faire\\r\\nla volont\\u00e9 de Dieu. <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><span lang=\\"fr\\">Quand tu restes longtemps dans la pr\\u00e9sence de Dieu,\\r\\nL\\u2019ob\\u00e9issance devient l\\u2019expression naturelle de ta vie, ce n\'est plus un\\r\\nfardeau.<\\/span><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Josu\\u00e9 6, Josu\\u00e9 \\u00e9tait proche de la pr\\u00e9sence de\\r\\nDieu; plus il \\u00e9tait proche de la pr\\u00e9sence de Dieu et quand il parlait le soleil\\r\\npeut s\\u2019arr\\u00eater. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Il y a des situations pour lesquelles tu dois\\r\\nn\\u00e9gocier comme les hommes d\\u2019intimit\\u00e9 avec Dieu, \\u00e0 l\\u2019exemple de Eli. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Eli est rest\\u00e9 longtemps dans la pr\\u00e9sence de\\r\\nDieu \\u00e0 genoux. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">Les\\r\\nhommes qui restent \\u00e0 genoux, bougent le ciel.<\\/span><\\/i><span lang=\\"fr\\"> <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Lorsqu\'une certaine saison est sur le point\\r\\nd\\u2019arriver, Dieu est entrain de placer en toi des capacit\\u00e9s qui vous permettront\\r\\nde t\\u00e9l\\u00e9charger les choses. <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Bien aim\\u00e9, cherches la face de Dieu, si tu\\r\\nn\\u2019es pas \\u00e0 la qu\\u00eate de Dieu il<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>y aura\\r\\ndes choses qui se passeront dans ta famille que tu ne sauras pas en mesure\\r\\nd\\u2019apporter de solution parce que tu n\\u2019as aucune connexion avec Celui qui peut\\r\\ntout. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Ne\\r\\ntronquez pas tout ce que Dieu vous demande de faire parce que vous serez\\r\\nentrain de perdre la capacit\\u00e9 de rester dans la pr\\u00e9sence de Dieu.<\\/span><\\/b><span lang=\\"fr\\"> <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Que Dieu vous b\\u00e9nisse !<\\/span><\\/p>","en":null}', NULL, NULL, 1, 'cherchez-continuellement-sa-face-9', 1, '2023-11-08 19:31:41', '2024-11-14 19:04:29', NULL, '2023-11-07 08:00:00', NULL, NULL),
	(14, '{"fr":"Cherchez continuellement sa face. (5)","en":null}', 3, 'https://www.youtube.com/watch?v=5TWjMd81XWw', '{"fr":"posts\\/1699476496.B21-Vign-J7.png","en":""}', '{"fr":"<p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" id=\\"docs-internal-guid-d4d6f7c2-7fff-3103-7fdc-ca531c8149e8\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Sous-Th\\u00e8me : <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Que le ciel s\\u2019ouvre sur toi.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Orateur : Docteur Athoms Mbuma<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">R\\u00e9f\\u00e9rence Biblique: Jean 1 42-47<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Ce matin mon th\\u00e8me, c\\u2019est comme une pri\\u00e8re, une d\\u00e9claration. Dans Jean 1 : 42-48, nous sommes en face de Christ qui va faire mention de ce concept, <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">\\u201c que le Ciel s\\u2019ouvre\\u201d.<\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"> Nous donnerons cinq choses sur la fa\\u00e7on de red\\u00e9finir cette pri\\u00e8re pour que le ciel s\\u2019ouvre.&nbsp;<\\/span><\\/p><ul style=\\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\\"><li dir=\\"ltr\\" style=\\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dans le Juda\\u00efsme, il existe Trois ciels : <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><\\/p><\\/li><\\/ul><ul style=\\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\\"><li dir=\\"ltr\\" style=\\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">&nbsp;Le ciel g\\u00e9ographique;&nbsp;<\\/span><\\/p><\\/li><\\/ul><ul style=\\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\\"><li dir=\\"ltr\\" style=\\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le ciel des anges ;<\\/span><\\/p><\\/li><li dir=\\"ltr\\" style=\\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le ciel o\\u00f9 Dieu habite&nbsp;<\\/span><\\/p><\\/li><\\/ul><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le ciel ouvert est un concept biblique, et non pas une spiritualit\\u00e9 qui fait preuve de trop de foi. Dieu veut&nbsp; ouvrir le ciel&nbsp; sur nous.&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dans les actes des ap\\u00f4tres ont racont\\u00e9 l\\u2019histoire de la vision que Pierre \\u00e0 eu.&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le concept de ciel ouvert vient plusieurs fois dans la bible.&nbsp;<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Qui ouvre le Ciel, dans tous les diff\\u00e9rents versets on parle de l\\u2019ouverture et de la fermeture du ciel.&nbsp;<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:underline;-webkit-text-decoration-skip:none;text-decoration-skip-ink:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">1er Dieu ouvre le ciel<\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:underline;-webkit-text-decoration-skip:none;text-decoration-skip-ink:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Il ouvre le ciel l\\u00e0 o\\u00f9 il habite et les rend disponibles.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le psaume dit :&nbsp; \\u201cSi tu d\\u00e9chirais les yeux \\u201c vient agressivement car je suis au combat. <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Ma pri\\u00e8re est Que Dieu d\\u00e9chire les cieux en votre faveur<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:underline;-webkit-text-decoration-skip:none;text-decoration-skip-ink:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">2e L\\u2019homme ouvre le ciel<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le ciel est comme une porte \\u00e0 ouverture d\\u2019une poign\\u00e9e dans les deux sens. Elie appara\\u00eet et comment il fermait le ciel pour que la pluie ne tombe Jacques 5 r\\u00e9p\\u00e8te cela dans un contexte de pri\\u00e8re. Elie est un homme de m\\u00eame nature que nous. Dieu donne aux hommes sur la terre de pouvoir aussi ouvrir ou fermer le ciel. Il donne les cl\\u00e9s, Christ dit je vous ai donn\\u00e9 les cl\\u00e9s du ciel ce que vous fermez ou ouvrez sur terre sera li\\u00e9 au ciel.<\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Vous ne vous rendez pas compte que si cela se passe sur terre, au ciel aussi. A quoi servent les cl\\u00e9s, quand tu frappes, quand tu demandes que tu sois capable de rechercher et d\'ouvrir de toit m\\u00eame. <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:underline;-webkit-text-decoration-skip:none;text-decoration-skip-ink:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Pourquoi le ciel s\'ouvre-t-il ?<\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"> <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><br><\\/span><\\/p><ol style=\\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\\"><li dir=\\"ltr\\" style=\\"list-style-type:decimal;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le ciel s\\u2019ouvre pour la manifestation de la r\\u00e9v\\u00e9lation de Dieu <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">;<\\/span><\\/p><\\/li><\\/ol><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Lors du bapt\\u00eame de J\\u00e9sus, la conversation entre Jean et J\\u00e9sus; puis une voix s\\u2019est faite entendre.&nbsp; <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><br><\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-left: 36pt;text-align: center;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Quand Dieu ouvre le ciel, il aime montrer sa face, une facette de Dieu que tu ne connaissais pas.<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-left: 36pt;text-align: center;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">\\u00c0 chaque fois que Dieu ouvre le ciel c\\u2019est pour que nous puissions vivre une autre facette de lui.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Quand on ouvre une porte en g\\u00e9n\\u00e9ral, on s\\u2019attend \\u00e0 un visage, et quand Dieu ouvre le ciel il veut que tu d\\u00e9couvres un autre visage.&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dieu ouvre le ciel, aime ouvrir le ciel pour se montrer, nous exaucer&nbsp; de mani\\u00e8re spectaculaire.&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dieu aime ouvrir le ciel pour qu\\u2019on puisse t\\u00e9moigner de lui<\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Il ouvre le ciel pour que l\\u2019on sache que nous sommes vraiment \\u00e0 lui. <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Quand nous demandons ici que Dieu ouvre le ciel nous disons que Dieu t\\u00e9moigne que nous sommes \\u00e0 lui.<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-left: 36pt;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Que Dieu fasse quelque chose pour que les hommes disent que toi tu as vraiment un Dieu.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">R\\u00e9v\\u00e8le toi pour que l\\u2019on sache que tu es Dieu, afin que l\\u2019on sache que je suis ton serviteur&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dieu aime ouvrir le ciel pour nous exaucer;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Que les cieux s\\u2019ouvrent sur toi;&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Que les ressources spirituelles&nbsp; entrent en action en ta faveur pour faire fonctionner le plan de Dieu sur toi. On va utiliser quelque chose qui vient de Dieu, ne t\\u2019appuie plus sur les noms des gens, Dieu peut le faire avec les ressources divines.&nbsp;<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">\\u00c0 l\'\\u00e9glise, nous croyons plus en la capacit\\u00e9 des sorciers \\u00e0 faire des actions n\\u00e9gatives physiques mais nous&nbsp; croyons difficilement \\u00e0 l\\u2019effet de nos pri\\u00e8res sur le monde physique. Appuie-toi sur Dieu.<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Ne trouves pas l\\u2019argent, utilises une autre ressource surnaturelle. Les anges travaillent en ta faveur.<\\/span><\\/p><br><ol style=\\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\\" start=\\"2\\"><li dir=\\"ltr\\" style=\\"list-style-type:decimal;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Ta spiritualit\\u00e9 conna\\u00eet une nouvelle exp\\u00e9rience de croissance.<\\/span><\\/p><\\/li><\\/ol><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Pendant ces 21 jours que tu arrives \\u00e0 une dimension o\\u00f9 tu ne pourras plus reculer. Pendant ce programme le pasteur fait de son mieux pour nous connecter \\u00e0 Dieu, 12h NON-STOP de pri\\u00e8res c\\u2019est la premi\\u00e8re fois de ta vie. Nous vivons parfois une&nbsp; vie d\\u2019\\u00e9lastique spirituelle. Mais quand tu \\u00e9tires l\\u2019\\u00e9lastique reste \\u00e0 la m\\u00eame dimension.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Que pendant ces 21 jours que ton maximum devienne ton nouveau minimum de croissance spirituelle. Si \\u00e0 l\'int\\u00e9rieur tu grandis tu es pr\\u00eat \\u00e0 recevoir ce qu\\u2019il n\\u2019a pas pr\\u00e9vu.&nbsp;<\\/span><\\/p><br><ol style=\\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\\" start=\\"3\\"><li dir=\\"ltr\\" style=\\"list-style-type:decimal;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dieu se r\\u00e9v\\u00e8le \\u00e0 toi autrement et puissamment (Actes 10.15).<\\/span><\\/p><\\/li><\\/ol><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dieu voulait le choquer, car il savait que par sa croyance juda\\u00efque il pensait que Dieu est venu pour les juifs. Pierre fut le premier ap\\u00f4tre des pa\\u00efens, Pierre n\\u2019\\u00e9tait pas pr\\u00eat \\u00e0 prier pour ceux qui ne sont pas juifs. Pour le choquer, il lui montre des nourritures qu\\u2019il ne peut pas manger. Il est possible que pendant cette \\u00e9dition de Bunda, tu te demandes si c\' est toujours toi ? Il te rend visite et te demande si c\\u2019est de Dieu. Dieu pr\\u00e9pare Pierre et il ne comprend pas la vision. Des personnes viennent le prendre, on l\\u2019emm\\u00e8ne dans une maison o\\u00f9 il y a plein de romains qui l\'ont appel\\u00e9 pour prier. Dieu fait acceptation de personne pour des personnes qui croient en lui. <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Quand Dieu ouvre le ciel ce n\\u2019est pas pour venir comme d\\u2019habitude. Il va manifester un visage autrement. Apr\\u00e8s ces 21 jours, il y a encore des chapitres \\u00e0 vivre. Le 1er Chapitre d\\u2019un livre ne ressemble pas au second chapitre ni \\u00e0 la suite.<\\/span><\\/p><br><ol style=\\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\\" start=\\"4\\"><li dir=\\"ltr\\" style=\\"list-style-type:decimal;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\" role=\\"presentation\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Un acc\\u00e8s fluide \\u00e0 la volont\\u00e9 te donne la capacit\\u00e9 d\\u2019\\u00eatre pr\\u00e9cis sur la terre.<\\/span><\\/p><\\/li><\\/ol><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Que pendant ces 21 jours tu poses les actes, que tu ne t\\u00e2tonnes pas. Le plan de Dieu fonctionne \\u00e0 l\\u2019int\\u00e9rieur de toi, le juste voit dans son c\\u0153ur des voies toutes trac\\u00e9es. <\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Tu seras au bon endroit, au bon moment. Le plan va fonctionner en toi. Tu sortiras quand il fallait sortir. Tu n\\u2019entreras pas dans un avion qui crash, dans un taxi o\\u00f9 l\\u2019on enl\\u00e8ve les gens, tu ne seras pas un dommage collat\\u00e9ral. Tu seras toujours l\\u00e0 o\\u00f9 la volont\\u00e9 de Dieu se trouve. C\\u2019est maintenant, vas-y.&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;text-align: center;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\"><br><\\/span><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">M\\u00eame si tout est dess\\u00e9ch\\u00e9, il y aura une pluie venue du ciel sur toi, ta famille et tes avoir.<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Que le ciel s\\u2019ouvre sur toi. On ne vous fera pas de mauvaise surprise. Dieu s\\u2019arrangera pour que tu puisses accomplir sa volont\\u00e9.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le ciel est ouvert, m\\u00eame sur ta poche.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Le ciel est ouvert sur moi.<\\/span><\\/p><br><p dir=\\"ltr\\" style=\\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\\"><span style=\\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\\">Dieu nous b\\u00e9nisse ! <\\/span><\\/p>","en":null}', NULL, NULL, 1, 'cherchez-continuellement-sa-face-5', 1, '2023-11-08 19:48:16', '2024-11-14 19:04:29', NULL, '2023-11-05 11:00:00', NULL, NULL),
