  Name=\\"List Table 6 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 6\\"\\/>\\r\\n <\\/w:LatentStyles>\\r\\n<\\/xml><![endif]--><!--[if gte mso 10]>\\r\\n<style>\\r\\n \\/* Style Definitions *\\/\\r\\n table.MsoNormalTable\\r\\n\\t{mso-style-name:\\"Tableau Normal\\";\\r\\n\\tmso-tstyle-rowband-size:0;\\r\\n\\tmso-tstyle-colband-size:0;\\r\\n\\tmso-style-noshow:yes;\\r\\n\\tmso-style-priority:99;\\r\\n\\tmso-style-parent:\\"\\";\\r\\n\\tmso-padding-alt:0cm 5.4pt 0cm 5.4pt;\\r\\n\\tmso-para-margin-top:0cm;\\r\\n\\tmso-para-margin-right:0cm;\\r\\n\\tmso-para-margin-bottom:8.0pt;\\r\\n\\tmso-para-margin-left:0cm;\\r\\n\\tline-height:107%;\\r\\n\\tmso-pagination:widow-orphan;\\r\\n\\tfont-size:11.0pt;\\r\\n\\tfont-family:\\"Calibri\\",sans-serif;\\r\\n\\tmso-ascii-font-family:Calibri;\\r\\n\\tmso-ascii-theme-font:minor-latin;\\r\\n\\tmso-hansi-font-family:Calibri;\\r\\n\\tmso-hansi-theme-font:minor-latin;\\r\\n\\tmso-bidi-font-family:\\"Times New Roman\\";\\r\\n\\tmso-bidi-theme-font:minor-bidi;\\r\\n\\tmso-font-kerning:1.0pt;\\r\\n\\tmso-ligatures:standardcontextual;\\r\\n\\tmso-ansi-language:FR;}\\r\\n<\\/style>\\r\\n<![endif]-->\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b><span lang=\\"FR\\">BUNDA 21 \\u2013 JOUR\\r\\n6 \\u2013 12H DE PRIERES NON-STOP \\/ Samedi 04 Novembre 2023.<\\/span><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Oratrice: Deborah\\r\\nMargaret<span style=\\"mso-spacerun:yes\\"> <\\/span>Passages Bibliques&nbsp;:\\r\\nPsaumes 105&nbsp;:1-4&nbsp;; Jean 8&nbsp;:31&nbsp;; Philippiens 3&nbsp;:10&nbsp;;\\r\\nMatthieu 6&nbsp;:24&nbsp;; 1 rois 18&nbsp;; 2 Rois 3&nbsp;:25<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b><i><span lang=\\"FR\\">Le plus grand\\r\\nbesoin du corps du Christ est celui de conna\\u00eetre Dieu.<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Si l\\u2019on interroge\\r\\nchacun en faisant un micro baladeur, on se rendra vite compte de l\\u2019\\u00e9tat ou la position\\r\\nde la plupart des personnes qui se revendiquent chr\\u00e9tiennes. Nous serons choqu\\u00e9s\\r\\nde r\\u00e9aliser combien est important le nombre d\\u2019hommes et de femmes qui ne croient\\r\\nplus en Dieu. Ces personnes viennent \\u00e0 Dieu pour chercher des solutions \\u00e0 leurs\\r\\nprobl\\u00e8mes. Elles se livrent aux murmures, elles se plaignent \\u00e0 tort et \\u00e0\\r\\ntravers, elles s\\u2019interrogent incessamment au sujet de la solution de Dieu \\u00e0 leurs\\r\\nprobl\\u00e8mes se demandant constamment si Dieu les a oubli\\u00e9es.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b><i><span lang=\\"FR\\">Bien-aim\\u00e9s,\\r\\nIl est plus ais\\u00e9, lorsque l\\u2019on acclame ou que l\\u2019on adore Dieu, de le faire en\\r\\nv\\u00e9rit\\u00e9 et de tout notre c\\u0153ur.<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b><i><span lang=\\"FR\\">Tu\\r\\nne peux pas attendre quelque chose de la personne avec qui tu n\\u2019entretiens\\r\\naucune communion.<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b><i><span lang=\\"FR\\">Ton\\r\\nintimit\\u00e9 avec Dieu est ce qui te pr\\u00e9dispose \\u00e0 la victoire. Sans elle tu es vou\\u00e9\\r\\n\\u00e0 l\\u2019\\u00e9chec. Voil\\u00e0 pourquoi<\\/span><\\/i><\\/b><span lang=\\"FR\\"> <b><i>tu as int\\u00e9r\\u00eat \\u00e0\\r\\ncapitaliser ce programme de Bunda 21 qui a vocation \\u00e0 t\\u2019approcher davantage de\\r\\nDieu<\\/i><\\/b>.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b><u><span lang=\\"FR\\">Chercher\\r\\ncontinuellement sa face pourquoi&nbsp;?<\\/span><\\/u><\\/b><u><span lang=\\"FR\\"><\\/span><\\/u><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Croire en Dieu est\\r\\nune bonne chose, mais cela ne fait pas de nous pour autant des disciples. C\\u2019est\\r\\ndemeurant dans sa pr\\u00e9sence qu\\u2019on le devient. Jean 8&nbsp;:31.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i><span lang=\\"FR\\">Cherchons\\r\\ncontinuellement sa face, parce que c\\u2019est dans cette d\\u00e9marche que nous allons\\r\\ntrouver son appui, le seul capable de nous distinguer.<\\/span><\\/i><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i><span lang=\\"FR\\">Bunda 21 ne\\r\\nsignifie pas que nous venons nous battre avec des coups de poing, mais c\\u2019est un\\r\\ncadre sp\\u00e9cial o\\u00f9 nous venons r\\u00e9pandre nos c\\u0153urs devant Dieu.<\\/span><\\/i><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Philippiens\\r\\n3&nbsp;:10 : N\\u00e9cessit\\u00e9 de connaitre Dieu.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">1cor8&nbsp;:9 (\\u00e0\\r\\nv\\u00e9rifier)<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Pour trouver le\\r\\nSeigneur, l\\u2019attitude de ton c\\u0153ur en est pour beaucoup. Car Dieu ne nous agr\\u00e9e\\r\\nque dans la mesure o\\u00f9 nous L\\u2019aimons de tout notre c\\u0153ur.<span style=\\"color:red\\">\\r\\n<\\/span>Matthieu 22&nbsp;.37<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b><i><span lang=\\"FR\\">De\\r\\nfois les enfants de Dieu tombent dans le pi\\u00e8ge de garder \\u00e0 l\\u2019esprit que p\\u00e9cher\\r\\nc\\u2019est seulement le fait de tomber dans l\\u2019adult\\u00e8re ou dans la fornication.\\r\\nErreur&nbsp;! Retenons que toute attitude susceptible de porter atteinte \\u00e0\\r\\nnotre intimit\\u00e9 avec Dieu, repr\\u00e9sente un p\\u00e9ch\\u00e9, \\u00e0 l\\u2019instar de l\\u2019orgueil.<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><b><i><span lang=\\"FR\\">Entretenir\\r\\nune relation superficielle avec Dieu serait trop injuste de notre part au\\r\\nregard du sacrifice supr\\u00eame qu\\u2019il a accompli en notre faveur \\u00e0 savoir, la mort\\r\\nde J\\u00e9sus la croix. Cela dit, Dieu m\\u00e9rite le meilleur de nous.<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Matthieu 6&nbsp;:24<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Qui est l\\u2019autre\\r\\nma\\u00eetre qu\\u2019\\u00eates-vous en train de servir&nbsp;? sachez que celui-l\\u00e0 vous \\u00e9loigne\\r\\nde Dieu.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b><span lang=\\"FR\\">\\u00ab&nbsp;Ton\\r\\nmiracle peut s\\u2019accomplir en un clin d\\u2019\\u0153il si et seulement si tu fais sa\\r\\nvolont\\u00e9&nbsp;\\u00bb<\\/span><\\/b><span lang=\\"FR\\">. A Abraham Dieu avait donn\\u00e9 une\\r\\npromesse et lui a demand\\u00e9 de quitter la maison de son p\\u00e8re en vue de son\\r\\naccomplissement. En sortant il prend avec lui Lot son neveu. L\\u2019Eternel ne lui\\r\\navait pas recommand\\u00e9 de faire autant. Son neveu a constitu\\u00e9 un obstacle majeur \\u00e0\\r\\nsa marche et dans sa communion avec Dieu. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Bien-aim\\u00e9s, \\u00e0 cette\\r\\nimage, Dieu attend de nous que nous nous s\\u00e9parions de tout ce qui peut \\u00e9corner\\r\\nnotre communion avec Lui. C\\u2019est-\\u00e0-dire tout ce qui peut nous emp\\u00eacher de vivre une\\r\\nintimit\\u00e9 profonde dans sa pr\\u00e9sence.<span style=\\"color:red\\"> <\\/span><b>Nos probl\\u00e8mes\\r\\nsur lesquels nous nous focalisons tant, nous emp\\u00eachent de focaliser la totalit\\u00e9\\r\\nde notre attention sur Dieu.<\\/b><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b><span lang=\\"FR\\">\\u00ab&nbsp;Il faut\\r\\nse s\\u00e9parer de Lot pour recevoir l\\u2019appui dans la pr\\u00e9sence de Dieu.&nbsp;\\u00bb<\\/span><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Apr\\u00e8s s\\u2019\\u00eatre s\\u00e9par\\u00e9\\r\\nde Lot, Dieu a exig\\u00e9 d\\u2019Abraham un sacrifice. Il s\\u2019agit de l\\u2019offrande d\\u2019Isaac,\\r\\nson seul et unique fils selon la volont\\u00e9 de Dieu, celui qu\\u2019il aimait tant.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Dans Gen\\u00e8se chapitre\\r\\n18&nbsp;:1, Dieu avait ouvert \\u00e0 Abraham les yeux de l\\u2019esprit pour voir ses messagers,\\r\\nporteurs de la nouvelle qui a amorc\\u00e9 le d\\u00e9but de l\\u2019accomplissement de la\\r\\npromesse de Dieu dans sa vie. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b><span lang=\\"FR\\">Pour accomplir\\r\\ndes sacrifices pour Dieu, nous devons nous passer de tous raisonnements\\r\\ncharnels car la chair nous pousse \\u00e0 argumenter avec Dieu pour ne pas faire ce\\r\\nqu\\u2019il nous recommande.<\\/span><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Il y a n\\u00e9cessit\\u00e9 de\\r\\nchoisir entre Dieu et le monde&nbsp;: Dans notre vie pratique, il est imp\\u00e9rieux\\r\\nque nous puissions lever des options qui, peut-\\u00eatre feront souffrir notre\\r\\nchair, mais qui en revanche nous emm\\u00e8neront dans une dimension o\\u00f9 <b><i>plaire\\r\\n\\u00e0 Dieu<\\/i><\\/b> devient la priorit\\u00e9 des priorit\\u00e9s. 1 rois 18<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Dieu nous appelle \\u00e0\\r\\nchercher continuellement sa face, mais ce processus ne peut nous \\u00eatre b\\u00e9n\\u00e9fique\\r\\nque si nous demeurons ob\\u00e9issants \\u00e0 sa personne. Le rechercher de tout notre\\r\\nc\\u0153ur nous impose de Le placer \\u00e0 la premi\\u00e8re place dans tous les aspects de\\r\\nnotre vie. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">Concr\\u00e8tement, Cette\\r\\nattitude ne fait pas toujours l\\u2019objet des pr\\u00e9occupations des humains que nous\\r\\nsommes. Mais la bonne nouvelle est que Dieu nous aime tellement qu\\u2019il r\\u00e9serve\\r\\nla voie de la repentance pour nous permettre de se mettre en r\\u00e8gle avec Lui. La\\r\\nrepentance \\u00e9tant la principale cl\\u00e9 pour avoir acc\\u00e8s \\u00e0 sa pr\\u00e9sence.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"FR\\">2 Rois 3&nbsp;:25<br><\\/span><b><span lang=\\"FR\\">D\\u00e9claration<\\/span><\\/b><span lang=\\"FR\\">&nbsp;: Cette \\u00e9dition de BUNDA 21 n\\u2019est pas comme d\\u2019habitude. Elle est\\r\\nvenue pour sortir les hommes du tombeau.<\\/span><\\/p>","en":null}', NULL, NULL, 1, 'cherchez-continuellement-sa-face', 1, '2023-11-08 21:03:04', '2024-11-14 19:04:29', NULL, '2023-11-04 16:00:00', NULL, NULL),
	(19, '{"fr":"La vision et le sacrifice : deux \\u00e9l\\u00e9ments pr\\u00e9alables incontournables.","en":null}', 3, 'https://www.youtube.com/watch?v=5DV8rCbVXoo', '{"fr":"posts\\/1708536624.Vign-Dim-18-02-2024.jpg","en":""}', '{"fr":"<span id=\\"docs-internal-guid-20b23622-7fff-3fe4-bcc8-c76687bc3504\\"><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Th\\u00e8me : La vision et le sacrifice&nbsp;: deux \\u00e9l\\u00e9ments pr\\u00e9alables incontournables.&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Sous-Th\\u00e8me : \\u00c0 l\'image de N\\u00e9h\\u00e9mie (2)&nbsp;<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">R\\u00e9f\\u00e9rences Bibliques : N\\u00e9h\\u00e9mie 1.1-6, 2.9-12.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Dans ce moment particulier, nous nous plongeons dans l\'histoire de N\\u00e9h\\u00e9mie, un Juif \\u00e9loign\\u00e9 de sa nation par la d\\u00e9portation, mais dont le c\\u0153ur reste attach\\u00e9 \\u00e0 son peuple m\\u00eame en terre \\u00e9trang\\u00e8re.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Le livre de N\\u00e9h\\u00e9mie relate son r\\u00f4le crucial dans la restauration de leur patrie. Il repr\\u00e9sente le peuple que Dieu cherche \\u00e0 relever et sauver, d\\u00e9passant ainsi les limites individuelles. C\'est une vision que Dieu a implant\\u00e9e en lui.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">La vision est comme une esquisse avant l\'ex\\u00e9cution ; c\'est la perception de soi en relation avec son parcours de vie ; c\'est la d\\u00e9finition de ce que l\'on aspire \\u00e0 devenir et \\u00e0 accomplir.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Nous pouvons la r\\u00e9sumer en prenant N\\u00e9h\\u00e9mie comme exemple, une image donn\\u00e9e divinement de ce qui pourrait \\u00eatre, de ce qui devrait \\u00eatre.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">N\\u00e9h\\u00e9mie a une vision pour lui et sa nation.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Il ne se limite pas \\u00e0 son r\\u00f4le d\'\\u00e9chanson du roi ; il se voit au-del\\u00e0.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Beaucoup, contrairement \\u00e0 N\\u00e9h\\u00e9mie, emp\\u00eachent la r\\u00e9ception de la vision que Dieu a pour eux.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Qu\'ils vivent dans le bonheur ou la tristesse au quotidien, les deux peuvent obscurcir ce que Dieu a pr\\u00e9vu de diff\\u00e9rent pour eux.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">La plupart pensent que la limite de leur vision est la limite du monde et que Dieu n\'est qu\'un \\u00e9l\\u00e9ment de leur contexte.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Ce matin, une question nous est pos\\u00e9e : laissez-vous votre pass\\u00e9, votre pr\\u00e9sent vous limiter ? Vos activit\\u00e9s, votre pays, votre environnement, vos contraintes et d\\u00e9fis vous limitent-ils ?<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">\\u00cates-vous aveugl\\u00e9s ? Parfois, la vision ne se forme pas, ne se re\\u00e7oit pas.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Quelques contextes qui \\u00e9touffent : Contexte 1. Les tentatives \\u00e9chou\\u00e9es ou non r\\u00e9alis\\u00e9es.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Parfois, la vision n\'\\u00e9merge pas \\u00e0 cause des \\u00e9checs.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Les \\u00e9checs se manifestent de deux mani\\u00e8res :&nbsp;<\\/span><\\/p><ol style=\\"margin-bottom: 0px; padding-inline-start: 48px;\\"><li dir=\\"ltr\\" style=\\"list-style-type: lower-alpha; font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space: pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\" role=\\"presentation\\"><span style=\\"font-size: 11pt; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; text-wrap: wrap;\\">En fonction de l\\u2019action.<\\/span><\\/p><\\/li><\\/ol><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Malgr\\u00e9 les efforts d\\u00e9ploy\\u00e9s, les projets restent lettre morte, les rencontres n\'aboutissent pas.&nbsp;<\\/span><\\/p><ol style=\\"margin-bottom: 0px; padding-inline-start: 48px;\\" start=\\"2\\"><li dir=\\"ltr\\" style=\\"list-style-type: lower-alpha; font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space: pre;\\" aria-level=\\"1\\"><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\" role=\\"presentation\\"><span style=\\"font-size: 11pt; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; text-wrap: wrap;\\">En fonction de l\'acteur.<\\/span><\\/p><\\/li><\\/ol><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">L\'\\u00e9chec d\'une autre personne peut impacter directement notre propre vision.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Dans la vie, nous avons tendance \\u00e0 nous r\\u00e9f\\u00e9rer \\u00e0 des exp\\u00e9riences pass\\u00e9es, positives ou n\\u00e9gatives, transmettant ainsi des h\\u00e9ritages, m\\u00eame ceux de nos ennemis. Cependant, ne soyons pas des victimes des rumeurs ou des exp\\u00e9riences n\\u00e9gatives des autres.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Nombres 13.1-3, 22, 26-, Deux r\\u00e9actions : Caleb voit la victoire, tandis que d\'autres se voient d\\u00e9j\\u00e0 vaincus. (Nombres 14.1-3)<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Pour certains, un \\u00e9chec projet\\u00e9 les plonge dans le d\\u00e9sespoir. Certains adoptent les \\u00e9checs pr\\u00e9dits par d\'autres comme leur propre destin\\u00e9e, arr\\u00eatant ainsi leur avancement.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Que ce que l\'on nous dit ne contredise pas la v\\u00e9rit\\u00e9 de Dieu sur notre vie.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">Autour de nous, il y a des Calebs. Prions pour le discernement afin de reconna\\u00eetre les bonnes conversations qui nous encouragent \\u00e0 suivre la vision de Dieu.<\\/span><\\/p><p dir=\\"ltr\\" style=\\"line-height:1.295;margin-top:0pt;margin-bottom:8pt;\\"><span style=\\"font-size: 11pt; font-family: Calibri, sans-serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;\\">1 Samuel 17. Ne laissons personne \\u00e9touffer la vision que Dieu a plac\\u00e9e dans nos c\\u0153urs.<\\/span><\\/p><\\/span>","en":null}', NULL, NULL, NULL, 'la-vision-et-le-sacrifice-deux-elements-prealables-incontournables', 1, '2024-02-21 16:30:24', '2024-11-14 19:04:29', NULL, '2024-02-18 10:00:00', NULL, 4),
	(20, '{"fr":"LA vision et le sacrifice, deux pr\\u00e9alables incontournables","en":null}', 3, 'https://www.youtube.com/watch?v=vITqEAr9N88', '{"fr":"posts\\/1708884580.Vign-Dim-24-02-2024.jpg","en":""}', '{"fr":"<p><span lang=\\"FR\\" style=\\"font-size: 11pt; line-height: 15.6933px; font-family: Calibri, sans-serif;\\">Th\\u00e8me&nbsp;: LA vision et le sacrifice, deux pr\\u00e9alables incontournables<br>Textes de base&nbsp;: Lamentations 3&nbsp;: 18 \\u2013 25<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Quand on parle de la jeunesse c\\u2019est un \\u00e9tat d\\u2019esprit, c\\u2019est une mentalit\\u00e9. Ce message a pour but d\\u2019avoir des r\\u00eaves \\u00e0 poursuivre. Nous ne sommes pas oblig\\u00e9s de subir l\\u2019avenir, de subir des circonstances, nous ne sommes pas oblig\\u00e9s de nous arr\\u00eater, nous avons la gr\\u00e2ce de l\\u2019influencer.<br>Avec Dieu, nous devons viser toujours grand, sortir d\\u2019une mentalit\\u00e9 basse de la m\\u00e9diocrit\\u00e9, il faut que nous puissions nous \\u00e9tendre dans nos aspirations, nous devons avoir des visions audacieuses.<br><br>Deux principes \\u00e0 retenir&nbsp;:<o:p><\\/o:p><\\/span><\\/p><ul><li style=\\"margin-left: 18pt;\\"><span lang=\\"FR\\">1ere principe&nbsp;: tout ce qui est grand a un jour commenc\\u00e9 petit&nbsp;; ne pas m\\u00e9priser les d\\u00e9buts timides et\\/ou faible.<br>Accepte les faiblesse du d\\u00e9but, Dieu sait o\\u00f9 il te conduit<\\/span><\\/li><li style=\\"margin-left: 18pt;\\">Les ambitions connaissent les adversit\\u00e9s<span style=\\"font-family: Calibri, sans-serif; font-size: 11pt;\\">&nbsp;<\\/span><\\/li><\\/ul><p class=\\"MsoNormal\\"><u><span lang=\\"FR\\">2<sup style=\\"font-size: 10.5px;\\">e<\\/sup>&nbsp;Cat\\u00e9gories<\\/span><\\/u><span lang=\\"FR\\">&nbsp;: &nbsp;Les personnes en \\u00e2ge avanc\\u00e9es<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">La vieillesse n\\u2019est pas une question biologique, c\\u2019est une mentalit\\u00e9, c\\u2019est un \\u00e9tat d\\u2019esprit. Il y a des gens qui sont vieux mentalement mais jeune de corps, qui vivent comme un vieillard alors qu\\u2019ils sont encore jeune. D\\u2019autres avanc\\u00e9 en \\u00e2ge mais ils sont encore vigoureux.<o:p><\\/o:p><\\/span><\\/p><p style=\\"margin-left: 18pt;\\"><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Les personnes avanc\\u00e9es en \\u00e2ge tombent dans certains pi\\u00e8ges, ils pensent que le temps est d\\u00e9j\\u00e0 pass\\u00e9 que l\\u2019on a manqu\\u00e9 un virage et que r\\u00e9ussir n\\u2019est plus possible pour eux.<br>Quand on est avanc\\u00e9 en \\u00e2ge si on ne fait pas attention, on devient aigri. Tu regardes d\\u2019un regard d\\u00e9daigneur ceux qui sont encore jeunes.<br>Souvent cette cat\\u00e9gorie de personne pense qu\\u2019ils sont pass\\u00e9 \\u00e0 cot\\u00e9 de chose, ils ont des regrets, plusieurs deviennent des frustr\\u00e9s, ils ont rat\\u00e9 quelque chose. Ils deviennent jaloux car ils n\\u2019ont pas re\\u00e7u ce qu\\u2019il voulait avoir. On a l\\u2019impression qu\\u2019on a rat\\u00e9 quelque chose. Tu te dis que tu aurais pu mieux faire.&nbsp;<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\" style=\\"font-size: 10.5pt; line-height: 14.98px; font-family: Arial, sans-serif; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\\"><span style=\\"font-weight: bolder;\\">Bien aim\\u00e9s, ce que nous sommes aujourd\\u2019hui n\\u2019est que le r\\u00e9sultat de la somme des exp\\u00e9riences que nous avons v\\u00e9cues au sein de&nbsp; l\\u2019environnement familial hier.<\\/span><\\/span><\\/p><p class=\\"MsoNormal\\"><span style=\\"font-family: Arial, sans-serif; font-size: 10.5pt;\\"><span style=\\"font-weight: bolder;\\">Si tu n\\u2019as pas une bonne vision de ta propre personne tu n\\u2019auras pas de bonne vision pour ton futur.&nbsp;<\\/span><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Tu regardes tes enfants, tu te dis que tu es pass\\u00e9 \\u00e0 c\\u00f4t\\u00e9 de quelque chose, tu aurais pu passer plus de temps avec la famille. J\\u2019aurais pu semer en eux des choses essentielles, j\\u2019aurais pu les orienter diff\\u00e9remment. Tant que tu le peux c\\u2019est le moment de les orienter pour faire des hommes et femmes dont tu seras fiers demain.<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><span style=\\"font-weight: bolder;\\">Alors que tu as encore des enfants au bas \\u00e2ge c\\u2019est le moment de les propulser.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Si tu ne le fais pas, si tu tombes dans la distraction, trop concentr\\u00e9 au travail, dans le minist\\u00e8re, ou autre activit\\u00e9 s\\u00e9culi\\u00e8re tu risques de passer \\u00e0 c\\u00f4t\\u00e9 de l\\u2019\\u00e9ducation de tes enfants. Pendant que tu es occup\\u00e9 et focus \\u00e0 d\\u2019autres choses c\\u2019est la rue, les r\\u00e9seaux sociaux qui risquent de prendre le dessus.<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Beaucoup sont trop occup\\u00e9s, les enfants ont besoin de rep\\u00e8re(parents), un mod\\u00e8le qu\\u2019ils doivent suivre pour s\\u2019orienter.<br>Tu n\\u2019es jamais pr\\u00e9sent, ils ont un p\\u00e8re et une m\\u00e8re, mais les parents ne sont jamais l\\u00e0. Les enfants doivent pouvoir se confier sur leur changement physiologique, sur leur sentiment, et si personne n\\u2019est l\\u00e0 ils se tournent vers la rue, ou actuellement vers internet et livr\\u00e9 au diable.<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Il n\\u2019y aura jamais de parents adjoints ou suppl\\u00e9ants, tu es la seule\\/ le seul qu\\u2019ils ont, donnent leur de ton temps. Les enfants que Dieu a plac\\u00e9 entre nos mais sont des joyaux, ils sont comme des fl\\u00e8ches tel un chasseur et nous avons la responsabilit\\u00e9 de les forger et de les lancer.<br>Le travail que tu as peut finir un jour et tu seras remplac\\u00e9. Personne n\\u2019est indispensable pour le business, le boulot, le minist\\u00e8re.&nbsp;<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align: center;\\"><span style=\\"font-weight: bolder;\\">Tu n\\u2019es pas indispensable pour les affaires mais tu es indispensable pour l\\u2019\\u00e9ducation de tes enfants.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Beaucoup de parents prennent ce que Dieu a mis entre leur main pour les gaspiller dans des futilit\\u00e9s.<br>Les hommes mari\\u00e9s qui courent apr\\u00e8s d\\u2019autres femmes, le jour o\\u00f9 tu n\\u2019as plus rien, elles partiront.<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align: center;\\"><span style=\\"font-weight: bolder;\\">Sois sage ! Ce que Dieu te donne aujourd\\u2019hui c\\u2019est pour la destin\\u00e9e de ton foyer, de tes enfants ne le dilapide pas, demain tu auras des comptes \\u00e0 rendre.&nbsp;<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Gloire \\u00e0 Dieu, avec Dieu il n\\u2019est jamais trop tard. M\\u00eame si l\\u2019\\u00e2ge est avanc\\u00e9<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><\\/p><p class=\\"MsoNormal\\"><span style=\\"font-weight: bolder;\\"><i>Lamentations 3&nbsp;: 18 -20<br><\\/i><\\/span><span lang=\\"FR\\">J\\u00e9r\\u00e9mie a &nbsp;comme l\\u2019impression qu\\u2019on est tomb\\u00e9 dans des erreurs irr\\u00e9versibles. Il d\\u00e9cide de tourner le regard l\\u00e0 o\\u00f9 il va trouver de l\\u2019esp\\u00e9rance.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align: center;\\"><span lang=\\"FR\\"><span style=\\"font-weight: bolder;\\">Mon ami.e m\\u00eame quand tu penses que c\\u2019est fini, avec Dieu ce n\\u2019est jamais fini. Ne laisse pas ta vision mourir ; avec Dieu tout encore possible .&nbsp;<o:p><\\/o:p><\\/span><\\/span><\\/p><p class=\\"MsoNormal\\"><i>Lamentations 3&nbsp;: 21 -23<\\/i><\\/p><p class=\\"MsoNormal\\"><i style=\\"font-size: 0.875rem;\\">Il d\\u00e9cide de regarder vers l\\u2019Eternel m\\u00eame si j\\u2019ai rat\\u00e9 hier les bont\\u00e9s de l\\u2019\\u00e9ternel ne sont pas \\u00e9puis\\u00e9es&nbsp;<\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align: center;\\"><span style=\\"font-weight: bolder;\\">Le Dieu que tu sers est vivant ; tu es pass\\u00e9 \\u00e0 c\\u00f4t\\u00e9 des certaines choses mais l\\u2019Eternel est sur son tr\\u00f4ne, Avec Dieu il n\\u2019est jamais trop tard&nbsp;<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align: center;\\"><span style=\\"font-weight: bolder;\\">Mon ami, le temps n\\u2019est pas au regret, les bont\\u00e9s de l\\u2019Eternel sont encore disponibles, avec Dieu il n\\u2019est jamais trop tard&nbsp;<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align: center;\\"><span style=\\"font-weight: bolder;\\">Ne sombres pas dans le d\\u00e9sespoir, nous avons un Dieu dans le ciel sache qu\\u2019il renouvelle ses bont\\u00e9s et ses compassions, il n\\u2019est pas encore trop tard.&nbsp;<\\/span><\\/p><div><p class=\\"MsoNormal\\"><span style=\\"font-weight: bolder;\\">Avec Dieu il n\\u2019est jamais trop tard<\\/span><\\/p><p class=\\"MsoNormal\\"><i style=\\"font-size: 0.875rem;\\">Eccl\\u00e9siastes 9&nbsp;:4<\\/i><\\/p><p class=\\"MsoNormal\\"><span style=\\"font-size: 0.875rem;\\">Tant que nous sommes toujours vivants&nbsp;;<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">M\\u00eame si tu es avanc\\u00e9 en \\u00e2ge ce n\\u2019est pas encore fini, ce n\\u2019est pas encore la fin de ta vie, il y a encore de l\\u2019esp\\u00e9rance avec Dieu.<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Notre Dieu est le Dieu du renouvellement. Dieu n\\u2019est pas impressionn\\u00e9 par le vide de ta vie<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\"><i>Habacuc 2&nbsp;: 3<br><\\/i>Ce que sa bouche d\\u00e9clare s\\u2019accomplit, m\\u00eame si tu as l\\u2019impression que tu a perdu des opportunit\\u00e9s.<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\"><i>Jo\\u00ebl 2&nbsp;: 25<o:p><\\/o:p><\\/i><\\/span><\\/p><p class=\\"MsoNormal\\"><i>Cette ann\\u00e9e est une ann\\u00e9e de restauration,<br>c\\u2019est le Dieu du \\u00ab&nbsp;re&nbsp;\\u00bb, restauration, reconstitution, rel\\u00e8vement, r\\u00e9tablissement, recommencement, \\u2026<br>Je ne suis pas encore K.O, j\\u2019ai encore du souffle je ne mourrai pas ni aujourd\\u2019hui ni demain, ce lui qui a fait la promesse est Fid\\u00e8le.<o:p><\\/o:p><\\/i><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">L\\u2019\\u0153uvre de l\\u2019Eternel commence maintenant. M\\u00eame si tu ne veux pas croire, cela ne viendra pas de toi.<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Caleb avanc\\u00e9 en \\u00e2ge croyait en la promesse, il croyait en Dieu et en lui m\\u00eale Josu\\u00e9 14&nbsp;: 11&nbsp;; malgr\\u00e9 sa vieillesse il a autant de force qu\\u2019il n\\u2019en avait encore . Je n\\u2019abandonnerai pas. Mon \\u00e2me le temps de d\\u00e9sesp\\u00e9r\\u00e9 est termin\\u00e9. L\\u2019Eternel vit encore. Sans avoir vu l\\u2019accomplissement de la parole.<br><o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><u><span lang=\\"FR\\">D\\u00e9clarons<\\/span><\\/u><span lang=\\"FR\\">&nbsp;:&nbsp;<span style=\\"font-weight: bolder;\\">Ce Matin je refuse le d\\u00e9couragement, l\\u2019amertume car ma course n\\u2019est pas encore finie, je verrai de mes yeux la r\\u00e9alisation de la promesse.<\\/span><o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Mon R\\u00e9dempteur est vivant il se l\\u00e8vera le dernier,<br>Je refuse de regarder aux \\u00e9v\\u00e8nement, aux circonstances, ce que je sais c\\u2019est que mon r\\u00e9dempteur se l\\u00e8vera le dernier.<o:p><\\/o:p><\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"FR\\">Que Dieu se l\\u00e8ve et intervienne dans ma situation&nbsp;!&nbsp;<\\/span><\\/p><\\/div>","en":null}', NULL, NULL, NULL, 'la-vision-et-le-sacrifice-deux-prealables-incontournables', 1, '2024-02-25 17:09:40', '2024-11-14 19:04:29', NULL, '2024-02-25 10:00:00', NULL, 1),
	(23, '{"fr":"1er SEMINAIRE | JOUR 1 | Lundi15 Avril 2024","en":null}', 3, 'https://www.youtube.com/watch?v=MQOajCM_8K8', '{"fr":"posts\\/1713500300.SEM-BIBL-VignYtb-J1.jpg","en":""}', '{"fr":"<!--[if gte mso 9]><xml>\\r\\n <o:OfficeDocumentSettings>\\r\\n  <o:AllowPNG\\/>\\r\\n <\\/o:OfficeDocumentSettings>\\r\\n<\\/xml><![endif]--><!--[if gte mso 9]><xml>\\r\\n <w:WordDocument>\\r\\n  <w:View>Normal<\\/w:View>\\r\\n  <w:Zoom>0<\\/w:Zoom>\\r\\n  <w:TrackMoves\\/>\\r\\n  <w:TrackFormatting\\/>\\r\\n  <w:PunctuationKerning\\/>\\r\\n  <w:ValidateAgainstSchemas\\/>\\r\\n  <w:SaveIfXMLInvalid>false<\\/w:SaveIfXMLInvalid>\\r\\n  <w:IgnoreMixedContent>false<\\/w:IgnoreMixedContent>\\r\\n  <w:AlwaysShowPlaceholderText>false<\\/w:AlwaysShowPlaceholderText>\\r\\n  <w:DoNotPromoteQF\\/>\\r\\n  <w:LidThemeOther>FR<\\/w:LidThemeOther>\\r\\n  <w:LidThemeAsian>X-NONE<\\/w:LidThemeAsian>\\r\\n  <w:LidThemeComplexScript>X-NONE<\\/w:LidThemeComplexScript>\\r\\n  <w:Compatibility>\\r\\n   <w:BreakWrappedTables\\/>\\r\\n   <w:SnapToGridInCell\\/>\\r\\n   <w:WrapTextWithPunct\\/>\\r\\n   <w:UseAsianBreakRules\\/>\\r\\n   <w:DontGrowAutofit\\/>\\r\\n   <w:SplitPgBreakAndParaMark\\/>\\r\\n   <w:EnableOpenTypeKerning\\/>\\r\\n   <w:DontFlipMirrorIndents\\/>\\r\\n   <w:OverrideTableStyleHps\\/>\\r\\n  <\\/w:Compatibility>\\r\\n  <m:mathPr>\\r\\n   <m:mathFont m:val=\\"Cambria Math\\"\\/>\\r\\n   <m:brkBin m:val=\\"before\\"\\/>\\r\\n   <m:brkBinSub m:val=\\"&#45;-\\"\\/>\\r\\n   <m:smallFrac m:val=\\"off\\"\\/>\\r\\n   <m:dispDef\\/>\\r\\n   <m:lMargin m:val=\\"0\\"\\/>\\r\\n   <m:rMargin m:val=\\"0\\"\\/>\\r\\n   <m:defJc m:val=\\"centerGroup\\"\\/>\\r\\n   <m:wrapIndent m:val=\\"1440\\"\\/>\\r\\n   <m:intLim m:val=\\"subSup\\"\\/>\\r\\n   <m:naryLim m:val=\\"undOvr\\"\\/>\\r\\n  <\\/m:mathPr><\\/w:WordDocument>\\r\\n<\\/xml><![endif]--><!--[if gte mso 9]><xml>\\r\\n <w:LatentStyles DefLockedState=\\"false\\" DefUnhideWhenUsed=\\"false\\"\\r\\n  DefSemiHidden=\\"false\\" DefQFormat=\\"fal