   Name=\\"List Table 6 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 6\\"\\/>\\r\\n <\\/w:LatentStyles>\\r\\n<\\/xml><![endif]--><!--[if gte mso 10]>\\r\\n<style>\\r\\n \\/* Style Definitions *\\/\\r\\n table.MsoNormalTable\\r\\n\\t{mso-style-name:\\"Tableau Normal\\";\\r\\n\\tmso-tstyle-rowband-size:0;\\r\\n\\tmso-tstyle-colband-size:0;\\r\\n\\tmso-style-noshow:yes;\\r\\n\\tmso-style-priority:99;\\r\\n\\tmso-style-parent:\\"\\";\\r\\n\\tmso-padding-alt:0cm 5.4pt 0cm 5.4pt;\\r\\n\\tmso-para-margin-top:0cm;\\r\\n\\tmso-para-margin-right:0cm;\\r\\n\\tmso-para-margin-bottom:8.0pt;\\r\\n\\tmso-para-margin-left:0cm;\\r\\n\\tline-height:107%;\\r\\n\\tmso-pagination:widow-orphan;\\r\\n\\tfont-size:11.0pt;\\r\\n\\tfont-family:\\"Calibri\\",sans-serif;\\r\\n\\tmso-ascii-font-family:Calibri;\\r\\n\\tmso-ascii-theme-font:minor-latin;\\r\\n\\tmso-hansi-font-family:Calibri;\\r\\n\\tmso-hansi-theme-font:minor-latin;\\r\\n\\tmso-bidi-font-family:\\"Times New Roman\\";\\r\\n\\tmso-bidi-theme-font:minor-bidi;\\r\\n\\tmso-font-kerning:1.0pt;\\r\\n\\tmso-ligatures:standardcontextual;\\r\\n\\tmso-ansi-language:FR;}\\r\\n<\\/style>\\r\\n<![endif]-->\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><u><span lang=\\"fr\\" style=\\"mso-bidi-font-weight:bold\\">Passages Bibliques<\\/span><\\/u><span lang=\\"fr\\" style=\\"mso-bidi-font-weight:bold\\">&nbsp;: Exodes 25&nbsp;:10-22<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><u><span lang=\\"fr\\">Buts de l\\u2019enseignement.<\\/span><\\/u>\\r\\n\\r\\n<\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><u><span lang=\\"fr\\"><span style=\\"text-decoration:none\\">&nbsp;<\\/span><\\/span><\\/u><span lang=\\"fr\\">Pourquoi\\r\\nle fardeau de cet enseignement&nbsp;?<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;N\\u00e9cessit\\u00e9\\r\\nd\\u2019analyser et de comprendre les symbolismes derri\\u00e8re l\\u2019arche. H\\u00e9breux 10:1<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Dans\\r\\nl\\u2019ancien testament, l\\u2019ancienne alliance n\\u2019est rien d\\u2019autre que l\\u2019ombre de\\r\\nchoses \\u00e0 venir. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;La\\r\\npr\\u00e9sence de l\\u2019arche de l\\u2019alliance dans l\\u2019ancien testament n\\u2019\\u00e9tait qu\\u2019une\\r\\npr\\u00e9figuration de la r\\u00e9alit\\u00e9 actuelle que nous devons vivre pleinement.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;<\\/span><u><span lang=\\"fr\\">But 1<\\/span><\\/u><span lang=\\"fr\\">. Nous faire comprendre les implications\\r\\nde la pr\\u00e9sence de l\\u2019arche dans l\\u2019ancien testament, et son importance dans le\\r\\nnouveau testament. Il s\\u2019agit de son application pour nous aujourd\\u2019hui.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;Dieu\\r\\na des choses \\u00e0 nous dire \\u00e0 travers l\\u2019arche de l\\u2019alliance et l\\u2019alliance de\\r\\nl\\u2019arche, pour nous qui sommes arriv\\u00e9s \\u00e0 la fin de temps.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;l\\r\\nn\\u2019y a donc plus de temps \\u00e0 perdre. Bient\\u00f4t le son de la trompette retentira,\\r\\ncar les enjeux spirituels sont tels qu\\u2019ils n\\u2019\\u00e9taient pas auparavant.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;Il\\r\\nest malheureux de constater l\\u2019ignorance de cette r\\u00e9alit\\u00e9 par l\\u2019\\u00e9glise(l\\u2019\\u00e9pouse),\\r\\ndans le chef des enfants de Dieu, suite \\u00e0 la distraction leur inflig\\u00e9e par le\\r\\nmalin.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Les\\r\\nc\\u0153urs se sont d\\u00e9tourn\\u00e9s de l\\u2019essentiel. Le malin a surcharg\\u00e9 nos pens\\u00e9es de choses\\r\\nfutiles afin de nous d\\u00e9tourner des desseins de Dieu. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;<\\/span><u><span lang=\\"fr\\">But 2<\\/span><\\/u><span lang=\\"fr\\">. Nous voulons aspirer \\u00e0 un engagement\\r\\nplus profond et plus d\\u00e9termin\\u00e9 dans notre marche personnel avec le Seigneur. Dieu\\r\\nveut nous emmener \\u00e0 cultiver une relation plus intense avec Lui. Il est\\r\\nquestion de plus de cons\\u00e9cration, plus de saintet\\u00e9, plus de conscience, plus de\\r\\ncrainte de Dieu. C\\u2019est une occasion de nous encourager pour un engagement plus vif.<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center;line-height:normal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">S\\u2019engager avec Dieu requiert\\r\\nun prix \\u00e0 payer.<\\/span><\\/b><span lang=\\"fr\\"> <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><u><span lang=\\"fr\\">But 3<\\/span><\\/u><span lang=\\"fr\\">. Nous voulons nous sensibiliser du\\r\\ndanger et des cons\\u00e9quences d\\u2019une vie chr\\u00e9tienne superficielle et moins\\r\\nprofonde. De nos jours, l\\u2019inverse semble devenir l\\u2019exception. L\\u2019hypocrisie\\r\\ncaract\\u00e9rise de plus en plus notre marche avec Dieu. Les Chr\\u00e9tiens sont devenus\\r\\nmod\\u00e9r\\u00e9s, faisant preuve d\\u2019un manque d\\u2019authenticit\\u00e9.<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Juges\\r\\n17&nbsp;:6&nbsp;; 21&nbsp;: Les chr\\u00e9tiens semblent ne plus avoir de principe ni\\r\\nd\\u2019id\\u00e9o. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Romains\\r\\n12&nbsp;:2. <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Les\\r\\nchr\\u00e9tiens sont pr\\u00eats \\u00e0 se compromettre \\u00e0 la moindre adversit\\u00e9. Que ce soit dans\\r\\nles lieux de travail et o\\u00f9 que ce soit. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Il\\r\\ns\\u2019observe davantage de la l\\u00e9g\\u00e8ret\\u00e9 parmi les chr\\u00e9tiens. Dans l\\u2019accoutrement et\\r\\ndans bien d\\u2019autres aspects de leur vie, cette malfa\\u00e7on prend de l\\u2019ampleur, et\\r\\nce ne sont pas les arguments qui manquent pour la d\\u00e9fendre.<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">M\\u00eame\\r\\nla qualit\\u00e9 de nos cultes se d\\u00e9t\\u00e9riore. L\\u2019agr\\u00e9able prend l\\u2019ascendance sur\\r\\nl\\u2019utile. Les chr\\u00e9tiens pr\\u00e9f\\u00e8rent s\\u2019y tr\\u00e9mousser plut\\u00f4t que de se focaliser sur\\r\\nl\\u2019essentiel, la personne de Dieu. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Pri\\u00e8re&nbsp;:\\r\\nD\\u2019ici la fin de ce s\\u00e9minaire, qu\\u2019il y ait des repentances authentiques. Ne pas\\r\\nle faire reviendrait \\u00e0 hypoth\\u00e9quer sa destin\\u00e9e pour des choses vaines et\\r\\n\\u00e9ph\\u00e9m\\u00e8res. <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">NB<\\/span><\\/b><span lang=\\"fr\\">&nbsp;:\\r\\nQuand ce vent de superficialit\\u00e9 atteint un chr\\u00e9tien, il a l\\u2019impression qu\\u2019il\\r\\nest toujours pr\\u00e8s du Seigneur. Il continue de venir \\u00e0 l\\u2019\\u00e9glise normalement, et\\r\\nm\\u00eame d\\u2019\\u0153uvrer normalement, mais loin de Dieu. Ils se sont d\\u00e9tourn\\u00e9s de\\r\\nl\\u2019essentiel.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;Tu\\r\\npeux bien \\u00eatre dans les choses de Dieu et t\\u2019\\u00eatre \\u00e9loign\\u00e9 de Dieu depuis\\r\\nlongtemps.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;Quand\\r\\nce vend de superficialit\\u00e9 t\\u2019atteint, tu perds ta passion, tu perds ton z\\u00e8le, ta\\r\\nfermet\\u00e9 et tu prends petit \\u00e0 petit plaisir \\u00e0 la mondanit\\u00e9.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;On\\r\\nprie et on m\\u00e9dite la parole de de Dieu plus pour calmer sa conscience que pour\\r\\nle d\\u00e9sir de voir Dieu par les \\u00e9critures. On perd la soif de passer du temps\\r\\navec Dieu. Sa pr\\u00e9sence devient un sujet d\\u2019ennui.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;Cette\\r\\nl\\u00e9g\\u00e8ret\\u00e9 spirituelle n\\u2019est pas sans cons\\u00e9quences. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;<\\/span><u><span lang=\\"fr\\">But 4<\\/span><\\/u><span lang=\\"fr\\">. Nous voulons nous conscientiser sur les\\r\\neffets n\\u00e9fastes d\\u2019un christianisme principalement tourn\\u00e9 vers la recherche du\\r\\nbien-\\u00eatre individuel (personnel). <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">1\\r\\ncorinthiens 15&nbsp;:19.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Les\\r\\nhommes se sont d\\u00e9tourn\\u00e9s de la source, Dieu, pour leur propre personne. Ils pensent\\r\\npouvoir r\\u00e9gler leurs probl\\u00e8mes sans la moindre implication de Dieu.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">C\\u2019est\\r\\nun d\\u00e9sastre qui se d\\u00e9veloppe dans l\\u2019\\u00e9glise. Nous prions beaucoup, mais pas pour\\r\\nchercher Dieu. C\\u2019est la satisfaction de nos propres besoins que nous\\r\\nrecherchons.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Passer\\r\\ndes heures dans la pri\\u00e8re et de jours dans le je\\u00fbne et pri\\u00e8re, n\\u2019est utile que\\r\\ndans la mesure o\\u00f9 nous rependons l\\u2019odeur du Seigneur autours de nous.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">A\\r\\nl\\u2019image des enfants d\\u2019Isra\\u00ebl transportant l\\u2019arche mais tabass\\u00e9s par les\\r\\nphilistins, il existe des chr\\u00e9tiens qui prient beaucoup mais qui sont oppress\\u00e9s\\r\\ndans leur sommeil.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Transporter\\r\\nl\\u2019arche de l\\u2019alliance sans vivre l\\u2019alliance de l\\u2019arche, conduit vers un destin\\r\\nfuneste.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><u><span lang=\\"fr\\">But 5<\\/span><\\/u><span lang=\\"fr\\">. Nous voulons nous inciter \\u00e0 travailler\\r\\nsans rel\\u00e2che notre qu\\u00eate de la maturit\\u00e9 spirituelle. Philippiens 3&nbsp;:13-15 <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;<\\/span><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Il y a n\\u00e9cessit\\u00e9 de\\r\\ns\\u2019\\u00e9loigner des relations qui nous distraient, celles qui nous font perdre la\\r\\ncommunion avec Dieu. <\\/span><\\/b><span lang=\\"fr\\">Le temps est arriv\\u00e9 de prendre\\r\\nconscience, de se lever et de courir \\u00e0 la qu\\u00eate de Dieu. Cela implique de\\r\\nmettre de c\\u00f4t\\u00e9 tout ce qui nous alourdit et nous ralentit.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">&nbsp;Les\\r\\nvents de la superficialit\\u00e9 font que l\\u2019on devienne indiff\\u00e9rent vis-\\u00e0-vis de\\r\\nDieu.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify;line-height:normal\\"><span lang=\\"fr\\">Que\\r\\nDieu vous b\\u00e9nisse&nbsp;!<\\/span><\\/p>","en":null}', NULL, NULL, 1, '1er-seminaire-jour-1-lundi15-avril-2024', 1, '2024-04-19 02:18:20', '2024-11-14 19:04:29', NULL, '2024-04-15 17:00:00', NULL, 1),
