=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 2\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 3\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 6\\"\\/>\\r\\n <\\/w:LatentStyles>\\r\\n<\\/xml><![endif]--><!--[if gte mso 10]>\\r\\n<style>\\r\\n \\/* Style Definitions *\\/\\r\\n table.MsoNormalTable\\r\\n\\t{mso-style-name:\\"Tableau Normal\\";\\r\\n\\tmso-tstyle-rowband-size:0;\\r\\n\\tmso-tstyle-colband-size:0;\\r\\n\\tmso-style-noshow:yes;\\r\\n\\tmso-style-priority:99;\\r\\n\\tmso-style-parent:\\"\\";\\r\\n\\tmso-padding-alt:0cm 5.4pt 0cm 5.4pt;\\r\\n\\tmso-para-margin:0cm;\\r\\n\\tmso-para-margin-bottom:.0001pt;\\r\\n\\tline-height:115%;\\r\\n\\tmso-pagination:widow-orphan;\\r\\n\\tfont-size:11.0pt;\\r\\n\\tfont-family:\\"Arial\\",sans-serif;\\r\\n\\tmso-ansi-language:#000C;}\\r\\n<\\/style>\\r\\n<![endif]-->\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">R\\u00e9f\\u00e9rences\\r\\nbibliques : <\\/span><\\/b><span lang=\\"fr\\">Proverbes 3:5-6; Romains 11:33; Proverbes\\r\\n3:19-20; Psaumes 104:24; Proverbes 8:12-28; Gen\\u00e8se 17:1;<\\/span><\\/p><p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">Quelle est l\'attitude que l\'homme doit avoir face \\u00e0 la\\r\\nsagesse de Dieu ?<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<ol style=\\"margin-top:0cm\\" start=\\"1\\" type=\\"1\\"><li class=\\"MsoNormal\\" style=\\"mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\">S\'humilier\\r\\n     et reconna\\u00eetre sa petitesse au devant de la grandeur de Dieu.<\\/span><\\/li><\\/ol><p class=\\"MsoNormal\\"><span lang=\\"fr\\">[<i style=\\"mso-bidi-font-style:normal\\">Romain\\r\\n11:33]<\\/i><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">O\\r\\nprofondeur des richesses et de la sagesse et de la connaissance de Dieu! Que\\r\\nses jugements sont insondables, et ses voies introuvables!<\\/span><\\/i><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<ol style=\\"margin-top:0cm\\" start=\\"2\\" type=\\"1\\"><li class=\\"MsoNormal\\" style=\\"mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\">Se\\r\\n     soumettre, s\'incliner,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>se\\r\\n     prosterner , m\\u00eame quand nous ne comprenons rien. Il y a des choses que\\r\\n     Dieu fait aujourd\'hui mais que nous ne pouvons comprendre.<\\/span><\\/li><li class=\\"MsoNormal\\" style=\\"mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\">Faire preuve\\r\\n     de confiance en Dieu <\\/span><\\/li><li class=\\"MsoNormal\\" style=\\"mso-list:l0 level1 lfo1\\"><span lang=\\"fr\\">Nous appuyer\\r\\n     sur sa sagesse pour qu\'elle nous \\u00e9claire dans nos d\\u00e9cisions,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>nos choix.<\\/span><\\/li><\\/ol>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"margin-left:36.0pt\\"><span lang=\\"fr\\">&nbsp;<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">\\u201cM\\u00eame quand tu crois que tu peux, fais confiance \\u00e0 Dieu ;\\r\\nsois comme un enfant,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>consulte Dieu \\u00e0\\r\\ntout bout de champ,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>m\\u00eame avant de\\r\\nprendre la plus petite d\\u00e9cision\\u201d.<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\"><span style=\\"mso-spacerun:yes\\">&nbsp;<\\/span>Compte sur la sagesse de Dieu,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>il conna\\u00eet le chemin qu\'il te faut emprunter.\\r\\n<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">&nbsp;<\\/span><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9.e,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>tu ne sais pas de quoi sera fait demain,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>mais Dieu le sait car il y a \\u00e9t\\u00e9 avant toi\\u201d.<\\/span><\\/i><\\/b><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9.e,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>m\\u00eame\\r\\nquand tu ne verra rien dans tes songes et visions, saches que dans le silence,\\r\\net m\\u00eame dans l\'inconscience,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>si tu as\\r\\nl\'habitude de chercher Dieu,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>lui-m\\u00eame va\\r\\ns\'arranger pour te garder sur le bon chemin\\u201d.<br><\\/span><\\/i><\\/b><span lang=\\"fr\\"><br><\\/span><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9.e, tu\\r\\nn\'entendras pas toujours Dieu te dire prends ta gauche ou ta droite,mais dans\\r\\nsa fid\\u00e9lit\\u00e9,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>il orientera tes pas, et tu\\r\\nne te tromperas pas de direction\\u201d. <br><\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">[ Proverbes 3:5-6]<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">La sagesse divine\\r\\nest cr\\u00e9atrice ; elle se manifeste au travers de la cr\\u00e9ation. <\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">[<i style=\\"mso-bidi-font-style:normal\\">Proverbes 3:19-20]<\\/i><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">19. L\'\\u00c9ternel a fond\\u00e9 la terre par la sagesse, il a\\r\\n\\u00e9tabli les cieux par l\'intelligence. <br><\\/span><\\/i><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">20. Par sa connaissance les ab\\u00eemes se fendirent, et les\\r\\nnu\\u00e9es distillent la ros\\u00e9e.<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">La vie n\'est pas le\\r\\nfait d\'une succession des co\\u00efncidences hasardeuses. C\'est une suite de\\r\\nplanification et de mise en \\u0153uvre divine. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Et quand nous\\r\\nanalysons la beaut\\u00e9 de la nature, aussi bien que la complexit\\u00e9 du cerveau\\r\\nhumain,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>nous r\\u00e9alisons que\\r\\nl\'intelligence divine va au-del\\u00e0 de l\'entendement humain.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">[Psaumes 104:24]<\\/span><\\/i><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">Que tes oeuvres sont nombreuses, \\u00f4 \\u00c9ternel! tu les as\\r\\ntoutes faites avec sagesse. La terre est pleine de tes richesses.<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">La sagesse de\\r\\nDieu<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>est omnisciente . <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">[J\\u00e9r\\u00e9mie 23:24]<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">La sagesse de Dieu\\r\\nest anticipative.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><span lang=\\"fr\\">2. La face du lion<\\/span><\\/b><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Le lion sugg\\u00e8re la\\r\\nforce et la puissance de Dieu.<span style=\\"mso-spacerun:yes\\">&nbsp;<\\/span><\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">[Esaie 49:26]<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Bien-aim\\u00e9.e nous\\r\\nservons et Dieu puissant. Et la puissance de Dieu est illimit\\u00e9e.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">[1 Samuel 15:29]<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Dans Job 37:4, Dieu\\r\\nse pr\\u00e9sente \\u00e0 Job et la bible dit \\u2026apr\\u00e8s lui on entend le lion rugir. Dans ce\\r\\ntexte Dieu est pr\\u00e9sent\\u00e9 comme un lion rugissant.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">Le rugissement du lion fait allusion \\u00e0 :<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">a.<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>La grande puissance de Dieu<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\"><span style=\\"mso-spacerun:yes\\">&nbsp;<\\/span><i style=\\"mso-bidi-font-style:normal\\">[Gen\\u00e8se\\r\\n17:1]<\\/i><\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">b. La souverainet\\u00e9\\r\\net l\'autorit\\u00e9 incontest\\u00e9e de Dieu. Sa capacit\\u00e9 \\u00e0 d\\u00e9cider par lui-m\\u00eame, dans sa\\r\\nsouverainet\\u00e9.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9s,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>Dieu n\'a aucun compte \\u00e0 te rendre. Alors\\r\\ncesse de lui poser quelques fois des questions sogrenues\\u201d.<\\/span><\\/i><\\/b><span lang=\\"fr\\"> <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Dieu est Dieu sans\\r\\ntoi. Il peut se passer de toi, et m\\u00eame te remplacer en emmenant mieux que toi\\r\\ncar il est souverain. Alors cesse de le servir comme si tu lui accordait une\\r\\nfaveur.<br><\\/span><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9s,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>quand on a int\\u00e9gr\\u00e9 la face du lion, on\\r\\ns\'approche de Dieu sans pr\\u00e9tention. \\u00c7a te permet d\'adorer et d\'honorer Dieu\\r\\nm\\u00eame quand tes propres pri\\u00e8res ne sont pas exauc\\u00e9es ; et de faire ce qu\'il veut\\r\\nque tu fasses m\\u00eame quand il ne fait pas ce que tu veux qu\'il fasse\\u201d. <br><\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">L\'image du lion\\r\\nnous r\\u00e9v\\u00e8le la puissance de Dieu et la mani\\u00e8re dont nous devons nous approcher\\r\\nde lui.<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">[Daniel 4:32; Job 9:12]<\\/span><\\/i><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Dieu dans son\\r\\nautorit\\u00e9 s\'impose devant tout : autant les hommes que des circonstances.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9.e,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>le Dieu que tu sers, rien ni personne ne peut\\r\\ns\'opposer \\u00e0 lui et \\u00e0 sa volont\\u00e9. Quand tu comprends cet attribu de Dieu,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>tu cesse d\'avoir peur de ceux qui veulent s\'opposer\\r\\n\\u00e0 l\'\\u0153uvre de Dieu dans ta vie\\u201d.<\\/span><\\/i><\\/b><span lang=\\"fr\\"><\\/span><span lang=\\"fr\\"> <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">[Job 11:10; Job 23:13; Esa\\u00efe 43:13]<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Aucune cr\\u00e9ature ne\\r\\npeut r\\u00e9sister \\u00e0 Dieu parce que tout a \\u00e9t\\u00e9 cr\\u00e9\\u00e9 par lui. Chacune des cr\\u00e9atures\\r\\nc\\u00e9lestes et terrestre se soumet de gr\\u00e9 ou de force \\u00e0 l\'autorit\\u00e9 qui l\'a cr\\u00e9\\u00e9. <br><\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><i style=\\"mso-bidi-font-style:\\r\\nnormal\\"><span lang=\\"fr\\">[Psaumes 33:8-11]<\\/span><\\/i><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cMon fr\\u00e8re\\/ ma\\r\\ns\\u0153ur,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>quand tu as une parole de\\r\\nDieu,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>fais-lui confiance.<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>Dieu a le moyen de sa politique,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>il a la provision de sa vision; il est\\r\\nsuffisamment responsable pour s\'investir dans tout ce qu\'il te dit qu\'il va\\r\\nfaire\\u201d. <\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><span lang=\\"fr\\">3. La face du b\\u0153uf <\\/span><\\/b><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">\\u00c9z\\u00e9chiel 1:10<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">a.Le b\\u0153uf\\r\\nrepr\\u00e9sente le travail,<\\/span><\\/i><\\/b><span lang=\\"fr\\"> il est reconnu pour son\\r\\nendurance et sa capacit\\u00e9 \\u00e0 travailler dur pendant longtemps. <\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Bien-aim\\u00e9s, notre\\r\\nDieu ne se lasse jamais,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>il ne commence\\r\\njamais ce qu\'il n\'a pas encore achev\\u00e9. Voil\\u00e0 pourquoi la Bible parle du Dieu des\\r\\n\\u0153uvres achev\\u00e9es. <\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Il tire la charrue\\r\\njusqu\'\\u00e0 la fin sans jamais s\'arr\\u00eater. Aucune b\\u00e2tisse de Dieu ne reste\\r\\ninachev\\u00e9e. <\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Le b\\u0153uf travaille\\r\\nde mani\\u00e8re constante et r\\u00e9guli\\u00e8re autant que Dieu. <\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><span lang=\\"fr\\">b. <i style=\\"mso-bidi-font-style:normal\\">Le temp\\u00e9rament\\r\\ncalme<\\/i><\\/span><\\/b><span lang=\\"fr\\"> : notre Dieu est imperturbable dans sa\\r\\nnature, dans sa qui\\u00e9tude. <\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Notre Dieu ne\\r\\ns\'agite au devant de rien. Et quand on a sa nature,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>on ne tremble devant rien car on sait qu\'il\\r\\ng\\u00e8re tout. <\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">c. Le b\\u0153uf\\r\\nprogresse lentement mais de mani\\u00e8re r\\u00e9guli\\u00e8re<\\/span><\\/i><\\/b><span lang=\\"fr\\"> :\\r\\nparfois nous avons l\'impression que Dieu prend du retard pour ce n\'est pas le\\r\\ncas.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Dieu n\'est pas en\\r\\nretard par rapport au temps,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>ce sont les\\r\\n\\u00e9v\\u00e9nements qui se syncronisent \\u00e0 son mouvement. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">&nbsp;<\\/span><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><span lang=\\"fr\\">4. La face de l\'aigle<\\/span><\\/b><span lang=\\"fr\\"> <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">&nbsp;<\\/span><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">a.Elle repr\\u00e9sente\\r\\nune vue per\\u00e7ante et redoutable. <\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">&nbsp;Le Dieu que nous\\r\\nservons fait tout en partant d\'une vision,<span style=\\"mso-spacerun:yes\\">&nbsp;\\r\\n<\\/span>et m\\u00eame l\'existence est pr\\u00e9c\\u00e9d\\u00e9e par la vision de Dieu .<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">La vision implique\\r\\nla planification,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>l\\u2019anticipation,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>la programmation.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9s, tout\\r\\nce que Dieu cr\\u00e9\\u00e9 en l\'homme s\'inscrit dans une vision globale ; il ne fait\\r\\njamais rien de fa\\u00e7on isol\\u00e9e\\u201d.<\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Tu ne peux vivre\\r\\npleinement ta vie que si tu t\'inscris dans le plan global de Dieu pour ta\\r\\ndestin\\u00e9e. <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">La sagesse consiste\\r\\n\\u00e0 revenir \\u00e0 Dieu et lui demander ce qu\'on doit faire,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>par rapport au plan global de ta vie.<\\/span><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9.e,\\r\\ns\'approchant de Dieu,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>vide-toi de tes\\r\\ncalculs,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>de tes convictions. Dieu\\r\\nn\'utilise jamais les personnes capables mais plut\\u00f4t celles disponibles\\u201d. <\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span lang=\\"fr\\">Laisse Dieu te\\r\\nformater, te d\\u00e9poss\\u00e9der de tes petites ambitions,<span style=\\"mso-spacerun:yes\\">&nbsp; <\\/span>car il en a de bien plus grandes.<\\/span><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\"> <\\/span><\\/i><\\/b><\\/p><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"><i style=\\"mso-bidi-font-style:normal\\"><span lang=\\"fr\\">\\u201cBien-aim\\u00e9.e, ne\\r\\npeut pas te remplir si tu te pr\\u00e9sente devant lui comme une bouteille pleine.\\r\\nViens \\u00e0 Dieu comme une bouteille vide et laisse-le te remplir\\u201d. <br><\\/span><\\/i><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\" align=\\"center\\" style=\\"text-align:center\\"><span lang=\\"fr\\">Que\\r\\nDieu<i style=\\"mso-bidi-font-style:normal\\"> vous b\\u00e9nisse<b style=\\"mso-bidi-font-weight:\\r\\nnormal\\"> !<\\/b><\\/i><\\/span><\\/p>","en":null}', NULL, NULL, 1, 'les-quatre-visages-de-christ-4', 1, '2024-07-18 03:07:16', '2024-11-14 19:04:29', NULL, '2024-06-13 19:30:00', NULL, 1),
	(34, '{"fr":"Les quatre visages de christ 5","en":null}', 3, 'https://www.youtube.com/watch?v=NwDZR2rvyic', '{"fr":"posts\\/1721279532.Vign-Seminaire Biblique 05.jpg","en":""}', '{"fr":"<!--[if gte mso 9]><xml>\\r\\n <w:WordDocument>\\r\\n  <w:View>Normal<\\/w:View>\\r\\n  <w:Zoom>0<\\/w:Zoom>\\r\\n  <w:TrackMoves\\/>\\r\\n  <w:TrackFormatting\\/>\\r\\n  <w:PunctuationKerning\\/>\\r\\n  <w:ValidateAgainstSchemas\\/>\\r\\n  <w:SaveIfXMLInvalid>false<\\/w:SaveIfXMLInvalid>\\r\\n  <w:IgnoreMixedContent>false<\\/w:IgnoreMixedContent>\\r\\n  <w:AlwaysShowPlaceholderText>false<\\/w:AlwaysShowPlaceholderText>\\r\\n  <w:DoNotPromoteQF\\/>\\r\\n  <w:LidThemeOther>EN-US<\\/w:LidThemeOther>\\r\\n  <w:LidThemeAsian>X-NONE<\\/w:LidThemeAsian>\\r\\n  <w:LidThemeComplexScript>X-NONE<\\/w:LidThemeComplexScript>\\r\\n  <w:Compatibility>\\r\\n   <w:BreakWrappedTables\\/>\\r\\n   <w:SnapToGridInCell\\/>\\r\\n   <w:WrapTextWithPunct\\/>\\r\\n   <w:UseAsianBreakRules\\/>\\r\\n   <w:DontGrowAutofit\\/>\\r\\n   <w:SplitPgBreakAndParaMark\\/>\\r\\n   <w:EnableOpenTypeKerning\\/>\\r\\n   <w:DontFlipMirrorIndents\\/>\\r\\n   <w:OverrideTableStyleHps\\/>\\r\\n   <w:UseFELayout\\/>\\r\\n  <\\/w:Compatibility>\\r\\n  <w:DoNotOptimizeForBrowser\\/>\\r\\n  <m:mathPr>\\r\\n   <m:mathFont m:val=\\"Cambria Math\\"\\/>\\r\\n   <m:brkBin m:val=\\"before\\"\\/>\\r\\n   <m:brkBinSub m:val=\\"&#45;-\\"\\/>\\r\\n   <m:smallFrac m:val=\\"off\\"\\/>\\r\\n   <m:dispDef\\/>\\r\\n   <m:lMargin m:val=\\"0\\"\\/>\\r\\n   <m:rMargin m:val=\\"0\\"\\/>\\r\\n   <m:defJc m:val=\\"centerGroup\\"\\/>\\r\\n   <m:wrapIndent m:val=\\"1440\\"\\/>\\r\\n   <m:intLim m:val=\\"subSup\\"\\/>\\r\\n   <m:naryLim m:val=\\"undOvr\\"\\/>\\r\\n  <\\/m:mathPr><\\/w:WordDocument>\\r\\n<\\/xml><![endif]--><!--[if gte mso 9]><xml>\\r\\n <w:LatentStyles DefLockedState=\\"false\\" DefUnhideWhenUsed=\\"false\\"\\r\\n  DefSemiHidden=\\"false\\" DefQFormat=\\"false\\" DefPriority=\\"99\\"\\r\\n  LatentStyleCount=\\"371\\">\\r\\n  <w:LsdExcep