ity=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 4\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 5\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"46\\"\\r\\n   Name=\\"List Table 1 Light Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"47\\" Name=\\"List Table 2 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"48\\" Name=\\"List Table 3 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"49\\" Name=\\"List Table 4 Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"50\\" Name=\\"List Table 5 Dark Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"51\\"\\r\\n   Name=\\"List Table 6 Colorful Accent 6\\"\\/>\\r\\n  <w:LsdException Locked=\\"false\\" Priority=\\"52\\"\\r\\n   Name=\\"List Table 7 Colorful Accent 6\\"\\/>\\r\\n <\\/w:LatentStyles>\\r\\n<\\/xml><![endif]--><!--[if gte mso 10]>\\r\\n<style>\\r\\n \\/* Style Definitions *\\/\\r\\n table.MsoNormalTable\\r\\n\\t{mso-style-name:\\"Tableau Normal\\";\\r\\n\\tmso-tstyle-rowband-size:0;\\r\\n\\tmso-tstyle-colband-size:0;\\r\\n\\tmso-style-noshow:yes;\\r\\n\\tmso-style-priority:99;\\r\\n\\tmso-style-parent:\\"\\";\\r\\n\\tmso-padding-alt:0cm 5.4pt 0cm 5.4pt;\\r\\n\\tmso-para-margin:0cm;\\r\\n\\tmso-para-margin-bottom:.0001pt;\\r\\n\\tline-height:115%;\\r\\n\\tmso-pagination:widow-orphan;\\r\\n\\tfont-size:11.0pt;\\r\\n\\tfont-family:\\"Arial\\",sans-serif;\\r\\n\\tmso-ansi-language:#000C;}\\r\\n<\\/style>\\r\\n<![endif]-->\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">&nbsp;<\\/span><b style=\\"mso-bidi-font-weight:normal\\"><u><span lang=\\"fr\\">Chapitre\\r\\n3. Organisation du monde des esprits(suite).<\\/span><\\/u><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">III.Activit\\u00e9s\\r\\net r\\u00f4les des anges <\\/span><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Les anges sont d\\u00e9crits comme ex\\u00e9cutants\\r\\ndiverses fonctions et t\\u00e2ches au service de Dieu en faveur des saints.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Matthieu 1.14<\\/span><\\/p><p class=\\"MsoNormal\\"><span lang=\\"fr\\">N.B.Les anges sont avant tout au service de\\r\\nDieu et non des hommes. Cependant ils rendent service en faveur des saints.<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><u><span lang=\\"fr\\">R\\u00f4le\\r\\n1.Adorateurs de Dieu<\\/span><\\/u><span lang=\\"fr\\">.<\\/span><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">L\\u2019adoration va jusqu\\u2019\\u00e0 la fa\\u00e7on de nous\\r\\ncomporter au quotidien, nos actions, r\\u00e9actions, notre service pour Dieu.<\\/span><\\/p>\\r\\n\\r\\n<ul><li><span lang=\\"fr\\">Les anges participent activement \\u00e0 la louange\\r\\net \\u00e0 l\\u2019adoration c\\u00e9leste.<\\/span><\\/li><li><span lang=\\"fr\\">L\\u2019adoration occupe une place centrale dans\\r\\nl\\u2019existence ang\\u00e9lique.<\\/span><\\/li><\\/ul>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Cela devrait \\u00eatre de m\\u00eame pour chaque enfant\\r\\nde Dieu, peu importe l\\u2019activit\\u00e9 le faire \\u00e0 la gloire de Dieu.<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Apocalypse 7.11-12<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Esa\\u00efe 6.2-3<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">\\u00c0\\r\\nchaque fois que tu r\\u00e9alises un attribut de Dieu, au m\\u00eame moment Dieu te permet\\r\\nde le vivre et le d\\u00e9couvre davantage.<\\/span><\\/b><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">L\\u2019adoration\\r\\n\\u00e0 un moment te rend incapable de multiplier des paroles, c\\u2019est \\u00e0 ce moment que\\r\\nle Saint Esprit t\\u2019am\\u00e8ne \\u00e0 des soupirs inexprimables.<\\/span><\\/b><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b>Deux choses sur l\\u2019adoration des\\r\\nanges rendu \\u00e0 Dieu:<\\/b><\\/p>\\r\\n\\r\\n<ol><li><b>Elle met en lumi\\u00e8re\\r\\nl\\u2019appel de toute la cr\\u00e9ation \\u00e0 se soumettre \\u00e0 Dieu mais avec r\\u00e9v\\u00e9rence, amour\\r\\net humilit\\u00e9<\\/b><\\/li><li><b>Elle constitue une\\r\\nsource d\\u2019inspiration majeure pour les croyants, offrant un mod\\u00e8le de r\\u00e9ponse\\r\\nappropri\\u00e9e \\u00e0 la majest\\u00e9 et \\u00e0 la grandeur divine.<\\/b><\\/li><\\/ol>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">L\\u2019Adoration est l\\u2019expression de ton amour, de\\r\\nta soumission \\u00e0 Dieu. Ne prie pas par habitude ou coutume; prie avec ton c\\u0153ur;\\r\\nen s\'attardant sur chaque mot que ton c\\u0153ur donne.<\\/span><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Apocalypse 5.11-14<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Le c\\u0153ur sinc\\u00e8re est la cl\\u00e9 de la vraie\\r\\nadoration<\\/span><\\/p><p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><u><span lang=\\"fr\\">R\\u00f4le\\r\\n2.Messagers de Dieu<\\/span><\\/u><\\/b><u><span lang=\\"fr\\"><\\/span><\\/u><\\/p>\\r\\n\\r\\n\\r\\n\\r\\n<ul><li><span lang=\\"fr\\">Les anges sont souvent envoy\\u00e9s par Dieu pour\\r\\ntransmettre des messages de grande importance aux hommes.<\\/span><\\/li><\\/ul>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Ceux que les anges font entre autre:<\\/span><\\/p>\\r\\n\\r\\n<ul><li><span lang=\\"fr\\">Annoncer les \\u00e9v\\u00e9nements futurs;<\\/span><\\/li><li><span lang=\\"fr\\">R\\u00e9v\\u00e9ler les myst\\u00e8res et v\\u00e9rit\\u00e9s divines;<\\/span><\\/li><li><span lang=\\"fr\\">Fournir des directives et orientations.<\\/span><\\/li><\\/ul>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Luc 1.11-13, 26-31, Gen\\u00e8se 16.7-11, 22.11-18<\\/span><\\/p><p class=\\"MsoNormal\\"><u><span lang=\\"fr\\">Retenons ceci:<\\/span><\\/u><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Les messages que les anges apportent servent \\u00e0\\r\\naccomplir quatre objectifs: <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Objectif\\r\\n1.contribuer \\u00e0 l\'accomplissement du dessein de Dieu. <\\/span><\\/b><span lang=\\"fr\\">Daniel\\r\\n10.4-6,11-14<\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><span lang=\\"fr\\">Nos pri\\u00e8res activent le minist\\u00e8re ang\\u00e9lique <\\/span><\\/p>\\r\\n\\r\\n<p class=\\"MsoNormal\\"><b style=\\"mso-bidi-font-weight:normal\\"><span lang=\\"fr\\">Objectif\\r\\n2.apporter r\\u00e9confort et encouragement. <\\/span><\\/b><span lang=\\"fr\\">Luc 22:41-43, 1\\r\\nrois 19.4-8<\\/span><\\/p>","en":null}', NULL, NULL, NULL, 'le-monde-des-esprits-et-leur-fonctionnement-3', 1, '2024-07-18 03:28:39', '2024-11-14 19:04:29', NULL, '2024-02-28 19:30:00', NULL, 1),
