INSERT INTO `requetes` (`id`, `fullname`, `email`, `phone`, `pays`, `requete`, `created_at`, `updated_at`) VALUES
	(14, 'Habakuk Noé', 'habakuknoe79@gmail.com', '+2250711202425', 'Afghanistan', 'Prier pour mon MINISTÈRE et L\'ÉGLISE que le Seigneur nous donne ici en Côte D\'Ivoire précisément à Hiré 🙏', '2025-01-16 09:20:03', '2025-01-16 09:20:03');
INSERT INTO `requetes` (`id`, `fullname`, `email`, `phone`, `pays`, `requete`, `created_at`, `updated_at`) VALUES
	(15, 'Martin nkulu', 'martinkulu412@gmail.com', '+243991777399', 'Congo (RDC)', 'Besoin du soutien divin pour mon programme de mariage coutumier au mois d\'octobre 2025', '2025-01-16 09:21:02', '2025-01-16 09:21:02'),
	(16, 'Mukendi wa mukendi guylain', 'guylainmukendi93@gmail.com', '+33751455473', 'France', 'Ma requête POUR LA RÉGULARISATION DE PAPIER ICI EN FRANCE ET J’AI PLUS AVOIR UN BOULOT Et pour ma santé j’ai douleur au niveau de ma poitrine gauche', '2025-01-16 09:22:33', '2025-01-16 09:22:33'),
	(17, 'Mukaso KILEDI Grâce', 'DGM.divinegracemkks@gmail.com', '0811012921', 'Congo (RDC)', 'Que le seigneur me fasse grâce afin que Je devienne sensible spirituellement, qu\'il m\'enlève la peur face à mes adversaires, que je récupère mes enfants qui sont bloqués au Congo Brazzaville par ma belle famille. Amen🙏', '2025-01-16 09:22:49', '2025-01-16 09:22:49'),
	(18, 'Masasa Clarisse', 'masasaclarisse@gmail.com', NULL, 'Congo (RDC)', 'Je suis à la recherche d\'une maison que l\'Éternel me fasse grâce, les maisons sont Cher mon budget est moindre j\'ai vraiment besoin d\'un miracle, tellement besoin', '2025-01-16 09:23:12', '2025-01-16 09:23:12'),
	(19, 'Jofelly luyenika diasonama', 'jofellyluyenika@gmail.cm', '0843008099', 'Congo (RDC)', 'Je vais simplement que l’année soit ouverte à ma faveur, que la présence de Dieu ce manifeste dans ma vie cette année.', '2025-01-16 09:23:22', '2025-01-16 09:23:22'),
	(20, 'Jenovic KAYEMBE', 'kapiambajenovic8@gmail.com', '+243971228335', 'Congo (RDC)', 'Ma requête est que le seigneur puisse faire réunir l\'amour dans ma famille et qu\'il m\'aide a avoir la force d\'avancer', '2025-01-16 09:24:09', '2025-01-16 09:24:09'),
	(21, NULL, NULL, NULL, 'Afghanistan', 'Ma prière est que Dieu me fasse Grâce, qu\'il protège très très longtemps mes parents ainsi que mes frères, qu\'il garde toujours en bonne santé mes parents mes frères et moi, qu\'il me remplisse d\'intelligence et de sagesse, qu\'il enlève en moi la peur,la honte,la négativité... qu\'il m\'aide à lui faire confiance, qu\'il me bénisse abondamment pour que je prenne soin de ma famille car je suis l\'ainée et mes parents viellissent déjà, c\'est moi qui dois prendre le relais et prendre soins d\'eux et de mes frères, qu\'il facilite mon parcourt et qu\'il m\'aide à réussir à l\'université, qu\'il guide mes frères,et qu\'il guérisse toutes les personnes malades, qu\'il aide ceux qui ont besoin de lui,et aussi qu\'il pardonne mes péchés 😔... qu\'il réalise tous les besoins et vœux de mon cœur,du coeur de mon Père, ma Mère et de mes frères,AMEN AMEN AMEN', '2025-01-16 09:25:55', '2025-01-16 09:25:55'),
	(22, 'Kongolo', 'kongoloelisee36@gmail.com', '+243972001628', 'Congo (RDC)', 'Que le seigneur débloque ma vie familiale financière et m\'ouvre d\'autres portes', '2025-01-16 09:26:39', '2025-01-16 09:26:39'),
	(23, 'Alexandra Rigadume', 'rigadume.sandra44@gmail.com', '812659007', 'Congo (RDC)', '-que Dieu créer la rencontre avec l\'homme de ma.vie avant mars 25 (mois du mariage)\r\n-stabilité et repos dans tout les domaines \r\n-que mon projet d orphelinat devienne effectif', '2025-01-16 09:27:21', '2025-01-16 09:27:21'),
	(24, 'Patrina Mandjale Mueji', 'Mueji@icloud.com', '0905273751', 'Congo (RDC)', 'Je demande au Seigneur de m’accorder mon diplôme avec au moins 78% et que le Seigneur bénisse et garde les parents ainsi que mes frères . Qu’il bénisse et oriente Andy qu’il ait du progrès dans sa vie \r\nEt aussi je demande à Dieu de rétablir mon cycle menstruel', '2025-01-16 09:27:32', '2025-01-16 09:27:32'),
	(25, 'Fr Jean Pierre kamanda', NULL, '0892230060', 'Congo (RDC)', 'Je demande à l\'église et pasteurs de prié pour ma santé, de ma femme que Dieu nous donne la stabilité dans le domaine du travail et qui nous garde fidèle à lui qu\'il nous guide dans notre marche qu\'il veille aussi à nos enfants', '2025-01-16 09:28:11', '2025-01-16 09:28:11'),
	(26, 'MiHiGO NYOTA Divine', 'divinemihigo@gmail.com', '0852663643', 'Congo (RDC)', 'Prier pour Le discernement des esprits \r\nPrier pour je vive dans la stabilité cette année (Physique, émotionnel et financière)\r\nPrier pour mon travail que je signe un contrat avec un bon salaire et que je revienne sur la localisation prévue initialement lors du recrutement (Kinshasa)\r\nPrier pour mon mariage , que je ne me trompe pas sur le choix de conjoint.', '2025-01-16 09:31:41', '2025-01-16 09:31:41'),
	(27, 'Marie rose Nyota', 'toto_assumani@hotmail.com', '+32471100331', 'Belgium', 'Priez pour moi pour que\r\n1.Que cet homme( Ali ) avec qui nous avons des projets de vie commune depuis 4 ans , bientôt 5 en Septembre m’honore par le mariage et qu’ensemble nous servions Le Seigneur.\r\n2. Que mon fils Matthieu soit délivré de la drogue, l’alcool et l’ impudicité et qu’il revienne à Dieu.\r\n3. Que ma fille Perle reste ferme dans l’engagement qu’elle a pris avec LE SEIGNEUR, que Dieu lui donne un mari qui craint et sert Dieu et que Dieu lui ouvre les portes de l’emploi( elle a un master en droit international).\r\n4.Que ma fille Shekina aille encore en profondeur dans son engagement avec Dieu, qu’elle réussisse tous ses examens à L’Université( elle est en 2e bachelor en droit européen et international) et son année.\r\n5. Que mon fils Louis reste attaché à Dieu et que Dieu bénisse ses études.', '2025-01-16 09:35:05', '2025-01-16 09:35:05'),
	(28, 'BATEKO , Mosango , chavez', 'cbateko@gmail.com', '+243 997360166', 'Congo (RDC)', 'Depuis un certain temps je sens que rien ne marche dans mes études , je tous fait ...je l\'impression de tourner au rond point  peut importe les efforts fournis', '2025-01-16 09:39:33', '2025-01-16 09:39:33'),
	(29, 'Grâce Nkosi senga', 'gracenkosi413@gmail.com', '826066206', 'Congo (RDC)', 'En cette année 2025, Je veux que l’éternel m’aide pour l’obtention de ma prime de risque, je travail pendant beaucoup \r\nd’années sans obtenir ma récompense…\r\n-Que l’éternel m’accorde un mariage heureux et des enfants, je veux témoigner comme les autres\r\n- Que l’éternel accorde une santé de fer à ma mère qui est tout le temps souffrante, AMEN', '2025-01-16 09:39:42', '2025-01-16 09:39:42'),
	(30, NULL, NULL, NULL, 'Afghanistan', '* sagesse et intelligence divine \r\n* travail bien rémunéré et épanouissant \r\n* Visitation financière \r\n* stabilité dans ma relation avec Prisca et éventuelle mariage', '2025-01-16 09:42:50', '2025-01-16 09:42:50'),
	(31, 'Alain', 'mosalaalain00@gmail.com', '823973929', 'Congo (RDC)', 'Que Dieu me fasse la grâce d\'être capable de pourvoir financièrement à mon foyer \r\nQue Dieu me fasse la grâce de connaître avec ma femme la joie de la maternité.\r\nMon amie à un cancer, que Dieu la guérisse', '2025-01-16 09:45:04', '2025-01-16 09:45:04'),
	(32, 'Joël Isaac k luabeya', 'kabotojoel2019@gmail.com', '‪+90 533 857 30 82‬', 'Cyprus', 'Requêtes \r\n\r\n1. Les finances pour mon voyage En mai 2025 5000 pour revoir ma famille et ma fiancée \r\n2. Les finances pour ⁠mon mariage le 12 décembre 2025 \r\n3. ⁠mon Travail et la stabilité financière , décrocher un nouveau poste \r\n4. ⁠la stabilité dans la vie  financière  de ma fiancée et le travail pour ma fiancée , sa prestation de serment et son stage professionnel \r\n5. ⁠la délivrance Totale de ma famille ( Les luabeya) \r\n6. ⁠les finances pour mettre à l’abri mes frères et sœurs ainsi que ma mère mais pour accomplir mon voeux de soutenir l’œuvre de Dieu. \r\n7. ⁠ la  restauration de la santé de maman \r\n8. ⁠ le positionnement dans mon ministère\r\n9. ⁠ achat d’une voiture \r\n10. ⁠mon Inscription au 3e cycle à la faculté de Droit.(DEA + DES ) et mon inscription au barreau de Kinshasa Gombe.\r\n11. QUE JE SOIS ATTACHÉ À DIEU POUR LA VIE', '2025-01-16 09:46:07', '2025-01-16 09:46:07'),
	(33, 'Nzedinga Sarah', NULL, '0817615804', 'Congo (RDC)', 'Prier pour la santé des mes enfants  ,la paix et la fidélité dans mon foyer', '2025-01-16 09:49:31', '2025-01-16 09:49:31'),
	(34, 'Masawu Aron', 'masawuaron367@gmail.com', '0831209484', 'Congo (RDC)', 'Que la grâce de Dieu tombe sur plamedie masawu qui s’ouvre de la vision et ça miséricorde soit sur lui', '2025-01-16 09:49:37', '2025-01-16 09:49:37'),
	(35, 'Josué mangala', 'josuemangala740@gmail.com', '0820662955', 'Congo (RDC)', 'Ma requête est celle ci : que le seigneur m\'aide à trouver le chemin tracé pour ma réussite, que Dieu me guide à trouver la voie de ma destinée...\r\nQue Dieu puisse m\'éclairer à comprendre la voie qu\'il veut que je suive.\r\n\r\nDonc la direction divine dans ma vie.\r\n\r\nJ\'ai foi que Dieu va m\'exaucer.', '2025-01-16 09:51:10', '2025-01-16 09:51:10'),
	(36, 'Odile Balanganayi TSHIBUABUA', 'honeyodile7@gmail.com', '+243898627832', 'Congo (RDC)', 'Ma requête \r\nQue Dieu de grâce Donne un travail à mon mari qui a traîné dans le chômage depuis 12 ans de mariage.\r\nQue Dieu me donner aussi un bon travail stable avec une bonne rémunération en cette année.', '2025-01-16 09:51:51', '2025-01-16 09:51:51'),
	(37, 'Kitini minzundu rama', 'ramakitini45@gmail.com', '0814619262 0977470535', 'Congo (RDC)', 'Que la main du seigneur se manifeste dans ma que j\'obtiens ce bon travail sur j\'attends toujours, seigneur exauce mes prières.', '2025-01-16 09:53:01', '2025-01-16 09:53:01'),
	(38, 'Hilaire Wonsa', 'hilairenkodia05@gmail.com', '+243897010211', 'Congo (RDC)', 'En cette saison j’aimerais que Dieu me rend plus sensible à sa parole, j’aimerais également qu’il m’accompagne à faire un bon choix pour ma destinée, qu’il enlève la distraction devant moi.', '2025-01-16 10:02:10', '2025-01-16 10:02:10'),
	(39, NULL, NULL, NULL, 'Congo (RDC)', 'J’aimerais une prière pour mon cheminant et moi, que l’éternel se souvienne de nous, qu’il aide nos cœurs à grandir et à rester soudé dans cette épreuve et surtout qu’il nous exauce.', '2025-01-16 10:03:16', '2025-01-16 10:03:16'),
	(40, 'Fils ONOMANGA ONOMANGA', 'filiusonomangare05@icloud.com', '+971529044891', 'United Arab Emirates', 'La croissance de Ma vie spirituelle \r\nLa précision sur mes projets dans l’entreprenariat \r\nLa clarté sur mes études car c’est une histoire qui me tourmente depuis', '2025-01-16 10:03:52', '2025-01-16 10:03:52'),
	(41, 'Pat', 'patrickmbwebwe@gmail.com', '+33758437429', 'France', 'Que Dieu accorde des enfants à mon couple (mon épouse et moi).\r\nPlus deux ans de mariage, nous sommes toujours en attente, nous avons même immigré en France afin de suivre un traitement adéquat, mais jusque là, nous sommes toujours en attente de la grâce Divine.', '2025-01-16 10:08:27', '2025-01-16 10:08:27'),
	(42, 'Guslain Katusunduaku', 'katuguslain75@gmail.com', NULL, 'Congo (RDC)', 'Je vais que le seigneur m\'utilise puissamment, qu\'il m\'aide à rester près de lui enfin de vaincre les combats de ce monde et qu\'il me comble de l\'Esprit Saint pour discerner les bien et le mal....', '2025-01-16 10:14:14', '2025-01-16 10:14:14'),
	(43, 'Nadège M', NULL, '+243817726466', 'Congo (RDC)', 'Je demande la prière pour le salut de les parents et leur réconciliation (ils sont séparés et chacun vit de son côté sans engagement)\r\nEt la prière pour la régularisation de mon mariage(que Dieu parle et  touche mon mari à ce sujet)', '2025-01-16 10:21:24', '2025-01-16 10:21:24'),
	(44, 'Emmanuel mvuabika mundu', 'centredesanteemmanuel@gmail.com', '+243817044241', 'Congo (RDC)', 'Je suis à la recherche d\'une fiancée. mon ex m\'avait trompée. Que cette fois ci le seigneur me donne ma femme. Qui craint DIEU, sage, fidèle.', '2025-01-16 10:22:55', '2025-01-16 10:22:55'),
	(45, 'Hubert Mutumbi', 'lioglopa@gmail.com', '0810133881', 'Congo (RDC)', 'QUE DIEU M\'OUVRE ENCORE D\'AUTRES PORTES DE BÉNÉDICTION ET GARDE TOUTE MA FAMILLE AU NOM DE JÉSUS CHRIST', '2025-01-16 10:26:16', '2025-01-16 10:26:16'),
	(46, 'Tracy Kalay', NULL, '+243842047365', 'Congo (RDC)', 'Que le seigneur me rapproche encore plus de lui et que je discerne ses plans pour ma vie , que le seigneur me conduit dans le chemin de sa paix', '2025-01-16 10:33:15', '2025-01-16 10:33:15'),
	(47, 'Roger Mutombo Kabamba', 'rogermutombo8@gmail.com', '+353 899833895/ +243 815165699(WhatsApp)', 'Ireland', 'une vie de communion plus intense avec le Seigneur Jésus-Christ  pour ma famille (ma femme et mes enfants). Matthieu 6:33', '2025-01-16 10:37:02', '2025-01-16 10:37:02'),
	(48, 'Sephora Ntumba', 'ntumbankusu1999@gmail.com', '+243 820 439 450', 'Congo (RDC)', 'Pour cette année 2025, je prie à Dieu de m’accorder la stabilité sur le plan spirituel, financier, et conjugal qu’Il accomplisse sa volonté parfaite pour ma vie.\r\nQu’Il m’aide à sortir les meilleurs de moi face à toutes ces épreuves de la vie, que j’arrive à discerner face à chaque situation selon sa volonté, qu’Il me donne d’être sage dans ma gestion financière et celle de mon couple. \r\nJe crois fermement que Dieu seul est le maître de ma vie, c’est Lui qui me conduit et qu’Il s’arrangera à achèver l’œuvre parfaite qu’Il a commencé dans ma vie et surtout dans mon couple.\r\nQu’Il nous accorde la vie, à moi, ma mère, mon frère, ma tante(qui est la seule représentante de mon défunt père) et toute ma famille afin que cette année nous achetons notre première parcelle.\r\nQu’il protège mon homme, ses parents, ses frères et sœurs ainsi que toute sa famille.\r\nQu’Il aide mon homme à réussir ses projets le plus cher afin qu’il aborde enfin le sujet du mariage.\r\nQu’Il l’aide aussi à m’aimer et à changer son comportement qui blessent un peu defois. Que Dieu aide mon chéri à orienter ses dépenses, à être plus conscient et responsable dans notre couple.\r\nEn fin, que la promesse que Dieu m’a fait l’année passée pour ce juillet 2025 s’accomplisse, selon sa fidélité.\r\nAmen.', '2025-01-16 10:39:47', '2025-01-16 10:39:47'),
	(49, 'BASILIA MALONGO CLAUDIA', 'Claudiabasilia20@gmail.com', '0990316447', 'Congo (RDC)', 'Merci seigneur pour l’année 2024 et je te bénis pour cette année 2025 c’est une grâce d’être compter parmi les vivants et me tenir ici présente pour faire de nouvelles requêtes pour cette merveilleuse année \r\n\r\n#Requête: \r\n-je demande à Dieu sa volonté parfaite pour ma destinée \r\n- je demande à Dieu de toujours sanctifier mes jour et mon parcours \r\n- je demande à Dieu de protéger les miens et surtout ma famille \r\n- je demande à Dieu que ça main puissante et bienveillante soit sur moi et ma famille \r\n- je demande à Dieu la croissance spirituelle et une crainte absolu à sa royauté et sa divinité \r\n- je demande à Dieu la révélation et le discernement des saisons pour mon église et ma famille \r\n- je demande à Dieu l’épanouissement financière pour toute ma famille \r\n- je demande à Dieu la révélation sur mon problème dès peau et dés santé \r\n- je demande à Dieu une croissance accélérée dans mon entreprise \r\n-je demande à Dieu de me donner les meilleurs employés qui me feront prospérer dans mon restaurant des personnes qui vont accompagner ma vision pour les entreprises \r\n-je demande à Dieu un mariage paisible un mari respectueux compréhensif intelligent attentionné Fidèle qui craint Dieu un mari travailleur et  riche un appuie un modèle un partenaire parfait \r\n-je demande Dieu une belle famille gentilles et des personnes sincères qui m’aimeront comme ma propre famille \r\n-je demande à Dieu de me donner des meilleurs enfants qui suivrons les voies de Dieu et qui marcherons dans la crainte de Dieu \r\n-je demande à Dieu de forger mon caractère pour toute les portes qui s’ouvriront devant moi \r\n-je demande à Dieu de mettre sur mon chemin des personnes qui vont m’accompagner dans ma destinée et dans mon parcours \r\nJe demande à Dieu de m’aider à Honoré mes parents avant leurs départ vers le créateur et de les aider comme il se doit \r\n-je demande à Dieu de ramener toutes ma famille à lui à fin que nous héritons tous le royaume de cieux \r\n-je demande à Dieu l’épanouissement pour tout le membre de ma famille et les meilleurs chose possibles pour eux santé paix richesse \r\n-je demande à Dieu des expériences magnifiques tout en étant dans sa présence et dans sa crainte que Dieu m’aide et m’apprend à tomber amoureuse que de lui et de lui servir comme une épouse parfaite que la paix du christ son amour sa bonté soit mon partage quotidien 💓🙌🏽❤️‍🔥Amen \r\n\r\nLa mort est le chemin de tous car nous étions poussières et nous rentrerons poussière mais si un jour in membres de ma famille restreinte devrait mourir qu’il meurt en christ cela est mon plus grand souhait . \r\n\r\nMerci pasteur Ken.LUAMBA pour cette initiative donnée que Dieu vous bénisse vous et votre famille ainsi que tout les pasteurs qui vont opérer dans ce service Que Dieu vous bénissent 🙏🏽❤️‍🔥🙌🏽', '2025-01-16 10:49:36', '2025-01-16 10:49:36'),
	(50, NULL, NULL, NULL, 'Afghanistan', 'Je veux vraiment être pur devant Dieu ; arrêtez la masturbation', '2025-01-16 10:55:47', '2025-01-16 10:55:47'),
	(51, 'Nsiku Yeka Israelle', 'nsikuyekaisraelle70@gmail.com', '243977869104', 'Congo (RDC)', 'Je demande à Dieu de guérir ma famille de toute condamnation, de toute malédictions qui ont été dites dans leur traditions  à propos des enfants, et je demande à ce que Dieu libère la grâce , restaure  la réussite, le bonheur , la stabilité dans tout les aspects et je demande aussi que Dieu se serve de moi dans son ministère et qu’il me prépare dans tout les aspects Amen .', '2025-01-16 10:57:57', '2025-01-16 10:57:57'),
	(52, 'Heurnice lukeba', 'Heurnicelekeba@icloud.com', '0891496831', 'Congo (RDC)', 'Prier pour mon père il a une maladie que la médecine ne se pas identifié.\r\nQue le Seigneur accorde la maternité dans ma famille et que la paix s’installe dans ma famille.\r\nMerci', '2025-01-16 11:06:45', '2025-01-16 11:06:45'),
