	(173, 'Matondo Nkanu Sephora', 'aichamatondo640@gmail.com', '097', 'Afghanistan', 'Seigneur Jésus Christ \r\nQue cette année 2025 soit une année de changement positif pour moi et ma famille \r\nQue le succès frappe à notre porte \r\nQue nous puissions enfin déménager de la parcelle familiale \r\nLa réconciliation de mes parents avec leur famille \r\nMon mariage avec la personne de ma destinée \r\nLa restauration ou la bénédiction de l\'état financier familiale \r\nAu nom de Jésus Christ \r\nAmen 🙏', '2025-01-16 14:58:04', '2025-01-16 14:58:04'),
	(174, NULL, NULL, NULL, 'Afghanistan', 'Que le Seigneur ouvre les portes enfin que je rejoigne mon mari, presque trois ans de mariage et toujours loin de mon mari , et qu\'il garde ma grossesse jusqu\'à terme', '2025-01-16 14:58:25', '2025-01-16 14:58:25'),
