	(257, 'Dani Okele', 'dani.okele13@gmail.com', '0816484644', 'Congo (RDC)', 'Je demande la grâce de Dieu pour pouvoir lui plaire. Je veux plaire à Dieu.', '2025-01-16 16:36:38', '2025-01-16 16:36:38'),
