	(1892, 'Likunde Ekila Naomie', 'naomielikunde18@gmail.com', '243817918295', 'Congo (RDC)', 'Bonjour je m\'appelle Naomie j\'ai des problème de mariage cela fait 10 ans que je rencontre souvent avec les hommes moins sérieux dans ma vie  parfois les hommes ne ressentent pas mon affection je vous demande de prier pour moi pour que je sois délivré', '2025-11-28 21:43:49', '2025-11-28 21:43:49'),
	(1893, 'Likunde Ekila Naomie', 'naomielikunde18@gmail.com', '243817918295', 'Congo (RDC)', 'Bonjour je m\'appelle Naomie j\'ai des problème de mariage cela fait 10 ans que je rencontre souvent avec les hommes moins sérieux dans ma vie  parfois les hommes ne ressentent pas mon affection je vous demande de prier pour moi pour que je sois délivré', '2025-11-28 21:43:59', '2025-11-28 21:43:59'),
	(1894, 'Likunde Ekila Naomie', 'naomielikunde18@gmail.com', '243817918295', 'Congo (RDC)', 'Bonjour je m\'appelle Naomie j\'ai des problème de mariage cela fait 10 ans que je rencontre souvent avec les hommes moins sérieux dans ma vie  parfois les hommes ne ressentent pas mon affection je vous demande de prier pour moi pour que je sois délivré', '2025-11-28 21:44:06', '2025-11-28 21:44:06'),
	(1895, NULL, NULL, NULL, 'Congo (RDC)', 'Requête\r\n\r\nJe viens humblement solliciter vos prières pour mon père, atteint d’un cancer du poumon. Il a déjà dû se déplacer trois fois pour suivre des traitements de chimiothérapie, mais aujourd’hui, il traverse une période difficile qui l’empêche de poursuivre correctement son traitement.\r\n\r\nAffaibli et découragé, il s’abandonne parfois à l’alcool, ce qui ne fait qu’aggraver son état de santé. Il se délaisse, devient colérique et reporte souvent la faute sur moi et mon jeune frère, alors que depuis la mort de notre maman en 2021, nous sommes les seuls à être restés constamment à ses côtés.\r\n\r\nNous faisons face à de nombreuses difficultés, autant dans notre famille restreinte qu’au sein de la famille élargie. Il arrive même qu’il raconte des faux témoignages en notre nom sans que nous sachions pourquoi, alors qu’un père devrait d’abord dialoguer avec sa famille et non l’exposer. Aujourd’hui, nous subissons des attaques et des réprimandes de toute part, alors que celui qui devrait être la base de toute solution lorsque tout va mal comme lorsque tout va bien semble s’être éloigné de son rôle.\r\n\r\nC’est douloureux pour nous de voir celui qui était un homme de foi, qui aidait l’Église et prêchait la Parole de Dieu, s’éloigner de cette lumière et de sa mission spirituelle. Aujourd’hui, nous ne reconnaissons plus celui qu’il était.\r\n\r\nQue Dieu nous vienne en aide.\r\nJe vous demande également de prier pour moi, afin que je puisse obtenir un meilleur travail pour soutenir mon père et prendre soin de mon jeune frère, qui est encore élève.\r\n\r\nQue la volonté de Dieu s’accomplisse dans nos vies.\r\nAmen.', '2025-11-28 22:51:22', '2025-11-28 22:51:22'),
	(1896, NULL, NULL, NULL, 'Congo (RDC)', 'Requête\r\n\r\nJe viens humblement solliciter vos prières pour mon père, atteint d’un cancer du poumon. Il a déjà dû se déplacer trois fois pour suivre des traitements de chimiothérapie, mais aujourd’hui, il traverse une période difficile qui l’empêche de poursuivre correctement son traitement.\r\n\r\nAffaibli et découragé, il s’abandonne parfois à l’alcool, ce qui ne fait qu’aggraver son état de santé. Il se délaisse, devient colérique et reporte souvent la faute sur moi et mon jeune frère, alors que depuis la mort de notre maman en 2021, nous sommes les seuls à être restés constamment à ses côtés.\r\n\r\nNous faisons face à de nombreuses difficultés, autant dans notre famille restreinte qu’au sein de la famille élargie. Il arrive même qu’il raconte des faux témoignages en notre nom sans que nous sachions pourquoi, alors qu’un père devrait d’abord dialoguer avec sa famille et non l’exposer. Aujourd’hui, nous subissons des attaques et des réprimandes de toute part, alors que celui qui devrait être la base de toute solution lorsque tout va mal comme lorsque tout va bien semble s’être éloigné de son rôle.\r\n\r\nC’est douloureux pour nous de voir celui qui était un homme de foi, qui aidait l’Église et prêchait la Parole de Dieu, s’éloigner de cette lumière et de sa mission spirituelle. Aujourd’hui, nous ne reconnaissons plus celui qu’il était.\r\n\r\nQue Dieu nous vienne en aide.\r\nJe vous demande également de prier pour moi, afin que je puisse obtenir un meilleur travail pour soutenir mon père et prendre soin de mon jeune frère, qui est encore élève.\r\n\r\nQue la volonté de Dieu s’accomplisse dans nos vies.\r\nAmen.', '2025-11-28 22:51:40', '2025-11-28 22:51:40'),
	(1897, 'KITIAKA', NULL, '0856499362', 'Congo (RDC)', 'Je viens humblement solliciter vos prières pour mon père, atteint d’un cancer du poumon. Il a déjà dû se déplacer trois fois pour suivre des traitements de chimiothérapie, mais aujourd’hui, il traverse une période difficile qui l’empêche de poursuivre correctement son traitement.\r\n\r\nAffaibli et découragé, il s’abandonne parfois à l’alcool, ce qui ne fait qu’aggraver son état de santé. Il se délaisse, devient colérique et reporte souvent la faute sur moi et mon jeune frère, alors que depuis la mort de notre maman en 2021, nous sommes les seuls à être restés constamment à ses côtés.\r\n\r\nNous faisons face à de nombreuses difficultés, autant dans notre famille restreinte qu’au sein de la famille élargie. Il arrive même qu’il raconte des faux témoignages en notre nom sans que nous sachions pourquoi, alors qu’un père devrait d’abord dialoguer avec sa famille et non l’exposer. Aujourd’hui, nous subissons des attaques et des réprimandes de toute part, alors que celui qui devrait être la base de toute solution lorsque tout va mal comme lorsque tout va bien semble s’être éloigné de son rôle.\r\n\r\nC’est douloureux pour nous de voir celui qui était un homme de foi, qui aidait l’Église et prêchait la Parole de Dieu, s’éloigner de cette lumière et de sa mission spirituelle. Aujourd’hui, nous ne reconnaissons plus celui qu’il était.\r\n\r\nQue Dieu nous vienne en aide.\r\nJe vous demande également de prier pour moi, afin que je puisse obtenir un meilleur travail pour soutenir mon père et prendre soin de mon jeune frère, qui est encore élève.\r\n\r\nQue la volonté de Dieu s’accomplisse dans nos vies.\r\nAmen.', '2025-11-28 22:55:47', '2025-11-28 22:55:47'),
