INSERT INTO `testimonials` (`id`, `fullname`, `phone`, `email`, `type`, `body`, `image_url`, `is_active`, `created_at`, `updated_at`) VALUES
	(1, 'silas', '0993107499', 'silasjmas@gmail.com', 'Bunda21', 'Orateur : Pasteur Héros Mbumba\r\nS/Thème :  Le Repos de Dieu.\r\nRéférences Bibliques : Genèse 32. 24-30 ; 2 chroniques 15. 12-15\r\n\r\nGenèse 32 :28 Il dit encore : ton nom ne sera plus Jacob, mais tu seras appelé Israël ; car tu as lutté avec Dieu et avec des hommes, et tu as été vainqueur.\r\nGenèse 32 :30 Jacob appela ce lieu du nom de Peniel : car, dit-il, j\'ai vu Dieu face à face, et mon âme a été sauvée.\r\n\r\nQuand on rencontre Dieu face à face, il change notre identité, si tu es entré dans ce Bunda comme Jacob, tu en ressortiras comme Israël.\r\n\r\nVous ne pouvez pas rencontrer le Seigneur face à face et avoir la même vie. Il accorde la délivrance ; l’âme est sauvée !\r\n\r\nNous ne sommes pas ici en tourisme. Nous y sommes pour un but, la délivrance, ayant vu sa face.\r\nEt ce midi, déclare ceci : « parce que je t\'ai vu Seigneur, accorde délivrance à ma maison, … »\r\n\r\n2 chroniques 15. 12-15\r\n2 Chroniques 15 :15. Tout Juda se réjouit de ce serment, car ils avaient juré de tout leur cœur, ils avaient cherché l\'Éternel de plein gré, et ils l\'avaient trouvé, et l\'Éternel leur donna du repos de tous côtés.\r\nLe repos de Dieu est plus que celui que les hommes prétendent accorder.\r\n\r\nRetenons que parce que nous avons vu Dieu face à face, cette rencontre engendre trois conséquences :\r\n\r\n1.	Le changement d’identité ;\r\n2.	La délivrance de mon âme ;\r\n3.	Le repos de Dieu.\r\n\r\n\r\n\r\n\r\nAmen !!!', NULL, 1, '2023-11-05 00:27:01', '2023-11-05 00:27:01');
